import { supabase } from '../lib/supabase';
import { Employee, DailyRecord, SupplyItem, SupplyTransaction } from '../types';

export const dataService = {
  // --- Employees ---

  async getEmployees(): Promise<Employee[]> {
    const { data, error } = await supabase
      .from('employees')
      .select('*')
      .order('name');

    if (error) throw error;
    return data || [];
  },

  async createEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .insert(employee);

    if (error) throw error;
  },

  async updateEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .update({ name: employee.name, active: employee.active })
      .eq('id', employee.id);

    if (error) throw error;
  },

  // --- Daily Records ---

  async getHistory(): Promise<DailyRecord[]> {
    const { data, error } = await supabase
      .from('daily_records')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    // Sanitize data to ensure arrays are never null/undefined
    return (data || []).map((record: any) => ({
      id: record.id,
      date: record.date,
      volume: record.volume,
      trucks: record.trucks,
      assignments: Array.isArray(record.assignments) ? record.assignments : [],
      trips: Array.isArray(record.trips) ? record.trips : []
    }));
  },

  async saveDailyRecord(record: DailyRecord): Promise<void> {
    // Upsert (Insert or Update) based on ID (date)
    const { error } = await supabase
      .from('daily_records')
      .upsert({
        id: record.id,
        date: record.date,
        volume: record.volume,
        trucks: record.trucks,
        assignments: record.assignments || [],
        trips: record.trips || []
      });

    if (error) throw error;
  },

  // --- Supplies ---

  async getSupplies(): Promise<SupplyItem[]> {
    const { data, error } = await supabase
      .from('supplies')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      name: item.name,
      quantity: Number(item.quantity),
      unit: item.unit,
      minStock: Number(item.min_stock)
    }));
  },

  async saveSupply(item: SupplyItem): Promise<void> {
    const { error } = await supabase
      .from('supplies')
      .upsert({
        id: item.id,
        name: item.name,
        quantity: item.quantity,
        unit: item.unit,
        min_stock: item.minStock
      });

    if (error) throw error;
  },

  async deleteSupply(id: string): Promise<void> {
    // 1. First delete all transactions related to this supply.
    // We wrap this in a try-catch to ensure that if the 'supply_transactions' table 
    // has issues (or doesn't exist yet), we still attempt to delete the main item.
    try {
      const { error: transError } = await supabase
        .from('supply_transactions')
        .delete()
        .eq('supply_id', id);

      if (transError) {
        console.warn("Aviso ao excluir transações (pode ser ignorado se a tabela não existir):", transError.message);
      }
    } catch (e) {
      console.warn("Erro não fatal ao tentar limpar transações:", e);
    }

    // 2. Then delete the supply item
    const { error } = await supabase
      .from('supplies')
      .delete()
      .eq('id', id);

    if (error) throw error;
  },

  // --- Supply Transactions ---

  async getSupplyTransactions(): Promise<SupplyTransaction[]> {
    const { data, error } = await supabase
      .from('supply_transactions')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      supplyId: item.supply_id,
      supplyName: item.supply_name,
      type: item.type,
      quantity: Number(item.quantity),
      date: item.date,
      user: item.user_name
    }));
  },

  async addSupplyTransaction(transaction: SupplyTransaction): Promise<void> {
    const { error } = await supabase
      .from('supply_transactions')
      .insert({
        id: transaction.id,
        supply_id: transaction.supplyId,
        supply_name: transaction.supplyName,
        type: transaction.type,
        quantity: transaction.quantity,
        date: transaction.date,
        user_name: transaction.user
      });

    if (error) throw error;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Box, Plus, Search, Filter, ArrowUpRight, ArrowDownLeft, FileText, AlertTriangle, History, Package, User, Calendar, Trash2, Save, X, Pencil, Settings, Loader2 } from 'lucide-react';
import { SupplyItem, SupplyTransaction } from '../types';
import { dataService } from '../services/dataService';

const SuppliesControl: React.FC = () => {
  // Estados
  const [view, setView] = useState<'inventory' | 'reports'>('inventory');
  const [supplies, setSupplies] = useState<SupplyItem[]>([]);
  const [history, setHistory] = useState<SupplyTransaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // Estado para Modais
  const [showAddModal, setShowAddModal] = useState(false);
  const [showTransactionModal, setShowTransactionModal] = useState(false);
  const [transactionType, setTransactionType] = useState<'IN' | 'OUT'>('OUT');
  const [selectedSupply, setSelectedSupply] = useState<SupplyItem | null>(null);

  // Estado de Edição e Processamento
  const [editingId, setEditingId] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null); // Estado específico para exclusão

  // Form States
  const [newItemName, setNewItemName] = useState('');
  const [newItemUnit, setNewItemUnit] = useState('un');
  const [newItemMin, setNewItemMin] = useState(10);
  const [newItemQty, setNewItemQty] = useState(0);

  const [transQty, setTransQty] = useState(1);
  const [transUser, setTransUser] = useState('');

  // Carregar dados ao montar
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [items, transactions] = await Promise.all([
        dataService.getSupplies(),
        dataService.getSupplyTransactions()
      ]);
      setSupplies(items);
      setHistory(transactions);
    } catch (error) {
      console.error("Erro ao carregar insumos:", error);
      // Fail silently to allow UI to render even if tables are empty/missing initially
    } finally {
      setLoading(false);
    }
  };

  // --- Filtros ---
  const filteredSupplies = supplies.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Ações ---

  const handleSaveItem = async () => {
    if (!newItemName) return;
    setProcessing(true);

    try {
      const isNew = !editingId;
      const itemId = editingId || `supply-${Date.now()}`;

      const itemToSave: SupplyItem = {
        id: itemId,
        name: newItemName,
        unit: newItemUnit,
        minStock: newItemMin,
        quantity: isNew ? newItemQty : newItemQty // Se for edição, assume o valor atualizado
      };

      await dataService.saveSupply(itemToSave);

      // Se for novo e tiver quantidade inicial, criar transação de entrada
      if (isNew && newItemQty > 0) {
        const trans: SupplyTransaction = {
          id: `init-${Date.now()}`,
          supplyId: itemId,
          supplyName: newItemName,
          type: 'IN',
          quantity: newItemQty,
          date: new Date().toISOString(),
          user: 'Cadastro Inicial'
        };
        await dataService.addSupplyTransaction(trans);
      }

      await loadData();
      closeModal();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar item.");
    } finally {
      setProcessing(false);
    }
  };

  const openAddModal = () => {
    setEditingId(null);
    resetForms();
    setShowAddModal(true);
  };

  const openEditModal = (item: SupplyItem, e?: React.MouseEvent) => {
    e?.stopPropagation(); // Impede clique no card
    setEditingId(item.id);
    setNewItemName(item.name);
    setNewItemUnit(item.unit);
    setNewItemMin(item.minStock);
    setNewItemQty(item.quantity);
    setShowAddModal(true);
  };

  const closeModal = () => {
    setShowAddModal(false);
    setEditingId(null);
    resetForms();
  };

  const openTransaction = (item: SupplyItem, type: 'IN' | 'OUT') => {
    setSelectedSupply(item);
    setTransactionType(type);
    setTransQty(1);
    setTransUser('');
    setShowTransactionModal(true);
  };

  const confirmTransaction = async () => {
    if (!selectedSupply || !transUser) {
      alert("Preencha todos os campos.");
      return;
    }
    if (transactionType === 'OUT' && transQty > selectedSupply.quantity) {
      alert("Estoque insuficiente!");
      return;
    }

    setProcessing(true);
    try {
      // 1. Atualizar Objeto Local para calculo
      const newQuantity = transactionType === 'IN' 
        ? selectedSupply.quantity + transQty 
        : selectedSupply.quantity - transQty;

      const updatedSupply = { ...selectedSupply, quantity: newQuantity };

      // 2. Salvar Atualização do Item
      await dataService.saveSupply(updatedSupply);

      // 3. Criar Transação
      const newTrans: SupplyTransaction = {
        id: `trans-${Date.now()}`,
        supplyId: selectedSupply.id,
        supplyName: selectedSupply.name,
        type: transactionType,
        quantity: transQty,
        date: new Date().toISOString(),
        user: transUser
      };

      await dataService.addSupplyTransaction(newTrans);

      await loadData();
      setShowTransactionModal(false);
    } catch (error) {
      console.error(error);
      alert("Erro ao processar transação.");
    } finally {
      setProcessing(false);
    }
  };

  const deleteItem = async (id: string, e?: React.MouseEvent) => {
    if (e) {
      e.stopPropagation();
      e.preventDefault();
    }

    if (confirm('Tem certeza que deseja excluir este item? Todo o histórico de movimentações também será apagado permanentemente.')) {
      setDeletingId(id);
      try {
        await dataService.deleteSupply(id);
        // Atualiza a lista localmente imediatamente para feedback rápido
        setSupplies(prev => prev.filter(s => s.id !== id));
        await loadData(); // Recarrega do banco para garantir consistência
      } catch (error: any) {
        console.error("Erro delete:", error);
        alert(`Erro ao excluir item: ${error.message || "Tente recarregar a página."}`);
      } finally {
        setDeletingId(null);
      }
    }
  };

  const resetForms = () => {
    setNewItemName('');
    setNewItemQty(0);
    setNewItemMin(10);
    setTransQty(1);
    setTransUser('');
  };

  // --- Cálculos de Relatório ---
  const reportStats = useMemo(() => {
    return supplies.map(supply => {
      // Filtrar saídas deste item
      const outputs = history.filter(h => h.supplyId === supply.id && h.type === 'OUT');
      const totalConsumed = outputs.reduce((acc, curr) => acc + curr.quantity, 0);

      // Média Simples (Pode ser melhorada futuramente com filtro de data)
      // Se não houver histórico de datas, consideramos consumo total como "atual"
      const avgMonthly = Math.round(totalConsumed); 

      return {
        ...supply,
        totalConsumed,
        avgMonthly
      };
    });
  }, [supplies, history]);

  if (loading && supplies.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-500">
        <Loader2 className="w-10 h-10 animate-spin mb-4 text-emerald-600" />
        <p>Carregando estoque...</p>
      </div>
    );
