              return (
                <div key={item.id} className={`bg-white rounded-xl border shadow-sm overflow-hidden flex flex-col transition-all hover:shadow-md relative group ${isLowStock ? 'border-red-200' : 'border-slate-200'}`}>

                  {/* Botões de Ação */}
                  {/* Importante: Botões são posicionados absolutamente sobre o card. */}
                  {/* z-10 garante que fiquem acima do conteúdo do card. */}
                  <div className="absolute top-2 right-2 flex gap-2 z-10">
                    <button 
                      type="button"
                      onClick={(e) => openEditModal(item, e)}
                      disabled={isDeleting}
                      className="p-2 bg-white text-slate-500 hover:text-indigo-600 border border-slate-200 rounded-lg shadow-sm transition-all hover:border-indigo-300 hover:scale-105 active:scale-95 disabled:opacity-50"
                      title="Editar"
                    >
                      <Pencil className="w-4 h-4 pointer-events-none" />
                    </button>

                    <button 
                      type="button"
                      onClick={(e) => deleteItem(item.id, e)}
                      disabled={isDeleting}
                      className="p-2 bg-white text-slate-500 hover:text-red-600 border border-slate-200 rounded-lg shadow-sm transition-all hover:border-red-300 hover:scale-105 active:scale-95 disabled:opacity-50"
                      title="Excluir"
                    >
                      {isDeleting ? (
                        <Loader2 className="w-4 h-4 animate-spin text-red-600 pointer-events-none" />
                      ) : (
                        <Trash2 className="w-4 h-4 pointer-events-none" />
                      )}
                    </button>
                  </div>

                  <div className="p-5 flex-1 mt-2">
                    <div className="flex justify-between items-start mb-2">
                       <h3 className="font-bold text-slate-800 text-lg leading-tight pr-8">{item.name}</h3>
                       {isLowStock && (
                         <div className="bg-red-100 text-red-700 p-1.5 rounded-full flex-shrink-0" title="Estoque Baixo">
                           <AlertTriangle className="w-4 h-4" />
                         </div>
                       )}
                    </div>
                    <div className="flex items-baseline gap-1 mt-4">
                       <span className={`text-4xl font-bold ${isLowStock ? 'text-red-600' : 'text-slate-800'}`}>
                         {item.quantity}
                       </span>
                       <span className="text-sm text-slate-500 font-medium">{item.unit}</span>
                    </div>
                    <p className="text-xs text-slate-400 mt-1">Mínimo: {item.minStock} {item.unit}</p>
                  </div>

                  <div className="bg-slate-50 border-t border-slate-100 p-3 grid grid-cols-2 gap-3">
                    <button 
                      type="button"
                      onClick={() => openTransaction(item, 'IN')}
                      disabled={isDeleting}
                      className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-green-700 text-sm font-medium hover:bg-green-50 hover:border-green-200 transition-colors cursor-pointer"
                    >
                      <ArrowDownLeft className="w-4 h-4 pointer-events-none" /> Entrada
                    </button>
                    <button 
                      type="button"
                      onClick={() => openTransaction(item, 'OUT')}
                      disabled={isDeleting}
                      className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-red-700 text-sm font-medium hover:bg-red-50 hover:border-red-200 transition-colors cursor-pointer"
                    >
                      <ArrowUpRight className="w-4 h-4 pointer-events-none" /> Saída
                    </button>
                  </div>
                </div>
              );
            })}

            {filteredSupplies.length === 0 && (
              <div className="col-span-full py-12 text-center text-slate-400">
                <Package className="w-12 h-12 mx-auto mb-3 opacity-20" />
                <p>Nenhum insumo encontrado.</p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* --- MODAL: NOVO/EDITAR ITEM --- */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">
              {editingId ? 'Editar Insumo' : 'Cadastrar Novo Insumo'}
            </h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Nome do Item</label>
                <input 
                  type="text" 
