              >
                {processing && <Loader2 className="w-4 h-4 animate-spin" />}
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* --- MODAL: TRANSAÇÃO (ENTRADA/SAÍDA) --- */}
      {showTransactionModal && selectedSupply && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
