import { supabase } from '../lib/supabase';
import { Employee, DailyRecord, SupplyItem, SupplyTransaction } from '../types';

export const dataService = {
  // --- Employees ---

  async getEmployees(): Promise<Employee[]> {
    const { data, error } = await supabase
      .from('employees')
      .select('*')
      .order('name');

    if (error) throw error;
    return data || [];
  },

  async createEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .insert(employee);

    if (error) throw error;
  },

  async updateEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .update({ name: employee.name, active: employee.active })
      .eq('id', employee.id);

    if (error) throw error;
  },

  // --- Daily Records ---

  async getHistory(): Promise<DailyRecord[]> {
    const { data, error } = await supabase
      .from('daily_records')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    // Sanitize data to ensure arrays are never null/undefined
    return (data || []).map((record: any) => ({
      id: record.id,
      date: record.date,
      volume: record.volume,
      trucks: record.trucks,
      assignments: Array.isArray(record.assignments) ? record.assignments : [],
      trips: Array.isArray(record.trips) ? record.trips : []
    }));
  },

  async saveDailyRecord(record: DailyRecord): Promise<void> {
    // Upsert (Insert or Update) based on ID (date)
    const { error } = await supabase
      .from('daily_records')
      .upsert({
        id: record.id,
        date: record.date,
        volume: record.volume,
        trucks: record.trucks,
        assignments: record.assignments || [],
        trips: record.trips || []
      });

    if (error) throw error;
  },

  // --- Supplies ---

  async getSupplies(): Promise<SupplyItem[]> {
    const { data, error } = await supabase
      .from('supplies')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      name: item.name,
      quantity: Number(item.quantity),
      unit: item.unit,
      minStock: Number(item.min_stock)
    }));
  },

  async saveSupply(item: SupplyItem): Promise<void> {
    const { error } = await supabase
      .from('supplies')
      .upsert({
        id: item.id,
        name: item.name,
        quantity: item.quantity,
        unit: item.unit,
        min_stock: item.minStock
      });

    if (error) throw error;
  },

  async deleteSupply(id: string): Promise<void> {
    // 1. Tentar excluir transações vinculadas primeiro
    // Mesmo que tenha ON DELETE CASCADE, fazer isso manualmente garante que 
    // RLS ou outros problemas não bloqueiem a exclusão do pai.
    await supabase
      .from('supply_transactions')
      .delete()
      .eq('supply_id', id);

    // 2. Excluir o item principal
    const { error } = await supabase
      .from('supplies')
      .delete()
      .eq('id', id);

    if (error) {
      // Se ainda der erro, lança uma mensagem amigável
      throw new Error(`Não foi possível excluir o item: ${error.message}`);
    }
  },

  // --- Supply Transactions ---

  async getSupplyTransactions(): Promise<SupplyTransaction[]> {
    const { data, error } = await supabase
      .from('supply_transactions')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      supplyId: item.supply_id,
      supplyName: item.supply_name,
      type: item.type,
      quantity: Number(item.quantity),
      date: item.date,
      user: item.user_name
    }));
  },

  async addSupplyTransaction(transaction: SupplyTransaction): Promise<void> {
    const { error } = await supabase
      .from('supply_transactions')
      .insert({
        id: transaction.id,
        supply_id: transaction.supplyId,
        supply_name: transaction.supplyName,
        type: transaction.type,
        quantity: transaction.quantity,
        date: transaction.date,
        user_name: transaction.user
      });

    if (error) throw error;
  }
};

export interface Employee {
  id: string;
  name: string;
  active: boolean;
}

export enum TaskCategory {
  UNLOAD = 'Descarregar',
  TURN = 'Virar Pacote',
  FISHING = 'Pescar Rota',
  BAGGING = 'Ensacar'
}

export interface TaskDefinition {
  id: string;
  name: string;
  description: string; // The specific routes or details
  category: TaskCategory;
  capacity: number; // How many people needed
}

export interface Assignment {
  taskId: string;
  employeeId: string;
  slotIndex: number; // For tasks with multiple people, which slot (0, 1, etc)
}

export interface TripInfo {
  id: string; // 15 chars alphanumeric
  unsealed: boolean; // deslacrada
  unsealTimestamp?: string; // Data e hora do deslacre (Formatado para exibição)
  unsealTimeISO?: string; // Data ISO para cálculos de timer
}

export interface DailyRecord {
  id: string; // YYYY-MM-DD
  date: string;
  volume: number;
  trucks: number;
  assignments: Assignment[];
  trips?: TripInfo[];
}

export interface AIRecommendation {
  rationale: string;
  assignments: { taskId: string; slotIndex: number; employeeName: string }[];
}

export interface SupplyItem {
  id: string;
  name: string;
  quantity: number;
  unit: string; // ex: 'un', 'cx', 'rolo'
  minStock: number;
}

export interface SupplyTransaction {
  id: string;
  supplyId: string;
  supplyName: string;
  type: 'IN' | 'OUT';
  quantity: number;
  date: string; // ISO String
  user: string; // Quem retirou ou quem adicionou
}

export interface EpiItem {
  id: string;
  name: string;
  caNumber: string; // Certificado de Aprovação
  quantity: number;
  minStock: number;
  validityDays?: number; // Validade média em dias para troca
}

export interface EpiTransaction {
  id: string;
  epiId: string;
  epiName: string;
  type: 'IN' | 'OUT'; // IN = Compra/Estoque, OUT = Entrega funcionário
  quantity: number;
  date: string;
  employeeId?: string; // ID do funcionário que recebeu
  employeeName: string; // Nome do funcionário ou 'Estoque Inicial'
  notes?: string;
}

