import React, { useState, useEffect } from 'react';
import { DailyRecord, Employee, TripInfo } from './types';
import Layout from './components/Layout';
import DailyOperations from './components/DailyOperations';
import TeamManagement from './components/TeamManagement';
import Reports from './components/Reports';
import GenerateReport from './components/GenerateReport';
import ManagementReport from './components/ManagementReport';
import ShippedNotArrived from './components/ShippedNotArrived';
import SecondaryTrips from './components/SecondaryTrips';
import SuppliesControl from './components/SuppliesControl';
import EpiControl from './components/EpiControl';
import QrCodeGenerator from './components/QrCodeGenerator';
import { dataService } from './services/dataService';
import { Loader2, AlertTriangle, Database, Copy, Check } from 'lucide-react';

// SQL Script for setup to be displayed in case of missing tables
const SETUP_SQL = `-- Run this in your Supabase SQL Editor

CREATE TABLE IF NOT EXISTS public.employees (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    active BOOLEAN DEFAULT TRUE
);

CREATE TABLE IF NOT EXISTS public.daily_records (
    id TEXT PRIMARY KEY, -- YYYY-MM-DD
    date TEXT NOT NULL,
    volume NUMERIC,
    trucks NUMERIC,
    assignments JSONB DEFAULT '[]'::jsonb,
    trips JSONB DEFAULT '[]'::jsonb
);

CREATE TABLE IF NOT EXISTS public.supplies (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    quantity NUMERIC DEFAULT 0,
    unit TEXT DEFAULT 'un',
    min_stock NUMERIC DEFAULT 0
);

CREATE TABLE IF NOT EXISTS public.supply_transactions (
    id TEXT PRIMARY KEY,
    supply_id TEXT REFERENCES public.supplies(id) ON DELETE CASCADE,
    supply_name TEXT,
    type TEXT CHECK (type IN ('IN', 'OUT')),
    quantity NUMERIC NOT NULL,
    date TEXT NOT NULL,
    user_name TEXT
);

-- EPIs Tables
CREATE TABLE IF NOT EXISTS public.epis (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    ca_number TEXT,
    quantity NUMERIC DEFAULT 0,
    min_stock NUMERIC DEFAULT 5,
    validity_days NUMERIC DEFAULT 0
);

CREATE TABLE IF NOT EXISTS public.epi_transactions (
    id TEXT PRIMARY KEY,
    epi_id TEXT REFERENCES public.epis(id) ON DELETE CASCADE,
    epi_name TEXT,
    type TEXT CHECK (type IN ('IN', 'OUT')),
    quantity NUMERIC NOT NULL,
    date TEXT NOT NULL,
    employee_id TEXT,
    employee_name TEXT,
    notes TEXT
);

-- Enable Row Level Security (RLS)
ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.daily_records ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.supplies ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.supply_transactions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.epis ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.epi_transactions ENABLE ROW LEVEL SECURITY;

-- Create policies to allow public access (Adjust for production!)
DROP POLICY IF EXISTS "Public Access Employees" ON public.employees;
CREATE POLICY "Public Access Employees" ON public.employees FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Records" ON public.daily_records;
CREATE POLICY "Public Access Records" ON public.daily_records FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Supplies" ON public.supplies;
CREATE POLICY "Public Access Supplies" ON public.supplies FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Transactions" ON public.supply_transactions;
CREATE POLICY "Public Access Transactions" ON public.supply_transactions FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Epis" ON public.epis;
CREATE POLICY "Public Access Epis" ON public.epis FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access EpiTrans" ON public.epi_transactions;
CREATE POLICY "Public Access EpiTrans" ON public.epi_transactions FOR ALL USING (true);`;

function App() {
  const [view, setView] = useState<'daily' | 'team' | 'reports' | 'generate' | 'shipped' | 'management' | 'secondary' | 'supplies' | 'epis' | 'qrcode'>('daily');

  const [employees, setEmployees] = useState<Employee[]>([]);
  const [history, setHistory] = useState<DailyRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Initial Load from Supabase
  useEffect(() => {
    const fetchData = async () => {
      try {
        setError(null);
        // We try to fetch all data.
        const [empData, histData] = await Promise.all([
          dataService.getEmployees(),
          dataService.getHistory(),
          dataService.getSupplies() // Used just to check if table exists during init
        ]);
        setEmployees(empData);
        setHistory(histData);
      } catch (err: any) {
        console.error("Failed to load data:", JSON.stringify(err));
        // Extract meaningful message from Supabase error
        const msg = err.message || JSON.stringify(err);
        const code = err.code || '';

        // Check for specific "table not found" error
        if (code === 'PGRST205' || msg.includes('does not exist')) {
          setError('MISSING_TABLES');
        } else {
          setError(msg);
        }
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const handleSaveRecord = async (record: DailyRecord) => {
    try {
      await dataService.saveDailyRecord(record);

      setHistory(prev => {
        const idx = prev.findIndex(p => p.date === record.date);
        if (idx >= 0) {
          const newHistory = [...prev];
          newHistory[idx] = record;
          return newHistory;
        }
        return [record, ...prev]; // Add new records to top for easier history view
      });
      return true;
    } catch (error: any) {
      console.error("Error saving record:", error);
      alert(`Erro ao salvar: ${error.message || "Erro desconhecido"}`);
      return false;
    }
  };

  const handleAddEmployee = async (newEmp: Employee) => {
    await dataService.createEmployee(newEmp);
    setEmployees(prev => [...prev, newEmp]);
  };

  const handleUpdateEmployee = async (updatedEmp: Employee) => {
    await dataService.updateEmployee(updatedEmp);
    setEmployees(prev => prev.map(e => e.id === updatedEmp.id ? updatedEmp : e));
  };

  const copySqlToClipboard = () => {
    navigator.clipboard.writeText(SETUP_SQL);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center text-slate-500">
        <Loader2 className="w-10 h-10 animate-spin mb-4 text-indigo-600" />
        <p>Carregando sistema...</p>
      </div>
    );
  }

  // Error State Display
  if (error) {
    const isMissingTables = error === 'MISSING_TABLES';

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-2xl w-full">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertTriangle className="w-8 h-8 text-red-600" />
          </div>

          <h2 className="text-2xl font-bold text-slate-800 mb-2 text-center">
            {isMissingTables ? 'Configuração Necessária' : 'Erro de Conexão'}
          </h2>

          <p className="text-slate-600 mb-6 text-center">
            {isMissingTables 
              ? 'O banco de dados do Supabase ainda não possui as tabelas necessárias (incluindo as novas tabelas de Insumos e EPIs).' 
              : 'Não foi possível carregar os dados do banco de dados.'}
          </p>

          {isMissingTables ? (
            <div className="space-y-4">
               <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg">
                 <h3 className="font-semibold text-blue-800 text-sm flex items-center gap-2 mb-2">
                   <Database className="w-4 h-4" /> Como Resolver:
                 </h3>
                 <ol className="list-decimal list-inside text-sm text-blue-800 space-y-1 ml-1">
                   <li>Copie o código SQL abaixo.</li>
                   <li>Acesse seu painel do Supabase.</li>
                   <li>Vá até o <strong>SQL Editor</strong>.</li>
                   <li>Cole o código e clique em <strong>RUN</strong>.</li>
                   <li>Recarregue esta página.</li>
                 </ol>
               </div>

               <div className="relative">
                 <pre className="bg-slate-900 text-slate-100 p-4 rounded-lg text-xs font-mono overflow-auto max-h-64 whitespace-pre-wrap">
                   {SETUP_SQL}
                 </pre>
                 <button 
                  onClick={copySqlToClipboard}
                  className="absolute top-2 right-2 bg-white/10 hover:bg-white/20 text-white p-2 rounded transition-colors"
                  title="Copiar SQL"
                 >
                   {copied ? <Check className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4" />}
                 </button>
               </div>
            </div>
          ) : (
            <div className="bg-slate-100 p-3 rounded text-left mb-6 overflow-auto max-h-32">
              <code className="text-xs text-slate-700 font-mono break-all">{error}</code>
            </div>
          )}

          <div className="mt-8 flex justify-center">
            <button 
              onClick={() => window.location.reload()}
              className="bg-indigo-600 text-white px-8 py-3 rounded-lg hover:bg-indigo-700 transition-colors font-medium"
            >
              Recarregar Aplicação
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout currentView={view} onChangeView={setView}>
      {view === 'daily' && (
        <DailyOperations 
          employees={employees} 
          history={history} 
          onSaveRecord={handleSaveRecord} 
        />
      )}
      {view === 'team' && (
        <TeamManagement 
          employees={employees} 
          onAddEmployee={handleAddEmployee}
          onUpdateEmployee={handleUpdateEmployee}
        />
      )}
      {view === 'reports' && (
        <Reports 
          history={history} 
          employees={employees} 
        />
      )}
      {view === 'generate' && (
        <GenerateReport />
      )}
      {view === 'management' && (
        <ManagementReport history={history} />
      )}
      {view === 'shipped' && (
        <ShippedNotArrived />
      )}
      {view === 'secondary' && (
        <SecondaryTrips />
      )}
      {view === 'supplies' && (
        <SuppliesControl />
      )}
      {view === 'epis' && (
        <EpiControl />
      )}
      {view === 'qrcode' && (
        <QrCodeGenerator />
      )}
    </Layout>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { HardHat, Plus, Search, Filter, History, Package, User, Trash2, Pencil, AlertTriangle, ArrowDownLeft, ArrowUpRight, Loader2, ShieldCheck, CalendarClock } from 'lucide-react';
import { EpiItem, EpiTransaction, Employee } from '../types';
import { dataService } from '../services/dataService';

const EpiControl: React.FC = () => {
  // --- Estados Principais ---
  const [view, setView] = useState<'inventory' | 'history'>('inventory');
  const [epis, setEpis] = useState<EpiItem[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [transactions, setTransactions] = useState<EpiTransaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // --- Modais e Forms ---
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDeliverModal, setShowDeliverModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Form: Item EPI
  const [epiName, setEpiName] = useState('');
  const [epiCa, setEpiCa] = useState('');
  const [epiQty, setEpiQty] = useState(0);
  const [epiMin, setEpiMin] = useState(5);
  const [epiValidity, setEpiValidity] = useState(180); // Dias

  // Form: Entrega/Movimentação
  const [selectedEpi, setSelectedEpi] = useState<EpiItem | null>(null);
  const [transType, setTransType] = useState<'IN' | 'OUT'>('OUT'); // OUT = Entrega, IN = Reposição
  const [transQty, setTransQty] = useState(1);
  const [transEmpId, setTransEmpId] = useState('');
  const [transNotes, setTransNotes] = useState('');

  // --- Inicialização ---
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [episData, empsData, transData] = await Promise.all([
        dataService.getEpis(),
        dataService.getEmployees(),
        dataService.getEpiTransactions()
      ]);
      setEpis(episData);
      setEmployees(empsData);
      setTransactions(transData);
    } catch (error) {
      console.error("Erro carregando EPIs:", error);
    } finally {
      setLoading(false);
    }
  };

  // --- Helpers ---
  const filteredEpis = epis.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.caNumber.includes(searchTerm)
  );

  const activeEmployees = employees.filter(e => e.active);

  // --- Actions: CRUD EPI ---
  const openAddModal = () => {
    setEditingId(null);
    setEpiName('');
    setEpiCa('');
    setEpiQty(0);
    setEpiMin(5);
    setEpiValidity(180);
    setShowAddModal(true);
  };

  const openEditModal = (item: EpiItem) => {
    setEditingId(item.id);
    setEpiName(item.name);
    setEpiCa(item.caNumber);
    setEpiQty(item.quantity);
    setEpiMin(item.minStock);
    setEpiValidity(item.validityDays || 180);
    setShowAddModal(true);
  };

  const handleSaveEpi = async () => {
    if (!epiName) return;
    setProcessing(true);
    try {
      const isNew = !editingId;
      const id = editingId || `epi-${Date.now()}`;

      const item: EpiItem = {
        id,
        name: epiName,
        caNumber: epiCa,
        quantity: isNew ? epiQty : epiQty, // Se editar, mantem o form (cuidado aqui, idealmente só edita nome/CA/min)
        minStock: epiMin,
        validityDays: epiValidity
      };

      await dataService.saveEpi(item);

      // Se novo e com estoque inicial > 0, cria transação IN
      if (isNew && epiQty > 0) {
        await dataService.addEpiTransaction({
          id: `epi-init-${Date.now()}`,
          epiId: id,
          epiName: epiName,
          type: 'IN',
          quantity: epiQty,
          date: new Date().toISOString(),
          employeeName: 'Estoque Inicial',
          notes: 'Cadastro Inicial'
        });
      }

      await loadData();
      setShowAddModal(false);
    } catch (e) {
      alert("Erro ao salvar EPI");
    } finally {
      setProcessing(false);
    }
  };

  const handleDeleteEpi = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!window.confirm("Excluir este EPI apagará todo o histórico de entregas. Continuar?")) return;

    setDeletingId(id);
    try {
      await dataService.deleteEpi(id);
      setEpis(prev => prev.filter(x => x.id !== id));
      await loadData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setDeletingId(null);
    }
  };

  // --- Actions: Transações (Entrega/Reposição) ---
  const openDeliverModal = (item: EpiItem, type: 'IN' | 'OUT') => {
    setSelectedEpi(item);
    setTransType(type);
    setTransQty(1);
    setTransEmpId('');
    setTransNotes('');
    setShowDeliverModal(true);
  };

  const handleTransaction = async () => {
    if (!selectedEpi) return;
    if (transType === 'OUT' && !transEmpId) {
      alert("Selecione um funcionário para entrega.");
      return;
    }
    if (transType === 'OUT' && selectedEpi.quantity < transQty) {
      alert("Estoque insuficiente.");
      return;
    }

    setProcessing(true);
    try {
      const empName = transType === 'IN' 
        ? 'Estoque / Compra' 
        : employees.find(e => e.id === transEmpId)?.name || 'Desconhecido';

      // 1. Atualizar EPI
      const newQty = transType === 'IN' 
        ? selectedEpi.quantity + transQty 
        : selectedEpi.quantity - transQty;

      await dataService.saveEpi({ ...selectedEpi, quantity: newQty });

      // 2. Criar Transação
      await dataService.addEpiTransaction({
        id: `ept-${Date.now()}`,
        epiId: selectedEpi.id,
        epiName: selectedEpi.name,
        type: transType,
        quantity: transQty,
        date: new Date().toISOString(),
        employeeId: transType === 'OUT' ? transEmpId : undefined,
        employeeName: empName,
        notes: transNotes
      });

      await loadData();
      setShowDeliverModal(false);
    } catch (e) {
      alert("Erro ao processar.");
    } finally {
      setProcessing(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10 relative">

      {/* Header */}
      <div className="bg-orange-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1504328345606-18bbc8c9d7d1?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <HardHat className="w-8 h-8" />
          Controle de EPIs
        </h2>
        <p className="text-orange-100 max-w-xl">
          Gestão de entrega, validade e estoque de equipamentos de proteção.
        </p>
      </div>

      {/* Navegação */}
      <div className="flex border-b border-slate-200 gap-6">
        <button 
          onClick={() => setView('inventory')}
          className={`pb-3 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${view === 'inventory' ? 'border-orange-600 text-orange-700' : 'border-transparent text-slate-500 hover:text-orange-600'}`}
        >
          <ShieldCheck className="w-4 h-4" /> Estoque & Entregas
        </button>
        <button 
          onClick={() => setView('history')}
          className={`pb-3 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${view === 'history' ? 'border-orange-600 text-orange-700' : 'border-transparent text-slate-500 hover:text-orange-600'}`}
        >
          <History className="w-4 h-4" /> Histórico Completo
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-orange-600" /></div>
      ) : (
        <>
          {view === 'inventory' && (
            <div className="space-y-6 animate-fade-in">
              {/* Toolbar */}
              <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <div className="relative w-full md:w-96">
                  <input 
                    type="text" 
                    placeholder="Buscar EPI (Nome ou CA)..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-orange-500"
                  />
                  <Search className="w-5 h-5 text-slate-400 absolute left-3 top-2.5" />
                </div>
                <button onClick={openAddModal} className="w-full md:w-auto flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 font-medium">
                  <Plus className="w-4 h-4" /> Novo EPI
                </button>
              </div>

              {/* Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredEpis.map(item => {
                  const isLow = item.quantity <= item.minStock;
                  return (
                    <div key={item.id} className={`bg-white rounded-xl border shadow-sm overflow-hidden flex flex-col group ${isLow ? 'border-red-300' : 'border-slate-200'}`}>
                      <div className="p-4 flex justify-between items-start">
                        <div>
                           <h3 className="font-bold text-slate-800 text-lg leading-tight">{item.name}</h3>
                           <p className="text-xs text-slate-500 font-mono mt-1">CA: {item.caNumber || 'N/A'}</p>
                        </div>
                        <div className="flex gap-1 opacity-100 lg:opacity-0 group-hover:opacity-100 transition-opacity">
                           <button onClick={() => openEditModal(item)} className="p-1.5 bg-slate-100 rounded hover:bg-indigo-100 hover:text-indigo-600"><Pencil className="w-4 h-4" /></button>
                           <button onClick={(e) => handleDeleteEpi(item.id, e)} className="p-1.5 bg-slate-100 rounded hover:bg-red-100 hover:text-red-600">
                             {deletingId === item.id ? <Loader2 className="w-4 h-4 animate-spin"/> : <Trash2 className="w-4 h-4" />}
                           </button>
                        </div>
                      </div>

                      <div className="px-4 pb-4 flex-1">
                        <div className="flex items-baseline gap-1 mt-2">
                           <span className={`text-4xl font-bold ${isLow ? 'text-red-600' : 'text-slate-800'}`}>{item.quantity}</span>
                           <span className="text-sm text-slate-500 font-medium">un</span>
                        </div>
                        {isLow && <div className="text-xs text-red-600 flex items-center gap-1 mt-1"><AlertTriangle className="w-3 h-3" /> Estoque Baixo (Min: {item.minStock})</div>}
                      </div>

                      <div className="bg-slate-50 border-t border-slate-100 p-3 grid grid-cols-2 gap-3">
                        <button onClick={() => openDeliverModal(item, 'IN')} className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-green-700 text-xs font-bold hover:bg-green-50 uppercase">
                           <ArrowDownLeft className="w-4 h-4" /> Repor
                        </button>
                        <button onClick={() => openDeliverModal(item, 'OUT')} className="flex items-center justify-center gap-2 py-2 bg-orange-600 text-white border border-transparent rounded text-xs font-bold hover:bg-orange-700 uppercase shadow-sm">
                           <ArrowUpRight className="w-4 h-4" /> Entregar
                        </button>
                      </div>
                    </div>
                  );
                })}
