                        </div>
                      </div>

                      <div className="px-4 pb-4 flex-1">
                        <div className="flex items-baseline gap-1 mt-2">
                           <span className={`text-4xl font-bold ${isLow ? 'text-red-600' : 'text-slate-800'}`}>{item.quantity}</span>
                           <span className="text-sm text-slate-500 font-medium">un</span>
                        </div>
                        {isLow && <div className="text-xs text-red-600 flex items-center gap-1 mt-1"><AlertTriangle className="w-3 h-3" /> Estoque Baixo (Min: {item.minStock})</div>}
                      </div>

                      <div className="bg-slate-50 border-t border-slate-100 p-3 grid grid-cols-2 gap-3">
                        <button onClick={() => openDeliverModal(item, 'IN')} className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-green-700 text-xs font-bold hover:bg-green-50 uppercase">
                           <ArrowDownLeft className="w-4 h-4" /> Repor
                        </button>
                        <button onClick={() => openDeliverModal(item, 'OUT')} className="flex items-center justify-center gap-2 py-2 bg-orange-600 text-white border border-transparent rounded text-xs font-bold hover:bg-orange-700 uppercase shadow-sm">
                           <ArrowUpRight className="w-4 h-4" /> Entregar
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {view === 'history' && (
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden animate-fade-in">
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-semibold uppercase text-xs">
                  <tr>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Tipo</th>
                    <th className="px-6 py-4">EPI</th>
                    <th className="px-6 py-4">Responsável / Funcionário</th>
                    <th className="px-6 py-4 text-right">Qtd</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {transactions.map(t => (
                    <tr key={t.id} className="hover:bg-slate-50">
                      <td className="px-6 py-4 font-mono text-slate-500">{new Date(t.date).toLocaleDateString()}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded text-xs font-bold ${t.type === 'IN' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                          {t.type === 'IN' ? 'ENTRADA' : 'ENTREGA'}
                        </span>
                      </td>
                      <td className="px-6 py-4 font-medium text-slate-700">{t.epiName}</td>
                      <td className="px-6 py-4 text-slate-600">
                        <div className="flex items-center gap-2">
                           <User className="w-4 h-4 text-slate-400" />
                           {t.employeeName}
                        </div>
                        {t.notes && <div className="text-xs text-slate-400 mt-1 italic">{t.notes}</div>}
                      </td>
                      <td className="px-6 py-4 text-right font-bold">{t.quantity}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && <tr><td colSpan={5} className="p-8 text-center text-slate-400">Sem histórico.</td></tr>}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* Modal Adicionar EPI */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">{editingId ? 'Editar EPI' : 'Novo EPI'}</h3>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-500">Nome do Equipamento</label>
                <input type="text" value={epiName} onChange={e => setEpiName(e.target.value)} className="w-full p-2 border rounded" placeholder="Ex: Bota de Segurança" />
              </div>
              <div>
                <label className="text-xs font-bold text-slate-500">C.A. (Certificado de Aprovação)</label>
                <input type="text" value={epiCa} onChange={e => setEpiCa(e.target.value)} className="w-full p-2 border rounded" placeholder="Ex: 12345" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="text-xs font-bold text-slate-500">Estoque Atual</label>
                    <input type="number" value={epiQty} onChange={e => setEpiQty(Number(e.target.value))} className="w-full p-2 border rounded" />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-500">Mínimo (Alerta)</label>
                    <input type="number" value={epiMin} onChange={e => setEpiMin(Number(e.target.value))} className="w-full p-2 border rounded" />
                 </div>
              </div>
              <div>
                 <label className="text-xs font-bold text-slate-500">Validade Média (Dias)</label>
                 <input type="number" value={epiValidity} onChange={e => setEpiValidity(Number(e.target.value))} className="w-full p-2 border rounded" placeholder="Para troca" />
              </div>
            </div>
            <div className="flex gap-3 mt-6">
               <button onClick={() => setShowAddModal(false)} className="flex-1 py-2 border rounded text-slate-600">Cancelar</button>
               <button onClick={handleSaveEpi} disabled={processing} className="flex-1 py-2 bg-orange-600 text-white rounded font-bold hover:bg-orange-700">
                  {processing ? <Loader2 className="animate-spin mx-auto"/> : 'Salvar'}
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Entrega/Movimentação */}
      {showDeliverModal && selectedEpi && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 border-t-4 border-orange-500">
            <h3 className="text-lg font-bold text-slate-800 mb-1">
               {transType === 'IN' ? 'Reposição de Estoque' : 'Entrega de EPI'}
            </h3>
            <p className="text-sm text-slate-500 mb-4">{selectedEpi.name} (CA: {selectedEpi.caNumber})</p>

            <div className="space-y-4">
               <div>
                  <label className="text-xs font-bold text-slate-500">Quantidade</label>
                  <input type="number" min="1" value={transQty} onChange={e => setTransQty(Number(e.target.value))} className="w-full p-2 border rounded text-lg font-bold text-center" />
               </div>

               {transType === 'OUT' && (
                 <div>
                    <label className="text-xs font-bold text-slate-500">Funcionário</label>
                    <select value={transEmpId} onChange={e => setTransEmpId(e.target.value)} className="w-full p-2 border rounded bg-white">
                       <option value="">Selecione...</option>
                       {activeEmployees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                    </select>
                 </div>
               )}

               <div>
                  <label className="text-xs font-bold text-slate-500">Observações (Opcional)</label>
                  <input type="text" value={transNotes} onChange={e => setTransNotes(e.target.value)} className="w-full p-2 border rounded" placeholder="Motivo, número da nota, etc." />
               </div>
            </div>

            <div className="flex gap-3 mt-6">
               <button onClick={() => setShowDeliverModal(false)} className="flex-1 py-2 border rounded text-slate-600">Cancelar</button>
               <button onClick={handleTransaction} disabled={processing} className="flex-1 py-2 bg-orange-600 text-white rounded font-bold hover:bg-orange-700">
                  {processing ? <Loader2 className="animate-spin mx-auto"/> : 'Confirmar'}
               </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default EpiControl;

import { supabase } from '../lib/supabase';
import { Employee, DailyRecord, SupplyItem, SupplyTransaction, EpiItem, EpiTransaction } from '../types';

export const dataService = {
  // --- Employees ---

  async getEmployees(): Promise<Employee[]> {
    const { data, error } = await supabase
      .from('employees')
      .select('*')
      .order('name');

    if (error) throw error;
    return data || [];
  },

  async createEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .insert(employee);

    if (error) throw error;
  },

  async updateEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .update({ name: employee.name, active: employee.active })
      .eq('id', employee.id);

    if (error) throw error;
  },

  // --- Daily Records ---

  async getHistory(): Promise<DailyRecord[]> {
    const { data, error } = await supabase
      .from('daily_records')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    // Sanitize data to ensure arrays are never null/undefined
    return (data || []).map((record: any) => ({
      id: record.id,
      date: record.date,
      volume: record.volume,
      trucks: record.trucks,
      assignments: Array.isArray(record.assignments) ? record.assignments : [],
      trips: Array.isArray(record.trips) ? record.trips : []
    }));
  },

  async saveDailyRecord(record: DailyRecord): Promise<void> {
    // Upsert (Insert or Update) based on ID (date)
    const { error } = await supabase
      .from('daily_records')
      .upsert({
        id: record.id,
        date: record.date,
        volume: record.volume,
        trucks: record.trucks,
        assignments: record.assignments || [],
        trips: record.trips || []
      });

    if (error) throw error;
  },

  // --- Supplies ---

  async getSupplies(): Promise<SupplyItem[]> {
    const { data, error } = await supabase
      .from('supplies')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      name: item.name,
      quantity: Number(item.quantity),
      unit: item.unit,
      minStock: Number(item.min_stock)
    }));
  },

  async saveSupply(item: SupplyItem): Promise<void> {
    const { error } = await supabase
      .from('supplies')
      .upsert({
        id: item.id,
        name: item.name,
        quantity: item.quantity,
        unit: item.unit,
        min_stock: item.minStock
      });

    if (error) throw error;
  },

  async deleteSupply(id: string): Promise<void> {
    // 1. Tentar excluir transações primeiro
    const { error: transError } = await supabase
      .from('supply_transactions')
      .delete()
      .eq('supply_id', id);

    if (transError) {
       console.error("Erro ao limpar transações de insumo (não fatal se CASCADE existir):", transError);
    }

    // 2. Excluir o item principal
    const { error } = await supabase
      .from('supplies')
      .delete()
      .eq('id', id);

    if (error) {
      throw new Error(`Não foi possível excluir o item: ${error.message} (${error.details || ''})`);
    }
  },

  // --- Supply Transactions ---

  async getSupplyTransactions(): Promise<SupplyTransaction[]> {
    const { data, error } = await supabase
      .from('supply_transactions')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      supplyId: item.supply_id,
      supplyName: item.supply_name,
      type: item.type,
      quantity: Number(item.quantity),
      date: item.date,
      user: item.user_name
    }));
  },

  async addSupplyTransaction(transaction: SupplyTransaction): Promise<void> {
    const { error } = await supabase
      .from('supply_transactions')
      .insert({
        id: transaction.id,
        supply_id: transaction.supplyId,
        supply_name: transaction.supplyName,
        type: transaction.type,
        quantity: transaction.quantity,
        date: transaction.date,
        user_name: transaction.user
      });

    if (error) throw error;
  },

  // --- EPIs (PPEs) ---

  async getEpis(): Promise<EpiItem[]> {
    const { data, error } = await supabase
      .from('epis')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      name: item.name,
      caNumber: item.ca_number || '',
      quantity: Number(item.quantity),
      minStock: Number(item.min_stock),
      validityDays: Number(item.validity_days || 0)
    }));
  },

  async saveEpi(item: EpiItem): Promise<void> {
    const { error } = await supabase
      .from('epis')
      .upsert({
        id: item.id,
        name: item.name,
        ca_number: item.caNumber,
        quantity: item.quantity,
        min_stock: item.minStock,
        validity_days: item.validityDays
      });

    if (error) throw error;
  },

  async deleteEpi(id: string): Promise<void> {
    // 1. Tentar excluir transações
    const { error: transError } = await supabase
      .from('epi_transactions')
      .delete()
      .eq('epi_id', id);

    if (transError) {
      console.error("Erro ao limpar transações de EPI:", transError);
    }

    // 2. Excluir EPI
    const { error } = await supabase
      .from('epis')
      .delete()
      .eq('id', id);

    if (error) {
       throw new Error(`Erro ao excluir EPI: ${error.message} (${error.details || ''})`);
    }
  },

  async getEpiTransactions(): Promise<EpiTransaction[]> {
    const { data, error } = await supabase
      .from('epi_transactions')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      epiId: item.epi_id,
      epiName: item.epi_name,
      type: item.type,
      quantity: Number(item.quantity),
      date: item.date,
      employeeId: item.employee_id,
      employeeName: item.employee_name,
      notes: item.notes
    }));
  },

  async addEpiTransaction(transaction: EpiTransaction): Promise<void> {
    const { error } = await supabase
      .from('epi_transactions')
      .insert({
        id: transaction.id,
        epi_id: transaction.epiId,
        epi_name: transaction.epiName,
        type: transaction.type,
        quantity: transaction.quantity,
        date: transaction.date,
        employee_id: transaction.employeeId,
        employee_name: transaction.employeeName,
        notes: transaction.notes
      });

    if (error) throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { HardHat, Plus, Search, Filter, History, Package, User, Trash2, Pencil, AlertTriangle, ArrowDownLeft, ArrowUpRight, Loader2, ShieldCheck, CalendarClock, X, AlertCircle } from 'lucide-react';
import { EpiItem, EpiTransaction, Employee } from '../types';
import { dataService } from '../services/dataService';

const EpiControl: React.FC = () => {
  // --- Estados Principais ---
  const [view, setView] = useState<'inventory' | 'history'>('inventory');
  const [epis, setEpis] = useState<EpiItem[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [transactions, setTransactions] = useState<EpiTransaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // --- Modais e Forms ---
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDeliverModal, setShowDeliverModal] = useState(false);

  // Novo Estado para Modal de Exclusão
  const [itemToDelete, setItemToDelete] = useState<EpiItem | null>(null);

  const [editingId, setEditingId] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Form: Item EPI
  const [epiName, setEpiName] = useState('');
  const [epiCa, setEpiCa] = useState('');
  const [epiQty, setEpiQty] = useState(0);
  const [epiMin, setEpiMin] = useState(5);
  const [epiValidity, setEpiValidity] = useState(180); // Dias

  // Form: Entrega/Movimentação
  const [selectedEpi, setSelectedEpi] = useState<EpiItem | null>(null);
  const [transType, setTransType] = useState<'IN' | 'OUT'>('OUT'); // OUT = Entrega, IN = Reposição
  const [transQty, setTransQty] = useState(1);
  const [transEmpId, setTransEmpId] = useState('');
  const [transNotes, setTransNotes] = useState('');

  // --- Inicialização ---
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [episData, empsData, transData] = await Promise.all([
        dataService.getEpis(),
        dataService.getEmployees(),
        dataService.getEpiTransactions()
      ]);
      setEpis(episData);
      setEmployees(empsData);
      setTransactions(transData);
    } catch (error) {
      console.error("Erro carregando EPIs:", error);
    } finally {
      setLoading(false);
    }
  };

  // --- Helpers ---
  const filteredEpis = epis.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.caNumber.includes(searchTerm)
  );

  const activeEmployees = employees.filter(e => e.active);

  // --- Actions: CRUD EPI ---
  const openAddModal = () => {
    setEditingId(null);
    setEpiName('');
    setEpiCa('');
    setEpiQty(0);
    setEpiMin(5);
    setEpiValidity(180);
    setShowAddModal(true);
  };

  const openEditModal = (item: EpiItem) => {
    setEditingId(item.id);
    setEpiName(item.name);
    setEpiCa(item.caNumber);
    setEpiQty(item.quantity);
    setEpiMin(item.minStock);
    setEpiValidity(item.validityDays || 180);
    setShowAddModal(true);
  };

  const handleSaveEpi = async () => {
    if (!epiName) return;
    setProcessing(true);
    try {
      const isNew = !editingId;
      const id = editingId || `epi-${Date.now()}`;

      const item: EpiItem = {
        id,
        name: epiName,
        caNumber: epiCa,
        quantity: isNew ? epiQty : epiQty, // Se editar, mantem o form
        minStock: epiMin,
        validityDays: epiValidity
      };

      await dataService.saveEpi(item);

      // Se novo e com estoque inicial > 0, cria transação IN
      if (isNew && epiQty > 0) {
        await dataService.addEpiTransaction({
          id: `epi-init-${Date.now()}`,
          epiId: id,
          epiName: epiName,
          type: 'IN',
          quantity: epiQty,
          date: new Date().toISOString(),
          employeeName: 'Estoque Inicial',
          notes: 'Cadastro Inicial'
        });
      }

      await loadData();
      setShowAddModal(false);
    } catch (e: any) {
      console.error(e);
      alert(`Erro ao salvar EPI: ${e.message || "Verifique se a tabela 'epis' foi criada no Supabase."}`);
    } finally {
      setProcessing(false);
    }
  };

  const handleRequestDelete = (item: EpiItem, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setItemToDelete(item);
  };

  const confirmDelete = async () => {
    if (!itemToDelete) return;

    setDeletingId(itemToDelete.id);
    try {
      await dataService.deleteEpi(itemToDelete.id);
      setEpis(prev => prev.filter(x => x.id !== itemToDelete.id));
      await loadData(); // Reload to refresh history view too
      setItemToDelete(null);
    } catch (err: any) {
      console.error(err);
      alert(`Erro ao excluir: ${err.message}`);
    } finally {
      setDeletingId(null);
    }
  };

  // --- Actions: Transações (Entrega/Reposição) ---
  const openDeliverModal = (item: EpiItem, type: 'IN' | 'OUT') => {
    setSelectedEpi(item);
    setTransType(type);
    setTransQty(1);
    setTransEmpId('');
    setTransNotes('');
    setShowDeliverModal(true);
  };

  const handleTransaction = async () => {
    if (!selectedEpi) return;
    if (transType === 'OUT' && !transEmpId) {
      alert("Selecione um funcionário para entrega.");
      return;
    }
    if (transType === 'OUT' && selectedEpi.quantity < transQty) {
      alert("Estoque insuficiente.");
      return;
    }

    setProcessing(true);
    try {
      const empName = transType === 'IN' 
        ? 'Estoque / Compra' 
        : employees.find(e => e.id === transEmpId)?.name || 'Desconhecido';

      // 1. Atualizar EPI
      const newQty = transType === 'IN' 
        ? selectedEpi.quantity + transQty 
        : selectedEpi.quantity - transQty;

      await dataService.saveEpi({ ...selectedEpi, quantity: newQty });

      // 2. Criar Transação
      await dataService.addEpiTransaction({
        id: `ept-${Date.now()}`,
        epiId: selectedEpi.id,
        epiName: selectedEpi.name,
        type: transType,
        quantity: transQty,
        date: new Date().toISOString(),
        employeeId: transType === 'OUT' ? transEmpId : undefined,
        employeeName: empName,
        notes: transNotes
      });

      await loadData();
      setShowDeliverModal(false);
    } catch (e: any) {
       console.error(e);
       alert(`Erro ao processar: ${e.message}`);
    } finally {
      setProcessing(false);
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10 relative">

      {/* Header */}
      <div className="bg-orange-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1504328345606-18bbc8c9d7d1?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <HardHat className="w-8 h-8" />
          Controle de EPIs
        </h2>
        <p className="text-orange-100 max-w-xl">
          Gestão de entrega, validade e estoque de equipamentos de proteção.
        </p>
      </div>

      {/* Navegação */}
      <div className="flex border-b border-slate-200 gap-6">
        <button 
          onClick={() => setView('inventory')}
          className={`pb-3 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${view === 'inventory' ? 'border-orange-600 text-orange-700' : 'border-transparent text-slate-500 hover:text-orange-600'}`}
        >
          <ShieldCheck className="w-4 h-4" /> Estoque & Entregas
        </button>
        <button 
          onClick={() => setView('history')}
          className={`pb-3 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${view === 'history' ? 'border-orange-600 text-orange-700' : 'border-transparent text-slate-500 hover:text-orange-600'}`}
        >
          <History className="w-4 h-4" /> Histórico Completo
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-orange-600" /></div>
      ) : (
        <>
          {view === 'inventory' && (
            <div className="space-y-6 animate-fade-in">
              {/* Toolbar */}
              <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <div className="relative w-full md:w-96">
                  <input 
                    type="text" 
                    placeholder="Buscar EPI (Nome ou CA)..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-orange-500"
                  />
                  <Search className="w-5 h-5 text-slate-400 absolute left-3 top-2.5" />
                </div>
                <button onClick={openAddModal} className="w-full md:w-auto flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 font-medium">
                  <Plus className="w-4 h-4" /> Novo EPI
                </button>
              </div>

              {/* Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredEpis.map(item => {
                  const isLow = item.quantity <= item.minStock;
                  const isDeleting = deletingId === item.id;

                  return (
                    <div key={item.id} className={`bg-white rounded-xl border shadow-sm overflow-hidden flex flex-col group ${isLow ? 'border-red-300' : 'border-slate-200'}`}>
                      <div className="p-4 flex justify-between items-start">
                        <div>
                           <h3 className="font-bold text-slate-800 text-lg leading-tight">{item.name}</h3>
                           <p className="text-xs text-slate-500 font-mono mt-1">CA: {item.caNumber || 'N/A'}</p>
                        </div>
                        <div className="flex gap-1 opacity-100 lg:opacity-0 group-hover:opacity-100 transition-opacity z-10">
                           <button 
                             onClick={() => openEditModal(item)} 
                             className="p-1.5 bg-slate-100 rounded hover:bg-indigo-100 hover:text-indigo-600 border border-slate-200"
                             title="Editar"
                           >
                             <Pencil className="w-4 h-4" />
                           </button>

                           <button 
                             type="button" 
                             onClick={(e) => handleRequestDelete(item, e)} 
                             disabled={isDeleting}
                             className="p-1.5 bg-slate-100 rounded hover:bg-red-100 hover:text-red-600 cursor-pointer border border-slate-200"
                             title="Excluir"
                           >
                             <Trash2 className="w-4 h-4 pointer-events-none" />
                           </button>
                        </div>
                      </div>

                      <div className="px-4 pb-4 flex-1">
                        <div className="flex items-baseline gap-1 mt-2">
                           <span className={`text-4xl font-bold ${isLow ? 'text-red-600' : 'text-slate-800'}`}>{item.quantity}</span>
                           <span className="text-sm text-slate-500 font-medium">un</span>
                        </div>
                        {isLow && <div className="text-xs text-red-600 flex items-center gap-1 mt-1"><AlertTriangle className="w-3 h-3" /> Estoque Baixo (Min: {item.minStock})</div>}
                      </div>

                      <div className="bg-slate-50 border-t border-slate-100 p-3 grid grid-cols-2 gap-3">
                        <button onClick={() => openDeliverModal(item, 'IN')} className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-green-700 text-xs font-bold hover:bg-green-50 uppercase">
                           <ArrowDownLeft className="w-4 h-4" /> Repor
                        </button>
                        <button onClick={() => openDeliverModal(item, 'OUT')} className="flex items-center justify-center gap-2 py-2 bg-orange-600 text-white border border-transparent rounded text-xs font-bold hover:bg-orange-700 uppercase shadow-sm">
                           <ArrowUpRight className="w-4 h-4" /> Entregar
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {view === 'history' && (
            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden animate-fade-in">
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-semibold uppercase text-xs">
                  <tr>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Tipo</th>
                    <th className="px-6 py-4">EPI</th>
                    <th className="px-6 py-4">Responsável / Funcionário</th>
                    <th className="px-6 py-4 text-right">Qtd</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {transactions.map(t => (
                    <tr key={t.id} className="hover:bg-slate-50">
                      <td className="px-6 py-4 font-mono text-slate-500">{new Date(t.date).toLocaleDateString()}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded text-xs font-bold ${t.type === 'IN' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                          {t.type === 'IN' ? 'ENTRADA' : 'ENTREGA'}
                        </span>
                      </td>
                      <td className="px-6 py-4 font-medium text-slate-700">{t.epiName}</td>
                      <td className="px-6 py-4 text-slate-600">
                        <div className="flex items-center gap-2">
                           <User className="w-4 h-4 text-slate-400" />
                           {t.employeeName}
                        </div>
                        {t.notes && <div className="text-xs text-slate-400 mt-1 italic">{t.notes}</div>}
                      </td>
                      <td className="px-6 py-4 text-right font-bold">{t.quantity}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && <tr><td colSpan={5} className="p-8 text-center text-slate-400">Sem histórico.</td></tr>}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* Modal Adicionar EPI */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">{editingId ? 'Editar EPI' : 'Novo EPI'}</h3>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-500">Nome do Equipamento</label>
                <input type="text" value={epiName} onChange={e => setEpiName(e.target.value)} className="w-full p-2 border rounded" placeholder="Ex: Bota de Segurança" />
              </div>
              <div>
                <label className="text-xs font-bold text-slate-500">C.A. (Certificado de Aprovação)</label>
                <input type="text" value={epiCa} onChange={e => setEpiCa(e.target.value)} className="w-full p-2 border rounded" placeholder="Ex: 12345" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="text-xs font-bold text-slate-500">Estoque Atual</label>
                    <input type="number" value={epiQty} onChange={e => setEpiQty(Number(e.target.value))} className="w-full p-2 border rounded" />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-500">Mínimo (Alerta)</label>
                    <input type="number" value={epiMin} onChange={e => setEpiMin(Number(e.target.value))} className="w-full p-2 border rounded" />
                 </div>
              </div>
              <div>
                 <label className="text-xs font-bold text-slate-500">Validade Média (Dias)</label>
                 <input type="number" value={epiValidity} onChange={e => setEpiValidity(Number(e.target.value))} className="w-full p-2 border rounded" placeholder="Para troca" />
              </div>
            </div>
            <div className="flex gap-3 mt-6">
               <button onClick={() => setShowAddModal(false)} className="flex-1 py-2 border rounded text-slate-600">Cancelar</button>
               <button onClick={handleSaveEpi} disabled={processing} className="flex-1 py-2 bg-orange-600 text-white rounded font-bold hover:bg-orange-700">
                  {processing ? <Loader2 className="animate-spin mx-auto"/> : 'Salvar'}
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Entrega/Movimentação */}
      {showDeliverModal && selectedEpi && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 border-t-4 border-orange-500">
            <h3 className="text-lg font-bold text-slate-800 mb-1">
               {transType === 'IN' ? 'Reposição de Estoque' : 'Entrega de EPI'}
            </h3>
            <p className="text-sm text-slate-500 mb-4">{selectedEpi.name} (CA: {selectedEpi.caNumber})</p>

            <div className="space-y-4">
               <div>
                  <label className="text-xs font-bold text-slate-500">Quantidade</label>
                  <input type="number" min="1" value={transQty} onChange={e => setTransQty(Number(e.target.value))} className="w-full p-2 border rounded text-lg font-bold text-center" />
               </div>

               {transType === 'OUT' && (
                 <div>
                    <label className="text-xs font-bold text-slate-500">Funcionário</label>
                    <select value={transEmpId} onChange={e => setTransEmpId(e.target.value)} className="w-full p-2 border rounded bg-white">
                       <option value="">Selecione...</option>
                       {activeEmployees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                    </select>
                 </div>
               )}

               <div>
                  <label className="text-xs font-bold text-slate-500">Observações (Opcional)</label>
                  <input type="text" value={transNotes} onChange={e => setTransNotes(e.target.value)} className="w-full p-2 border rounded" placeholder="Motivo, número da nota, etc." />
               </div>
            </div>

            <div className="flex gap-3 mt-6">
               <button onClick={() => setShowDeliverModal(false)} className="flex-1 py-2 border rounded text-slate-600">Cancelar</button>
               <button onClick={handleTransaction} disabled={processing} className="flex-1 py-2 bg-orange-600 text-white rounded font-bold hover:bg-orange-700">
                  {processing ? <Loader2 className="animate-spin mx-auto"/> : 'Confirmar'}
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Confirmação de Exclusão */}
      {itemToDelete && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 relative">
              <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-red-100 p-3 rounded-full border-4 border-white shadow-lg">
                 <AlertTriangle className="w-8 h-8 text-red-600" />
              </div>

              <div className="mt-6 text-center">
                <h3 className="text-xl font-bold text-slate-800 mb-2">Excluir EPI?</h3>
                <div className="bg-red-50 text-red-800 p-3 rounded-lg text-sm mb-4">
                   <p className="font-bold">Atenção!</p>
                   <p>Você está prestes a excluir: <strong>{itemToDelete.name}</strong></p>
                </div>
                <p className="text-slate-500 text-sm mb-6">
                   Isso apagará permanentemente o registro deste equipamento e <strong>todo o histórico de entregas</strong> associado a ele. Essa ação não pode ser desfeita.
                </p>

                <div className="flex gap-3">
                   <button 
                     onClick={() => setItemToDelete(null)}
                     className="flex-1 py-3 border border-slate-300 rounded-lg text-slate-700 font-medium hover:bg-slate-50"
                   >
                     Cancelar
                   </button>
                   <button 
                     onClick={confirmDelete}
                     className="flex-1 py-3 bg-red-600 text-white rounded-lg font-bold hover:bg-red-700 shadow-lg flex items-center justify-center gap-2"
                   >
                     {deletingId ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                     Excluir Definitivamente
                   </button>
                </div>
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

export default EpiControl;

import React, { useState, useMemo, useEffect } from 'react';
import { Box, Plus, Search, Filter, ArrowUpRight, ArrowDownLeft, FileText, AlertTriangle, History, Package, User, Calendar, Trash2, Save, X, Pencil, Settings, Loader2, BarChart3, AlertCircle } from 'lucide-react';
import { SupplyItem, SupplyTransaction } from '../types';
import { dataService } from '../services/dataService';

const SuppliesControl: React.FC = () => {
  // Estados
  const [view, setView] = useState<'inventory' | 'reports'>('inventory');
  const [supplies, setSupplies] = useState<SupplyItem[]>([]);
  const [history, setHistory] = useState<SupplyTransaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // Estado para Modais
  const [showAddModal, setShowAddModal] = useState(false);
  const [showTransactionModal, setShowTransactionModal] = useState(false);

  // Novo Estado para Modal de Exclusão
  const [itemToDelete, setItemToDelete] = useState<SupplyItem | null>(null);

  const [transactionType, setTransactionType] = useState<'IN' | 'OUT'>('OUT');
  const [selectedSupply, setSelectedSupply] = useState<SupplyItem | null>(null);

  // Estado de Edição e Processamento
  const [editingId, setEditingId] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Form States
  const [newItemName, setNewItemName] = useState('');
  const [newItemUnit, setNewItemUnit] = useState('un');
  const [newItemMin, setNewItemMin] = useState(10);
  const [newItemQty, setNewItemQty] = useState(0);

  const [transQty, setTransQty] = useState(1);
  const [transUser, setTransUser] = useState('');

  // Carregar dados ao montar
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [items, transactions] = await Promise.all([
        dataService.getSupplies(),
        dataService.getSupplyTransactions()
      ]);
      setSupplies(items);
      setHistory(transactions);
    } catch (error) {
      console.error("Erro ao carregar insumos:", error);
    } finally {
      setLoading(false);
    }
  };

  // --- Filtros ---
  const filteredSupplies = supplies.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Ações ---

  const handleSaveItem = async () => {
    if (!newItemName) return;
    setProcessing(true);

    try {
      const isNew = !editingId;
      const itemId = editingId || `supply-${Date.now()}`;

      const itemToSave: SupplyItem = {
        id: itemId,
        name: newItemName,
        unit: newItemUnit,
        minStock: newItemMin,
        quantity: isNew ? newItemQty : newItemQty // Se for edição, assume o valor atualizado
      };

      await dataService.saveSupply(itemToSave);

      if (isNew && newItemQty > 0) {
        const trans: SupplyTransaction = {
          id: `init-${Date.now()}`,
          supplyId: itemId,
          supplyName: newItemName,
          type: 'IN',
          quantity: newItemQty,
          date: new Date().toISOString(),
          user: 'Cadastro Inicial'
        };
        await dataService.addSupplyTransaction(trans);
      }

      await loadData();
      closeModal();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar item.");
    } finally {
      setProcessing(false);
    }
  };

  const openAddModal = () => {
    setEditingId(null);
    resetForms();
    setShowAddModal(true);
  };

  const openEditModal = (item: SupplyItem) => {
    setEditingId(item.id);
    setNewItemName(item.name);
    setNewItemUnit(item.unit);
    setNewItemMin(item.minStock);
    setNewItemQty(item.quantity);
    setShowAddModal(true);
  };

  const closeModal = () => {
    setShowAddModal(false);
    setEditingId(null);
    resetForms();
  };

  const openTransaction = (item: SupplyItem, type: 'IN' | 'OUT') => {
    setSelectedSupply(item);
    setTransactionType(type);
    setTransQty(1);
    setTransUser('');
    setShowTransactionModal(true);
  };

  const confirmTransaction = async () => {
    if (!selectedSupply || !transUser) {
      alert("Preencha todos os campos.");
      return;
    }
    if (transactionType === 'OUT' && transQty > selectedSupply.quantity) {
      alert("Estoque insuficiente!");
      return;
    }

    setProcessing(true);
    try {
      const newQuantity = transactionType === 'IN' 
        ? selectedSupply.quantity + transQty 
        : selectedSupply.quantity - transQty;

      const updatedSupply = { ...selectedSupply, quantity: newQuantity };

      await dataService.saveSupply(updatedSupply);

      const newTrans: SupplyTransaction = {
        id: `trans-${Date.now()}`,
        supplyId: selectedSupply.id,
        supplyName: selectedSupply.name,
        type: transactionType,
        quantity: transQty,
        date: new Date().toISOString(),
        user: transUser
      };

      await dataService.addSupplyTransaction(newTrans);

      await loadData();
      setShowTransactionModal(false);
    } catch (error) {
      console.error(error);
      alert("Erro ao processar transação.");
    } finally {
      setProcessing(false);
    }
  };

  const handleRequestDelete = (item: SupplyItem, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setItemToDelete(item);
  };

  const confirmDelete = async () => {
    if (!itemToDelete) return;

    setDeletingId(itemToDelete.id);
    try {
      await dataService.deleteSupply(itemToDelete.id);
      setSupplies(prev => prev.filter(s => s.id !== itemToDelete.id));
      await loadData(); // Reload for safety
      setItemToDelete(null);
    } catch (error: any) {
      console.error("Erro delete:", error);
      alert(`Erro: ${error.message}`);
    } finally {
      setDeletingId(null);
    }
  };

  const resetForms = () => {
    setNewItemName('');
    setNewItemQty(0);
    setNewItemMin(10);
    setTransQty(1);
    setTransUser('');
  };

  // --- Cálculos de Relatório ---
  const reportStats = useMemo(() => {
    return supplies.map(supply => {
      // Filtrar saídas deste item
      const outputs = history.filter(h => h.supplyId === supply.id && h.type === 'OUT');
      const totalConsumed = outputs.reduce((acc, curr) => acc + curr.quantity, 0);

      // Encontrar última movimentação
      const lastMove = history
        .filter(h => h.supplyId === supply.id)
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0];

      return {
        ...supply,
        totalConsumed,
        lastMoveDate: lastMove ? new Date(lastMove.date).toLocaleDateString('pt-BR') : '-'
      };
    });
  }, [supplies, history]);

  if (loading && supplies.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-500">
        <Loader2 className="w-10 h-10 animate-spin mb-4 text-emerald-600" />
        <p>Carregando estoque...</p>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10 relative">
      {/* Header */}
      <div className="bg-emerald-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <Box className="w-8 h-8" />
          Controle de Insumos
        </h2>
        <p className="text-emerald-100 max-w-xl">
          Gestão de estoque, controle de saídas e previsão de consumo.
        </p>
      </div>

      {/* Navegação de Abas */}
      <div className="flex border-b border-slate-200 gap-6">
        <button 
          onClick={() => setView('inventory')}
          className={`pb-3 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${view === 'inventory' ? 'border-emerald-600 text-emerald-700' : 'border-transparent text-slate-500 hover:text-emerald-600'}`}
        >
          <Package className="w-4 h-4" /> Inventário
        </button>
        <button 
          onClick={() => setView('reports')}
          className={`pb-3 text-sm font-medium flex items-center gap-2 border-b-2 transition-colors ${view === 'reports' ? 'border-emerald-600 text-emerald-700' : 'border-transparent text-slate-500 hover:text-emerald-600'}`}
        >
          <BarChart3 className="w-4 h-4" /> Relatórios de Uso
        </button>
      </div>

      {/* === VIEW: INVENTÁRIO === */}
      {view === 'inventory' && (
        <div className="space-y-6 animate-fade-in">
          {/* Toolbar */}
          <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
            <div className="relative w-full md:w-96">
              <input 
                type="text" 
                placeholder="Buscar insumo..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <Search className="w-5 h-5 text-slate-400 absolute left-3 top-2.5" />
            </div>

            <button 
              onClick={openAddModal}
              className="w-full md:w-auto flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 font-medium shadow-sm transition-colors"
            >
              <Plus className="w-4 h-4" /> Novo Item
            </button>
          </div>

          {/* Grid de Itens */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredSupplies.map(item => {
              const isLowStock = item.quantity <= item.minStock;
              const isDeleting = deletingId === item.id;

              return (
                <div key={item.id} className={`bg-white rounded-xl border shadow-sm overflow-hidden flex flex-col transition-all hover:shadow-md ${isLowStock ? 'border-red-200' : 'border-slate-200'}`}>

                  {/* Header do Card (Título + Ações) */}
                  <div className="p-4 pb-0 flex justify-between items-start">
                    <div className="pr-2">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-bold text-slate-800 text-lg leading-tight">{item.name}</h3>
                        {isLowStock && (
                          <div className="bg-red-100 text-red-700 p-1 rounded-full flex-shrink-0" title="Estoque Baixo">
                            <AlertTriangle className="w-3 h-3" />
                          </div>
                        )}
                      </div>
                    </div>

                    {/* Botões de Ação */}
                    <div className="flex gap-1 flex-shrink-0 z-20">
                      <button 
                        type="button"
                        onClick={() => openEditModal(item)}
                        className="p-1.5 bg-slate-50 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 border border-slate-200 rounded-md transition-colors"
                        title="Editar"
                      >
                        <Pencil className="w-4 h-4 pointer-events-none" />
                      </button>

                      <button 
                        type="button"
                        onClick={(e) => handleRequestDelete(item, e)}
                        disabled={isDeleting}
                        className="p-1.5 bg-slate-50 text-slate-500 hover:text-red-600 hover:bg-red-50 border border-slate-200 rounded-md transition-colors cursor-pointer"
                        title="Excluir"
                      >
                         <Trash2 className="w-4 h-4 pointer-events-none" />
                      </button>
                    </div>
                  </div>

                  {/* Conteúdo do Card */}
                  <div className="px-4 pb-4 flex-1">
                    <div className="flex items-baseline gap-1 mt-2">
                       <span className={`text-4xl font-bold ${isLowStock ? 'text-red-600' : 'text-slate-800'}`}>
                         {item.quantity}
                       </span>
                       <span className="text-sm text-slate-500 font-medium">{item.unit}</span>
                    </div>
                    <p className="text-xs text-slate-400 mt-1">Mínimo: {item.minStock} {item.unit}</p>
                  </div>

                  {/* Rodapé com botões grandes */}
                  <div className="bg-slate-50 border-t border-slate-100 p-3 grid grid-cols-2 gap-3 mt-auto">
                    <button 
                      type="button"
                      onClick={() => openTransaction(item, 'IN')}
                      className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-green-700 text-sm font-medium hover:bg-green-50 hover:border-green-200 transition-colors"
                    >
                      <ArrowDownLeft className="w-4 h-4" /> Entrada
                    </button>
                    <button 
                      type="button"
                      onClick={() => openTransaction(item, 'OUT')}
                      className="flex items-center justify-center gap-2 py-2 bg-white border border-slate-200 rounded text-red-700 text-sm font-medium hover:bg-red-50 hover:border-red-200 transition-colors"
                    >
                      <ArrowUpRight className="w-4 h-4" /> Saída
                    </button>
                  </div>
                </div>
              );
            })}

            {filteredSupplies.length === 0 && (
