import React, { useState, useRef, useEffect } from 'react';
import { Upload, FileSpreadsheet, AlertCircle, CheckCircle2, Loader2, Play, Package, Layers, RefreshCw, Users, Briefcase, UserX, Palmtree, MapPin, Calendar, Clock, Plus, Trash2, Truck, Send, ArrowRight, AlertTriangle, ArrowLeftRight, PackageX, Ban, Copy, Check } from 'lucide-react';
import * as XLSX from 'xlsx';
import { DailyRecord } from '../types';

interface Props {
  history?: DailyRecord[];
}

interface ManagementTrip {
  id: string;
  route: string;
  datetime: string;
}

// Helper para encontrar nomes de colunas variados
const findColumnName = (row: any, possibleNames: string[]): string | undefined => {
  if (!row) return undefined;
  const keys = Object.keys(row);
  for (const name of possibleNames) {
    const found = keys.find(k => k.trim().toLowerCase() === name.toLowerCase());
    if (found) return found;
  }
  return undefined;
};

// Helper para ler arquivo Excel
const readFile = (file: File): Promise<any[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        if (workbook.SheetNames.length === 0) {
          resolve([]);
          return;
        }
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const jsonData = XLSX.utils.sheet_to_json<any>(worksheet, { defval: "" });
        resolve(jsonData);
      } catch (error) {
        reject(error);
      }
    };
    reader.onerror = (error) => reject(error);
    reader.readAsBinaryString(file);
  });
};

const ManagementReport: React.FC<Props> = ({ history = [] }) => {
  // Refs para inputs de arquivo
  const processedInputRef = useRef<HTMLInputElement>(null);
  const shippedInputRef = useRef<HTMLInputElement>(null);

  // Estados dos arquivos
  const [selectedProcessedFile, setSelectedProcessedFile] = useState<File | null>(null);
  const [selectedShippedFile, setSelectedShippedFile] = useState<File | null>(null);

  const [status, setStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [message, setMessage] = useState('');

  // Data do Report
  const [reportDate, setReportDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Configuração de inputs (Equipe)
  const [plannedEmployees, setPlannedEmployees] = useState<number>(17);
  const [outsourcedEmployees, setOutsourcedEmployees] = useState<number>(0);
  const [absentEmployees, setAbsentEmployees] = useState<number>(0);
  const [vacationEmployees, setVacationEmployees] = useState<number>(0);

  // Configuração de inputs (Anormalidades)
  const [shippedNotArrived, setShippedNotArrived] = useState<number>(0);
  const [sortingErrors, setSortingErrors] = useState<number>(0);
  const [damages, setDamages] = useState<number>(0);
  const [barred, setBarred] = useState<number>(0);

  // Viagens
  const [trips, setTrips] = useState<ManagementTrip[]>([]);

  // Estado para botão de copiar
  const [textCopied, setTextCopied] = useState(false);

  // Carregar dados iniciais do histórico quando a data muda
  useEffect(() => {
    const record = history.find(h => h.date === reportDate);
    if (record) {
      // Carregar Viagens
      if (record.trips && record.trips.length > 0) {
        const mappedTrips: ManagementTrip[] = record.trips.map(t => ({
          id: t.id,
          route: 'SP BRE X SE AJU', // Default
          datetime: t.unsealTimestamp || '' // Usa o timestamp de deslacre se houver
        }));
        setTrips(mappedTrips);
      } else {
        setTrips([]);
      }
    } else {
      setTrips([]);
    }
  }, [reportDate, history]);

  // Estado para armazenar os resultados do processamento
  const [results, setResults] = useState<{ 
    multiple: number; 
    processed: number; 
    shipped: number;
    shippedByBase: Record<string, number>;
    planned: number;
    outsourced: number;
    absent: number;
    vacation: number;
    shippedNotArrived: number;
    sortingErrors: number;
    damages: number;
    barred: number;
    trips: ManagementTrip[];
  } | null>(null);

  // Handlers para Viagens
  const handleAddTrip = () => {
    setTrips(prev => [...prev, { id: '', route: 'SP BRE X SE AJU', datetime: '' }]);
  };

  const handleRemoveTrip = (index: number) => {
    setTrips(prev => prev.filter((_, i) => i !== index));
  };

  const handleTripChange = (index: number, field: keyof ManagementTrip, value: string) => {
    setTrips(prev => {
      const newTrips = [...prev];
      newTrips[index] = { ...newTrips[index], [field]: value };
      return newTrips;
    });
  };

  // Handlers de Arquivo
  const triggerProcessedInput = () => processedInputRef.current?.click();
  const triggerShippedInput = () => shippedInputRef.current?.click();

  const handleProcessedFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setSelectedProcessedFile(file);
      setStatus('idle');
      setMessage('');
      setResults(null);
    }
  };

  const handleShippedFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setSelectedShippedFile(file);
      setStatus('idle');
      setMessage('');
      setResults(null);
    }
  };

  const handleReset = () => {
    setSelectedProcessedFile(null);
    setSelectedShippedFile(null);
    setStatus('idle');
    setResults(null);
    setMessage('');
    if (processedInputRef.current) processedInputRef.current.value = '';
    if (shippedInputRef.current) shippedInputRef.current.value = '';
  };

  const handleGenerateReport = async () => {
    if (!selectedProcessedFile) {
      alert("É obrigatório selecionar pelo menos a Planilha de Processados.");
      return;
    }

    setStatus('processing');
    setMessage('Lendo e processando dados...');

    try {
      // Ler arquivos (Expedidos é opcional, mas se não tiver, conta como 0 ou ignora)
      const promises = [readFile(selectedProcessedFile)];
      if (selectedShippedFile) {
        promises.push(readFile(selectedShippedFile));
      }

      const [processedData, shippedData] = await Promise.all(promises);

      // --- Processar Planilha 1: Processados ---
      if (processedData.length === 0) throw new Error("A planilha de processados está vazia.");

      const processedCol = findColumnName(processedData[0], ['Número de pedido JMS', 'Numero de pedido JMS', 'Pedido', 'Order ID']);
      if (!processedCol) throw new Error("Coluna 'Número de pedido JMS' não encontrada na planilha de processados.");

      let countMultiples = 0; // Total de pedidos
      let countProcessed = 0; // Pedidos Pai (sem hífen)

      processedData.forEach((row: any) => {
        const rawId = row[processedCol];
        if (rawId) {
          const idStr = String(rawId).trim();
          if (idStr.length > 0) {
            countMultiples++;
            if (!idStr.includes('-')) {
              countProcessed++;
            }
          }
        }
      });

      // --- Processar Planilha 2: Expedidos (Se houver) ---
      let countShipped = 0;
      const shippedByBase: Record<string, number> = {};

      if (shippedData && shippedData.length > 0) {
        const shippedOrderCol = findColumnName(shippedData[0], ['Número de pedido JMS', 'Numero de pedido JMS', 'Pedido', 'Order ID']);
        const shippedBaseCol = findColumnName(shippedData[0], ['Parada anterior ou próxima', 'Parada anterior ou proxima', 'Next Stop', 'Parada', 'Destino']);

        if (shippedOrderCol) {
          shippedData.forEach((row: any) => {
             const rawId = row[shippedOrderCol];
             if (rawId) {
               const idStr = String(rawId).trim().toUpperCase();

               // Filtros de Expedição:
               // 1. Não pode conter hífen (Pedido filho)
               // 2. Não pode começar com 'BR' (Lote)
               if (idStr.length > 0 && !idStr.includes('-') && !idStr.startsWith('BR')) {
                 countShipped++;

                 // Agrupar por Base
                 if (shippedBaseCol) {
                   const base = row[shippedBaseCol] ? String(row[shippedBaseCol]).trim().toUpperCase() : 'INDEFINIDO';
                   shippedByBase[base] = (shippedByBase[base] || 0) + 1;
                 }
               }
             }
          });
        } else {
           // Fallback se não achar coluna de pedido (apenas conta linhas, mas sem filtros complexos)
           countShipped = shippedData.length;
        }
      }

      setResults({
        multiple: countMultiples,
        processed: countProcessed,
        shipped: countShipped,
        shippedByBase: shippedByBase,
        planned: plannedEmployees,
        outsourced: outsourcedEmployees,
        absent: absentEmployees,
        vacation: vacationEmployees,
        shippedNotArrived: shippedNotArrived,
        sortingErrors: sortingErrors,
        damages: damages,
        barred: barred,
        trips: trips
      });

      setStatus('success');
      setMessage('Análise concluída com sucesso!');

    } catch (err: any) {
      console.error(err);
      setStatus('error');
      setMessage(err.message || 'Erro ao processar arquivos.');
    }
  };

  const formatSummaryDate = (isoDate: string) => {
    const [year, month, day] = isoDate.split('-');
    return `${day}-${month}-${year}`;
  };

  const formatZero = (num: number) => {
    return num === 0 ? "00" : num.toLocaleString('pt-BR');
  };

  const generateSummaryText = () => {
    if (!results) return '';

    const dateStr = formatSummaryDate(reportDate);

    let text = `Operação finalizada SE AJU - ${dateStr}\n\n`;

    text += `Quantidade de Pacotes Processados: ${results.processed.toLocaleString('pt-BR')}\n`;
    text += `Quantidade de Pacotes Múltiplos: ${results.multiple.toLocaleString('pt-BR')}\n`;
    text += `Quantidade de colaboradores planejados: ${results.planned}\n`;
    text += `Quantidade de terceirizados: ${formatZero(results.outsourced)}\n`;
    text += `Quantidade de colaboradores em folga/falta: ${formatZero(results.absent)}\n`;
    text += `Quantidade de colaboradores em férias: ${formatZero(results.vacation)}\n\n`;

    text += `IDs do dia e horário de chegada:\n\n`;

    if (results.trips.length > 0) {
      results.trips.forEach(trip => {
        text += `ID: ${trip.id} - ${trip.route} - Horário de chegada: ${trip.datetime}\n`;
      });
    } else {
      text += `(Nenhuma viagem registrada)\n`;
    }

    text += `\nQuantidade de pacotes expedidos:\n\n`;

    if (Object.keys(results.shippedByBase).length > 0) {
      Object.entries(results.shippedByBase)
        .sort(([, a], [, b]) => (b as number) - (a as number))
        .forEach(([base, count]) => {
          text += `${base}: ${count}\n`;
        });
    } else {
       text += `0\n`;
    }

    text += `\nAnormalidades:\n\n`;
    text += `Expediu mas não chegou: ${formatZero(results.shippedNotArrived)}\n`;
    text += `Erro de triagem no SC: ${formatZero(results.sortingErrors)}\n`;
    text += `Avarias: ${formatZero(results.damages)}\n`;
    text += `Barrados: ${formatZero(results.barred)}`;

    return text;
  };

  const copyToClipboard = () => {
    const text = generateSummaryText();
    navigator.clipboard.writeText(text);
    setTextCopied(true);
    setTimeout(() => setTextCopied(false), 2000);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 pb-10">
      {/* Header */}
      <div className="bg-indigo-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1554224155-8d04cb21cd6c?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2">Relatório de Gestão</h2>
        <p className="text-indigo-100 max-w-xl">
          Importe as planilhas de dados gerenciais (Processados e Expedidos) para calcular indicadores operacionais.
        </p>
      </div>

      {/* Área Principal */}
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">

        {/* Se já tiver resultados, mostra painel de resultados */}
        {status === 'success' && results ? (
          <div className="space-y-8 animate-fade-in">
            <div className="flex items-center justify-between">
               <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                 <CheckCircle2 className="w-6 h-6 text-green-600" />
                 Resultados da Análise - {new Date(reportDate).toLocaleDateString('pt-BR')}
               </h3>
               <button 
                 onClick={handleReset}
                 className="text-sm text-slate-500 hover:text-indigo-600 flex items-center gap-1 font-medium transition-colors"
               >
                 <RefreshCw className="w-4 h-4" /> Nova Análise
               </button>
            </div>

            {/* Seção de Viagens no Resultado */}
            {results.trips.length > 0 && (
              <div className="bg-slate-50 border border-slate-200 rounded-xl p-4 mb-4">
                <h4 className="text-sm font-semibold text-slate-700 mb-3 flex items-center gap-2">
                  <Truck className="w-4 h-4" /> Viagens Registradas
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {results.trips.map((trip, idx) => (
                    <div key={idx} className="bg-white p-3 rounded-lg border border-slate-200 shadow-sm flex flex-col gap-1">
                      <div className="flex justify-between items-start">
                        <span className="font-bold text-indigo-700">{trip.id}</span>
                        <span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded text-slate-500">{trip.route}</span>
                      </div>
                      {trip.datetime && (
                         <div className="flex items-center gap-1 text-xs text-slate-500 mt-1">
                           <Clock className="w-3 h-3" /> <span className="font-medium">Chegada:</span> {trip.datetime}
                         </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {/* Card: Pacotes Múltiplos (Total) */}
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-blue-100 p-3 rounded-full mb-2">
                  <Layers className="w-6 h-6 text-blue-600" />
                </div>
                <p className="text-sm font-semibold text-blue-800 uppercase tracking-wide">Múltiplos</p>
                <p className="text-3xl font-bold text-slate-800">{results.multiple.toLocaleString('pt-BR')}</p>
                <p className="text-xs text-blue-600">Total processados</p>
              </div>

              {/* Card: Pacotes Processados (Sem Hífen) */}
              <div className="bg-green-50 border border-green-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-green-100 p-3 rounded-full mb-2">
                  <Package className="w-6 h-6 text-green-600" />
                </div>
                <p className="text-sm font-semibold text-green-800 uppercase tracking-wide">Processados</p>
                <p className="text-3xl font-bold text-slate-800">{results.processed.toLocaleString('pt-BR')}</p>
                <p className="text-xs text-green-600">Pedidos únicos (Pai)</p>
              </div>

              {/* Card: Expedidos (Novo) */}
              <div className="bg-teal-50 border border-teal-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-teal-100 p-3 rounded-full mb-2">
                  <Send className="w-6 h-6 text-teal-600" />
                </div>
                <p className="text-sm font-semibold text-teal-800 uppercase tracking-wide">Expedidos</p>
                <p className="text-3xl font-bold text-slate-800">{results.shipped.toLocaleString('pt-BR')}</p>
                <p className="text-xs text-teal-600">Pedidos Filtrados</p>
              </div>

              {/* Card: Colaboradores Planejados */}
              <div className="bg-purple-50 border border-purple-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-purple-100 p-3 rounded-full mb-2">
                  <Users className="w-6 h-6 text-purple-600" />
                </div>
                <p className="text-sm font-semibold text-purple-800 uppercase tracking-wide">Planejados</p>
                <p className="text-3xl font-bold text-slate-800">{results.planned}</p>
                <p className="text-xs text-purple-600">Equipe Meta</p>
              </div>

              {/* Card: Terceirizados */}
              <div className="bg-orange-50 border border-orange-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-orange-100 p-3 rounded-full mb-2">
                  <Briefcase className="w-6 h-6 text-orange-600" />
                </div>
                <p className="text-sm font-semibold text-orange-800 uppercase tracking-wide">Terceiros</p>
                <p className="text-3xl font-bold text-slate-800">{results.outsourced}</p>
                <p className="text-xs text-orange-600">Apoio</p>
              </div>

              {/* Card: Folga/Falta */}
              <div className="bg-red-50 border border-red-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-red-100 p-3 rounded-full mb-2">
                  <UserX className="w-6 h-6 text-red-600" />
                </div>
                <p className="text-sm font-semibold text-red-800 uppercase tracking-wide">Folga/Falta</p>
                <p className="text-3xl font-bold text-slate-800">{results.absent}</p>
                <p className="text-xs text-red-600">Ausências</p>
              </div>

              {/* Card: Férias */}
              <div className="bg-cyan-50 border border-cyan-100 rounded-xl p-6 flex flex-col items-center text-center gap-2 shadow-sm relative overflow-hidden">
                <div className="bg-cyan-100 p-3 rounded-full mb-2">
                  <Palmtree className="w-6 h-6 text-cyan-600" />
                </div>
                <p className="text-sm font-semibold text-cyan-800 uppercase tracking-wide">Férias</p>
                <p className="text-3xl font-bold text-slate-800">{results.vacation}</p>
                <p className="text-xs text-cyan-600">Afastados</p>
              </div>
            </div>

            {/* Grid de Anormalidades / Qualidade */}
            <h4 className="text-lg font-bold text-slate-800 mt-8 mb-4 flex items-center gap-2 border-t pt-6 border-slate-100">
               <AlertTriangle className="w-5 h-5 text-amber-500" /> Indicadores de Qualidade / Anormalidades
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
               {/* Expediu mas não chegou */}
               <div className="bg-amber-50 border border-amber-200 rounded-xl p-5 flex flex-col items-center text-center">
                  <p className="text-sm font-bold text-amber-800 mb-1">Expediu mas não chegou</p>
                  <p className="text-3xl font-bold text-slate-800">{results.shippedNotArrived}</p>
               </div>

               {/* Erro de Triagem */}
               <div className="bg-rose-50 border border-rose-200 rounded-xl p-5 flex flex-col items-center text-center">
                  <p className="text-sm font-bold text-rose-800 mb-1">Erro de Triagem SC</p>
                  <p className="text-3xl font-bold text-slate-800">{results.sortingErrors}</p>
               </div>

               {/* Avarias */}
               <div className="bg-red-50 border border-red-200 rounded-xl p-5 flex flex-col items-center text-center">
                  <p className="text-sm font-bold text-red-800 mb-1">Avarias</p>
                  <p className="text-3xl font-bold text-slate-800">{results.damages}</p>
               </div>

               {/* Barrados */}
               <div className="bg-slate-100 border border-slate-300 rounded-xl p-5 flex flex-col items-center text-center">
                  <p className="text-sm font-bold text-slate-700 mb-1">Barrados</p>
                  <p className="text-3xl font-bold text-slate-800">{results.barred}</p>
               </div>
            </div>


            {/* Detalhamento de Expedição por Base (NOVO) */}
            {Object.keys(results.shippedByBase).length > 0 && (
              <div className="bg-teal-50/50 border border-teal-100 rounded-xl p-6 mt-6">
                <h4 className="text-lg font-bold text-teal-900 mb-4 flex items-center gap-2">
                  <ArrowRight className="w-5 h-5" /> Detalhamento de Expedição por Base
                </h4>
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
                  {Object.entries(results.shippedByBase)
                    .sort(([, a], [, b]) => (b as number) - (a as number)) // Ordenar por quantidade decrescente
                    .map(([base, count]) => (
                      <div key={base} className="bg-white p-3 rounded-lg border border-teal-100 shadow-sm flex flex-col">
                        <span className="text-xs font-bold text-teal-600 uppercase truncate" title={base}>{base}</span>
                        <span className="text-2xl font-bold text-slate-800">{count}</span>
                      </div>
                    ))}
                </div>
              </div>
            )}

            {/* Gerador de Texto para Cópia (NOVO) */}
            <div className="bg-slate-100 p-6 rounded-xl border border-slate-200 mt-8 relative group">
              <div className="flex items-center justify-between mb-4">
                 <h4 className="font-bold text-slate-700 flex items-center gap-2">
                   <Copy className="w-4 h-4" /> Resumo para Divulgação
                 </h4>
                 <button 
                  onClick={copyToClipboard}
                  className="flex items-center gap-1.5 px-3 py-1.5 bg-white text-slate-700 border border-slate-300 rounded-lg text-xs font-medium hover:bg-slate-50 hover:text-indigo-600 transition-colors shadow-sm"
                 >
                   {textCopied ? <Check className="w-3.5 h-3.5 text-green-600" /> : <Copy className="w-3.5 h-3.5" />}
                   {textCopied ? 'Copiado!' : 'Copiar Texto'}
                 </button>
              </div>
              <pre className="font-mono text-sm text-slate-800 whitespace-pre-wrap leading-relaxed bg-white/50 p-4 rounded-lg border border-slate-200 overflow-auto max-h-[500px]">
                {generateSummaryText()}
              </pre>
            </div>

            <div className="bg-slate-50 p-4 rounded-lg text-sm text-slate-600 border border-slate-200 mt-8">
              <p><span className="font-semibold">Planilha Processados:</span> {selectedProcessedFile?.name}</p>
              {selectedShippedFile && (
                <p className="mt-1"><span className="font-semibold">Planilha Expedidos:</span> {selectedShippedFile.name}</p>
              )}
            </div>
          </div>
        ) : (
          /* Se não tiver resultados, mostra Configuração e Upload */
          <div className="flex flex-col gap-8">

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                 <label className="text-sm font-medium text-slate-700 whitespace-nowrap flex items-center gap-2">
                   <Calendar className="w-4 h-4 text-indigo-600" /> Data do Relatório:
                 </label>
                 <input 
                   type="date"
                   value={reportDate}
                   onChange={(e) => setReportDate(e.target.value)}
                   className="px-3 py-2 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full"
                 />
              </div>
            </div>

            {/* Configuração de Viagens */}
            <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
              <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                 <Truck className="w-5 h-5 text-indigo-600" />
                 Viagens do Dia
               </h3>

               <div className="space-y-3">
                 {trips.map((trip, idx) => (
                   <div key={idx} className="flex flex-col md:flex-row gap-3 items-end md:items-end bg-white p-4 rounded-lg border border-slate-200 shadow-sm animate-fade-in">
                      <div className="flex-1 w-full">
                         <label className="block text-xs font-bold text-slate-500 mb-1">ID da Viagem</label>
                         <input 
                           type="text"
                           placeholder="ID Viagem"
                           value={trip.id}
                           onChange={(e) => handleTripChange(idx, 'id', e.target.value)}
                           className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded focus:ring-2 focus:ring-indigo-500 outline-none uppercase font-mono text-sm"
                         />
                      </div>
                      <div className="flex-1 w-full">
                         <label className="block text-xs font-bold text-slate-500 mb-1">Rota</label>
                         <div className="relative">
                            <select 
                              value={trip.route}
                              onChange={(e) => handleTripChange(idx, 'route', e.target.value)}
                              className="w-full pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                            >
                              <option value="SP BRE X BA FEC X SE AJU">SP BRE X BA FEC X SE AJU</option>
                              <option value="SP BRE X SE AJU">SP BRE X SE AJU</option>
                            </select>
                            <MapPin className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
                         </div>
                      </div>
                      <div className="flex-1 w-full">
                         <label className="block text-xs font-bold text-slate-500 mb-1">Data e Hora de Chegada</label>
                         <input 
                           type="text"
                           placeholder="DD/MM/AAAA HH:mm"
                           value={trip.datetime}
                           onChange={(e) => handleTripChange(idx, 'datetime', e.target.value)}
                           className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                         />
                      </div>
                      <button
                        onClick={() => handleRemoveTrip(idx)}
                        className="p-2 mb-0.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded transition-colors"
                        title="Remover"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                   </div>
                 ))}
                 <button
                    onClick={handleAddTrip}
                    className="w-full py-2 border border-dashed border-indigo-300 text-indigo-600 rounded-lg text-sm font-medium hover:bg-indigo-50 hover:border-indigo-400 transition-all flex items-center justify-center gap-2"
                  >
                    <Plus className="w-4 h-4" />
                    Adicionar Viagem
                  </button>
               </div>
            </div>

            {/* Configuração da Equipe */}
            <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
               <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                 <Users className="w-5 h-5 text-indigo-600" />
                 Dados da Equipe
               </h3>

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Planejados</label>
                   <input type="number" min="1" value={plannedEmployees} onChange={(e) => setPlannedEmployees(Number(e.target.value))} className="w-full px-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Terceirizados</label>
                   <input type="number" min="0" value={outsourcedEmployees} onChange={(e) => setOutsourcedEmployees(Number(e.target.value))} className="w-full px-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Folga / Falta</label>
                   <input type="number" min="0" value={absentEmployees} onChange={(e) => setAbsentEmployees(Number(e.target.value))} className="w-full px-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Férias</label>
                   <input type="number" min="0" value={vacationEmployees} onChange={(e) => setVacationEmployees(Number(e.target.value))} className="w-full px-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                 </div>
               </div>
            </div>

            {/* Configuração de Anormalidades */}
            <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
               <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                 <AlertTriangle className="w-5 h-5 text-amber-500" />
                 Indicadores de Qualidade / Anormalidades
               </h3>

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Expediu mas não chegou</label>
                   <div className="relative">
                     <input type="number" min="0" value={shippedNotArrived} onChange={(e) => setShippedNotArrived(Number(e.target.value))} className="w-full pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                     <Truck className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
                   </div>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Erro de triagem SC</label>
                   <div className="relative">
                     <input type="number" min="0" value={sortingErrors} onChange={(e) => setSortingErrors(Number(e.target.value))} className="w-full pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                     <ArrowLeftRight className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
                   </div>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Avarias</label>
                   <div className="relative">
                     <input type="number" min="0" value={damages} onChange={(e) => setDamages(Number(e.target.value))} className="w-full pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                     <PackageX className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
                   </div>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-600 mb-1">Barrados</label>
                   <div className="relative">
                     <input type="number" min="0" value={barred} onChange={(e) => setBarred(Number(e.target.value))} className="w-full pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" />
                     <Ban className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
                   </div>
                 </div>
               </div>
            </div>

            {/* Upload Area - GRID DUPLO */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Box 1: Processados */}
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">1. Planilha de Pedidos Processados</label>
                <input 
                  type="file" 
                  ref={processedInputRef} 
                  onChange={handleProcessedFileChange} 
                  accept=".xlsx,.xls,.csv" 
                  className="hidden" 
                />

                <div 
                  onClick={triggerProcessedInput}
                  className={`
                    w-full p-8 border-2 border-dashed rounded-xl flex flex-col items-center gap-4 cursor-pointer transition-all group h-48 justify-center
                    ${selectedProcessedFile 
                      ? 'border-indigo-300 bg-indigo-50' 
                      : 'border-slate-300 bg-slate-50 hover:bg-slate-100 hover:border-indigo-400'
                    }
                  `}
                >
                  {selectedProcessedFile ? (
                    <>
                      <FileSpreadsheet className="w-10 h-10 text-indigo-600" />
                      <div className="text-center">
                        <p className="font-bold text-slate-800 break-all text-sm">{selectedProcessedFile.name}</p>
                        <p className="text-xs text-indigo-600 font-medium mt-1">Processados Selecionado</p>
                      </div>
                    </>
                  ) : (
                    <>
                      <Upload className="w-10 h-10 text-slate-400 group-hover:text-indigo-500 transition-colors" />
                      <div className="text-center">
                        <p className="font-medium text-slate-700 text-sm">Carregar Processados</p>
                        <p className="text-xs text-slate-500 mt-1">.xlsx, .xls, .csv</p>
                      </div>
                    </>
                  )}
                </div>
              </div>

              {/* Box 2: Expedidos */}
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">2. Planilha de Pedidos Expedidos</label>
                <input 
                  type="file" 
                  ref={shippedInputRef} 
                  onChange={handleShippedFileChange} 
                  accept=".xlsx,.xls,.csv" 
                  className="hidden" 
                />

                <div 
                  onClick={triggerShippedInput}
                  className={`
                    w-full p-8 border-2 border-dashed rounded-xl flex flex-col items-center gap-4 cursor-pointer transition-all group h-48 justify-center
                    ${selectedShippedFile 
                      ? 'border-teal-300 bg-teal-50' 
                      : 'border-slate-300 bg-slate-50 hover:bg-slate-100 hover:border-teal-400'
                    }
                  `}
                >
                  {selectedShippedFile ? (
                    <>
                      <FileSpreadsheet className="w-10 h-10 text-teal-600" />
                      <div className="text-center">
                        <p className="font-bold text-slate-800 break-all text-sm">{selectedShippedFile.name}</p>
                        <p className="text-xs text-teal-600 font-medium mt-1">Expedidos Selecionado</p>
                      </div>
                    </>
                  ) : (
                    <>
                      <Upload className="w-10 h-10 text-slate-400 group-hover:text-teal-500 transition-colors" />
                      <div className="text-center">
                        <p className="font-medium text-slate-700 text-sm">Carregar Expedidos</p>
                        <p className="text-xs text-slate-500 mt-1">.xlsx, .xls, .csv</p>
                      </div>
                    </>
                  )}
                </div>
              </div>
            </div>

            {/* Action Button */}
            <button
              onClick={handleGenerateReport}
              disabled={!selectedProcessedFile || status === 'processing'}
              className={`
                w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-2 shadow-md transition-all
                ${!selectedProcessedFile || status === 'processing'
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  : 'bg-indigo-600 hover:bg-indigo-700 text-white hover:shadow-lg hover:-translate-y-0.5'
                }
              `}
            >
              {status === 'processing' ? (
                <>
                  <Loader2 className="w-6 h-6 animate-spin" />
                  Processando...
                </>
              ) : (
                <>
                  <Play className="w-6 h-6 fill-current" />
                  Gerar Report Completo
                </>
              )}
            </button>

            {/* Status Message (Erro) */}
            {status === 'error' && (
              <div className="p-4 rounded-lg bg-red-50 text-red-800 border border-red-100 flex items-center gap-3 animate-fade-in">
                <AlertCircle className="w-5 h-5 flex-shrink-0" />
                <span className="text-sm font-medium">{message}</span>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default ManagementReport;

export interface Employee {
  id: string;
  name: string;
  active: boolean;
}

export enum TaskCategory {
  UNLOAD = 'Descarregar',
  TURN = 'Virar Pacote',
  FISHING = 'Pescar Rota',
  BAGGING = 'Ensacar'
}

export interface TaskDefinition {
  id: string;
  name: string;
  description: string; // The specific routes or details
  category: TaskCategory;
  capacity: number; // How many people needed
}

export interface Assignment {
  taskId: string;
  employeeId: string;
  slotIndex: number; // For tasks with multiple people, which slot (0, 1, etc)
}

export interface TripInfo {
  id: string; // 15 chars alphanumeric
  volume?: number; // Volumetria específica da viagem
  unsealed: boolean; // deslacrada
  unsealTimestamp?: string; // Data e hora do deslacre (Formatado para exibição)
  unsealTimeISO?: string; // Data ISO para cálculos de timer
}

export interface DailyRecord {
  id: string; // YYYY-MM-DD
  date: string;
  volume: number;
  trucks: number;
  assignments: Assignment[];
  trips?: TripInfo[];
}

export interface AIRecommendation {
  rationale: string;
  assignments: { taskId: string; slotIndex: number; employeeName: string }[];
}

export interface SupplyItem {
  id: string;
  name: string;
  quantity: number;
  unit: string; // ex: 'un', 'cx', 'rolo'
  minStock: number;
}

export interface SupplyTransaction {
  id: string;
  supplyId: string;
  supplyName: string;
  type: 'IN' | 'OUT';
  quantity: number;
  date: string; // ISO String
  user: string; // Quem retirou ou quem adicionou
}

export interface EpiItem {
  id: string;
  name: string;
  caNumber: string; // Certificado de Aprovação
  quantity: number;
  minStock: number;
  validityDays?: number; // Validade média em dias para troca
}

export interface EpiTransaction {
  id: string;
  epiId: string;
  epiName: string;
  type: 'IN' | 'OUT'; // IN = Compra/Estoque, OUT = Entrega funcionário
  quantity: number;
  date: string;
  employeeId?: string; // ID do funcionário que recebeu
  employeeName: string; // Nome do funcionário ou 'Estoque Inicial'
  notes?: string;
}

import React, { useState, useEffect } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Sparkles, Loader2, Calendar, Unlock, Lock, Container, Plus, Trash2, Clock, AlertTriangle, X, BarChart3 } from 'lucide-react';
import { generateScheduleSuggestion } from '../services/geminiService';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [assignments, setAssignments] = useState<Assignment[]>([]);

  // State for Trips (Dynamic)
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [notifications, setNotifications] = useState<string[]>([]);

  const [loadingAI, setLoadingAI] = useState(false);
  const [aiRationale, setAiRationale] = useState<string | null>(null);

  // Load existing data if editing a past date
  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setAssignments([]);
      setTrips([]);
    }
    setAiRationale(null);
  }, [date, history]);

  // Timer Logic: Check every minute
  useEffect(() => {
    const checkTimers = () => {
      const now = new Date();
      const newNotifications: string[] = [];

      trips.forEach(trip => {
        if (trip.unsealed && trip.unsealTimeISO) {
          const unsealTime = new Date(trip.unsealTimeISO);
          const diffMs = now.getTime() - unsealTime.getTime();
          const diffMinutes = diffMs / (1000 * 60);

          // 6 hours = 360 minutes
          // Warning Window: Between 5h30m (330m) and 6h (360m)
          if (diffMinutes >= 330 && diffMinutes < 360) {
            const minutesLeft = 360 - Math.floor(diffMinutes);
            newNotifications.push(`⚠️ Atenção: Viagem ${trip.id} vence o prazo de "Expedido mas não chegou" em ${minutesLeft} min.`);
          }
        }
      });

      // Update notifications if changed
      if (JSON.stringify(newNotifications) !== JSON.stringify(notifications)) {
        setNotifications(newNotifications);
      }
    };

    const timer = setInterval(checkTimers, 60000); // Check every minute
    checkTimers(); // Check immediately on mount/update

    return () => clearInterval(timer);
  }, [trips]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      // Remove any existing assignment for this slot
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      // If employee is assigned elsewhere, remove them from there (optional, but good UX)
      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);

      return [...withoutEmployee, { taskId, employeeId, slotIndex }];
    });
  };

  const handleAddTrip = () => {
    if (trips.length < 5) {
      setTrips(prev => [...prev, { id: '', unsealed: false }]);
    }
  };

  const handleRemoveTrip = (index: number) => {
    setTrips(prev => prev.filter((_, i) => i !== index));
  };

  const handleTripChange = (index: number, value: string) => {
    // Uppercase and limit to 15 chars
    const formattedValue = value.toUpperCase().slice(0, 15);

    setTrips(prev => {
      const newTrips = [...prev];
      newTrips[index] = { ...newTrips[index], id: formattedValue };
      return newTrips;
    });
  };

  const handleTripVolumeChange = (index: number, value: string) => {
    const numValue = value === '' ? undefined : Number(value);
    setTrips(prev => {
      const newTrips = [...prev];
      newTrips[index] = { ...newTrips[index], volume: numValue };
      return newTrips;
    });
  };

  const toggleTripUnsealed = (index: number) => {
    // 1. Calcular o novo estado das viagens
    const newTrips = [...trips];
    const currentTrip = newTrips[index];
    const isNowUnsealed = !currentTrip.unsealed;

    const now = new Date();

    // Se tornou deslacrada, adiciona timestamp. Se lacrou novamente, remove.
    const timestampDisplay = isNowUnsealed 
      ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })
      : undefined;

    const timestampISO = isNowUnsealed
      ? now.toISOString()
      : undefined;

    newTrips[index] = { 
      ...currentTrip, 
      unsealed: isNowUnsealed,
      unsealTimestamp: timestampDisplay,
      unsealTimeISO: timestampISO
    };

    // 2. Atualizar o estado visual local
    setTrips(newTrips);

    // 3. Salvar IMEDIATAMENTE no banco de dados para sincronizar com os relatórios
    const record: DailyRecord = {
      id: date,
      date,
      volume: Number(volume) || 0,
      trucks: Number(trucks) || 0,
      assignments,
      trips: newTrips
    };
    onSaveRecord(record);
  };

  const handleSave = () => {
    // Filtra viagens com ID vazio para não sujar o banco de dados
    const cleanTrips = trips.filter(t => t.id.trim() !== '');

    const record: DailyRecord = {
      id: date,
      date,
      volume: Number(volume) || 0,
      trucks: Number(trucks) || 0,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);

    // Atualiza o estado local caso alguma viagem vazia tenha sido removida
    setTrips(cleanTrips);

    alert("Dados salvos com sucesso!");
  };

  const handleSmartSchedule = async () => {
    setLoadingAI(true);
    try {
      const suggestion = await generateScheduleSuggestion(employees, history, date);
      setAiRationale(suggestion.rationale);

      const newAssignments: Assignment[] = [];

      suggestion.assignments.forEach((sug: any) => {
        const emp = employees.find(e => e.name.toLowerCase() === sug.employeeName.toLowerCase());
        const task = TASK_DEFINITIONS.find(t => t.id === sug.taskId);

        if (emp && task) {
          newAssignments.push({
            taskId: task.id,
            slotIndex: sug.slotIndex,
            employeeId: emp.id
          });
        }
      });

      setAssignments(newAssignments);
    } catch (e) {
      alert("Erro ao gerar sugestão. Verifique a API Key.");
    } finally {
      setLoadingAI(false);
    }
  };

  const getElapsedTime = (isoString?: string) => {
    if (!isoString) return null;
    const diff = new Date().getTime() - new Date(isoString).getTime();
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
    return `${hours}h ${minutes}m`;
  };

  const assignedCount = assignments.length;

  return (
    <div className="space-y-6 relative">

      {/* Notifications Area */}
      {notifications.length > 0 && (
        <div className="fixed top-20 right-4 z-50 w-full max-w-sm space-y-2 animate-fade-in">
          {notifications.map((note, idx) => (
            <div key={idx} className="bg-amber-100 border-l-4 border-amber-500 text-amber-900 p-4 rounded shadow-lg flex items-start gap-3">
              <AlertTriangle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-bold text-sm">Prazo de Expedição</p>
                <p className="text-sm">{note}</p>
              </div>
              <button 
                onClick={() => setNotifications(prev => prev.filter((_, i) => i !== idx))}
                className="ml-auto text-amber-500 hover:text-amber-700"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Header Controls */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 justify-between items-end">
        <div className="flex gap-4 items-end w-full md:w-auto">
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Data</label>
            <div className="relative">
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none w-full"
              />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Volumetria Total</label>
            <input
              type="number"
              placeholder="Ex: 5000"
              value={volume}
              onChange={(e) => setVolume(Number(e.target.value))}
              className="px-3 py-2 bg-white border border-slate-300 rounded-lg text-sm w-full md:w-32 focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Carretas</label>
            <input
              type="number"
              placeholder="Ex: 2"
              value={trucks}
              onChange={(e) => setTrucks(Number(e.target.value))}
              className="px-3 py-2 bg-white border border-slate-300 rounded-lg text-sm w-full md:w-24 focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
        </div>

        <div className="flex gap-3 w-full md:w-auto">
           <button
            onClick={handleSmartSchedule}
            disabled={loadingAI}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loadingAI ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
            IA Escala
          </button>

          <button
            onClick={handleSave}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors"
          >
            <Save className="w-4 h-4" />
            Salvar
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Metrics & Trips */}
        <div className="space-y-6 lg:col-span-1">
          {/* Progress Bar */}
          <div className="bg-white px-4 py-3 rounded-xl border border-slate-200 shadow-sm flex flex-col gap-2">
            <span className="text-sm font-medium text-slate-700">
              Alocação da Equipe: {assignedCount} / {employees.length}
            </span>
            <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-500 ${assignedCount === employees.length ? 'bg-green-500' : 'bg-blue-500'}`}
                style={{ width: `${Math.min((assignedCount / employees.length) * 100, 100)}%` }}
              />
            </div>
          </div>

          {/* Trip Registration */}
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Container className="w-4 h-4 text-slate-500" />
                <h3 className="text-sm font-semibold text-slate-700">Registro de Viagens</h3>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{trips.length}/5</span>
              </div>
            </div>

            <div className="p-4 space-y-3">
              {trips.length > 0 ? (
                trips.map((trip, idx) => {
                  const elapsedTime = trip.unsealed ? getElapsedTime(trip.unsealTimeISO) : null;
                  // Check if nearing 6 hours (5h30m = 330 min)
                  const isWarning = trip.unsealTimeISO && (new Date().getTime() - new Date(trip.unsealTimeISO).getTime()) > (330 * 60 * 1000);

                  return (
                    <div key={idx} className={`animate-fade-in flex flex-col gap-2 p-3 rounded-lg border ${isWarning ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-100'}`}>
                       <div className="flex items-start gap-2">
                         <div className="flex-1 flex flex-col gap-2">
                            {/* Linha 1: ID e Volume */}
                            <div className="flex gap-2">
                               <div className="flex-grow">
                                  <input
                                    type="text"
                                    maxLength={15}
                                    placeholder="ID Viagem"
                                    value={trip.id}
                                    onChange={(e) => handleTripChange(idx, e.target.value)}
                                    className="w-full px-3 py-2 bg-white border border-slate-300 rounded text-sm font-mono uppercase focus:ring-2 focus:ring-blue-500 outline-none placeholder:normal-case placeholder:font-sans"
                                  />
                               </div>
                               <div className="w-24 relative">
                                  <input
                                    type="number"
                                    placeholder="Vol."
                                    value={trip.volume || ''}
                                    onChange={(e) => handleTripVolumeChange(idx, e.target.value)}
                                    className="w-full pl-3 pr-7 py-2 bg-white border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                  />
                                  <BarChart3 className="w-3 h-3 text-slate-400 absolute right-2 top-2.5" />
                               </div>
                            </div>

                            {/* Linha 2: Timestamps */}
                            {trip.unsealed && trip.unsealTimestamp && (
                              <div className="flex justify-between items-center mt-1">
                                <span className="text-[10px] text-slate-500 font-medium px-1 flex items-center gap-1">
                                  <Clock className="w-3 h-3" /> {trip.unsealTimestamp}
                                </span>
                                {elapsedTime && (
                                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${isWarning ? 'bg-amber-200 text-amber-800' : 'bg-slate-100 text-slate-600'}`}>
                                    {elapsedTime}
                                  </span>
                                )}
                              </div>
                            )}
                         </div>

                        <div className="flex flex-col gap-1">
                          <button 
                            onClick={() => toggleTripUnsealed(idx)}
                            className={`flex items-center justify-center w-10 h-[38px] rounded border transition-all duration-200 ${
                              trip.unsealed 
                                ? 'bg-green-100 border-green-300 text-green-600 shadow-inner' 
                                : 'bg-red-100 border-red-300 text-red-600 hover:bg-red-200'
                            }`}
                            title={trip.unsealed ? "Deslacrada" : "Lacrada"}
                          >
                            {trip.unsealed ? <Unlock className="w-5 h-5" /> : <Lock className="w-5 h-5" />}
                          </button>

                          <button
                            onClick={() => handleRemoveTrip(idx)}
                            className="flex items-center justify-center w-10 h-[30px] text-slate-400 hover:text-red-500 hover:bg-red-50 rounded transition-colors"
                            title="Remover Viagem"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })
              ) : (
                <div className="text-center py-4 text-sm text-slate-400 border border-dashed border-slate-200 rounded-lg">
                  Nenhuma viagem registrada hoje
                </div>
              )}

              {trips.length < 5 && (
                <button
                  onClick={handleAddTrip}
                  className="w-full py-2 border border-dashed border-indigo-300 text-indigo-600 rounded-lg text-sm font-medium hover:bg-indigo-50 hover:border-indigo-400 transition-all flex items-center justify-center gap-2"
                >
                  <Plus className="w-4 h-4" />
                  Adicionar Nova Viagem
                </button>
              )}
            </div>
          </div>

          {aiRationale && (
            <div className="bg-purple-50 border border-purple-200 p-4 rounded-xl text-sm text-purple-800 animate-fade-in">
              <strong>Sugestão da IA:</strong> {aiRationale}
            </div>
          )}
        </div>

        {/* Right Column: Assignments Grid */}
        <div className="lg:col-span-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {TASK_DEFINITIONS.map(task => (
              <AssignmentCard
                key={task.id}
                task={task}
                assignments={assignments}
                employees={employees}
                onAssign={handleAssign}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DailyOperations;

import React, { useState, useMemo } from 'react';
import { DailyRecord, Employee, TaskCategory } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line } from 'recharts';
import { Calendar, Filter, Table2, User, Container, Lock, Unlock } from 'lucide-react';

interface Props {
  history: DailyRecord[];
  employees: Employee[];
}

const Reports: React.FC<Props> = ({ history, employees }) => {
  // Configurar datas iniciais (Início do mês atual até hoje)
  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);
  const [selectedEmployeeId, setSelectedEmployeeId] = useState<string>('all');

  // Filtrar o histórico baseado no intervalo selecionado
  const filteredHistory = useMemo(() => {
    return history.filter(rec => {
      return rec.date >= startDate && rec.date <= endDate;
    });
  }, [history, startDate, endDate]);

  // Lista de funcionários a serem exibidos (Todos ou Específico)
  const targetEmployees = useMemo(() => {
    if (selectedEmployeeId === 'all') {
      return employees;
    }
    return employees.filter(e => e.id === selectedEmployeeId);
  }, [employees, selectedEmployeeId]);

  // 1. Prepare data for Volume/Trucks over time using filtered history
  const operationalData = useMemo(() => {
    return filteredHistory
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(rec => {
        // Fix timezone issue for chart labels using string split
        const [year, month, day] = rec.date.split('-');
        return {
          date: `${day}/${month}`,
          volume: rec.volume,
          trucks: rec.trucks
        };
      });
  }, [filteredHistory]);

  // 2. Prepare Heatmap data (Employee vs Task Category count)
  const categoryStats = useMemo(() => {
    return targetEmployees.map(emp => {
      const stats: any = { name: emp.name };

      // Initialize counts
      Object.values(TaskCategory).forEach(cat => stats[cat] = 0);

      filteredHistory.forEach(day => {
        const assignment = day.assignments.find(a => a.employeeId === emp.id);
        if (assignment) {
          const taskDef = TASK_DEFINITIONS.find(t => t.id === assignment.taskId);
          if (taskDef) {
            stats[taskDef.category] = (stats[taskDef.category] || 0) + 1;
          }
        }
      });
      return stats;
    });
  }, [targetEmployees, filteredHistory]);

  // 3. Prepare Specific Task Detail data (Employee vs Specific Task ID)
  const specificTaskStats = useMemo(() => {
    return targetEmployees.map(emp => {
      // Create an object with employee name and all task IDs initialized to 0
      const stats: Record<string, any> = { id: emp.id, name: emp.name };
      TASK_DEFINITIONS.forEach(task => stats[task.id] = 0);

      filteredHistory.forEach(day => {
        const assignment = day.assignments.find(a => a.employeeId === emp.id);
        if (assignment) {
          stats[assignment.taskId] = (stats[assignment.taskId] || 0) + 1;
        }
      });
      return stats;
    });
  }, [targetEmployees, filteredHistory]);

  // 4. Prepare Trips Report Data
  const tripsData = useMemo(() => {
    const allTrips: { date: string; id: string; volume?: number; unsealed: boolean; timestamp?: string }[] = [];

    // Sort history specifically for the table (Newest first)
    const sortedHistory = [...filteredHistory].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    sortedHistory.forEach(day => {
      if (day.trips && day.trips.length > 0) {
        day.trips.forEach(trip => {
          allTrips.push({
            date: day.date,
            id: trip.id,
            volume: trip.volume,
            unsealed: !!trip.unsealed, // Force boolean conversion
            timestamp: trip.unsealTimestamp
          });
        });
      }
    });
    return allTrips;
  }, [filteredHistory]);

  // Helper para formatar data evitando problemas de timezone (UTC vs Local)
  const formatDate = (dateString: string) => {
    if (!dateString) return '-';
    const parts = dateString.split('-');
    if (parts.length === 3) {
      const [year, month, day] = parts;
      return `${day}/${month}/${year}`;
    }
    return dateString;
  };

  return (
    <div className="space-y-8">
      {/* Filtros */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col lg:flex-row items-end gap-4 sticky top-20 z-10">
        <div className="flex items-center gap-2 text-indigo-600 mb-2 lg:mb-1 mr-4 min-w-fit">
          <Filter className="w-5 h-5" />
          <span className="font-semibold">Filtros</span>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
          {/* Data Inicial */}
          <div>
            <label className="block text-xs font-medium text-slate-500 mb-1">Data Inicial</label>
            <div className="relative">
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full"
              />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>

          {/* Data Final */}
          <div>
            <label className="block text-xs font-medium text-slate-500 mb-1">Data Final</label>
            <div className="relative">
              <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full"
              />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>

          {/* Filtro Colaborador */}
          <div>
            <label className="block text-xs font-medium text-slate-500 mb-1">Colaborador</label>
            <div className="relative">
              <select
                value={selectedEmployeeId}
                onChange={(e) => setSelectedEmployeeId(e.target.value)}
                className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full appearance-none"
              >
                <option value="all">Todos os Colaboradores</option>
                {employees.filter(e => e.active).map(emp => (
                  <option key={emp.id} value={emp.id}>{emp.name}</option>
                ))}
              </select>
              <User className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
