          ) : (
             <div className="h-[300px] flex items-center justify-center text-slate-400 italic">
              Sem dados para exibir
            </div>
          )}
        </div>
      </div>

      {/* Tabela de Relatório de Viagens e Lacres (MOVIDA PARA CIMA) */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
           <div className="flex items-center gap-2">
             <Container className="w-5 h-5 text-indigo-600" />
             <h3 className="font-semibold text-slate-800">Relatório de Viagens e Lacres</h3>
           </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-100 text-slate-600 font-semibold border-b border-slate-200">
              <tr>
                <th className="px-6 py-3 w-40">Data</th>
                <th className="px-6 py-3">ID Viagem</th>
                <th className="px-6 py-3 text-right">Volume</th>
                <th className="px-6 py-3">Status</th>
                <th className="px-6 py-3 text-right">Horário Deslacre</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {tripsData.map((trip, idx) => (
                <tr key={`${trip.id}-${idx}`} className="hover:bg-slate-50">
                  <td className="px-6 py-3 font-medium text-slate-700">
                    {formatDate(trip.date)}
                  </td>
                  <td className="px-6 py-3 font-mono text-slate-600">
                    {trip.id}
                  </td>
                  <td className="px-6 py-3 font-mono text-slate-600 text-right font-bold">
                    {trip.volume ? trip.volume.toLocaleString('pt-BR') : '-'}
                  </td>
                  <td className="px-6 py-3">
                    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border ${
                      trip.unsealed 
                        ? 'bg-green-50 text-green-700 border-green-200' 
                        : 'bg-red-50 text-red-700 border-red-200'
                    }`}>
                      {trip.unsealed ? <Unlock className="w-3 h-3" /> : <Lock className="w-3 h-3" />}
                      {trip.unsealed ? 'Deslacrada' : 'Lacrada'}
                    </span>
                  </td>
                  <td className="px-6 py-3 text-right text-slate-500 font-mono">
                    {trip.timestamp ? trip.timestamp : '-'}
                  </td>
                </tr>
              ))}
              {tripsData.length === 0 && (
                <tr>
                   <td colSpan={5} className="p-8 text-center text-slate-400 italic">
                     Nenhuma viagem registrada no período selecionado.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Tabela Detalhada por TAREFA ESPECÍFICA */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
           <div className="flex items-center gap-2">
             <Table2 className="w-5 h-5 text-indigo-600" />
             <h3 className="font-semibold text-slate-800">Detalhamento por Posto Específico (Rotas)</h3>
           </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left border-collapse">
            <thead className="bg-slate-100 text-slate-600 font-semibold border-b border-slate-200">
              <tr>
                <th className="px-4 py-3 sticky left-0 bg-slate-100 z-10 border-r border-slate-200 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">Colaborador</th>
                {TASK_DEFINITIONS.map(task => (
                  <th key={task.id} className="px-3 py-3 whitespace-nowrap min-w-[120px]" title={task.description}>
                    <div className="flex flex-col">
                      <span>{task.name}</span>
                      <span className="text-[10px] text-slate-400 font-normal">{task.category}</span>
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {specificTaskStats.map((stat: any, index) => (
                <tr key={stat.id} className={index % 2 === 0 ? 'bg-white hover:bg-slate-50' : 'bg-slate-50/50 hover:bg-slate-50'}>
                  <td className="px-4 py-3 font-medium text-slate-700 sticky left-0 bg-inherit border-r border-slate-200 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                    {stat.name}
                  </td>
                  {TASK_DEFINITIONS.map(task => {
                    const count = stat[task.id];
                    return (
                      <td key={task.id} className="px-3 py-3 text-center border-r border-slate-50 last:border-0">
                        {count > 0 ? (
                          <span className="inline-flex items-center justify-center w-8 h-6 rounded bg-indigo-50 text-indigo-700 font-medium">
                            {count}
                          </span>
                        ) : (
                          <span className="text-slate-300">-</span>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))}
              {specificTaskStats.length === 0 && (
                <tr>
                   <td colSpan={TASK_DEFINITIONS.length + 1} className="p-4 text-center text-slate-400 italic">
                     Nenhum colaborador encontrado com os filtros atuais.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Tabela Resumo Categorias */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden opacity-80">
        <div className="p-3 border-b border-slate-100 bg-slate-50">
           <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Resumo Geral por Categoria</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 font-medium">
              <tr>
                <th className="px-4 py-3">Colaborador</th>
                {Object.values(TaskCategory).map(cat => (
                  <th key={cat} className="px-4 py-3">{cat}</th>
                ))}
                <th className="px-4 py-3">Total Dias</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {categoryStats.map((stat: any) => {
                const total = 
                  (stat[TaskCategory.UNLOAD] || 0) + 
                  (stat[TaskCategory.FISHING] || 0) + 
                  (stat[TaskCategory.TURN] || 0) + 
                  (stat[TaskCategory.BAGGING] || 0);

                return (
                  <tr key={stat.name} className="hover:bg-slate-50">
                    <td className="px-4 py-3 font-medium text-slate-700">{stat.name}</td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.UNLOAD] > 0 ? stat[TaskCategory.UNLOAD] : '-'}
                    </td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.FISHING] > 0 ? stat[TaskCategory.FISHING] : '-'}
                    </td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.TURN] > 0 ? stat[TaskCategory.TURN] : '-'}
                    </td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.BAGGING] > 0 ? stat[TaskCategory.BAGGING] : '-'}
                    </td>
                    <td className="px-4 py-3 font-semibold text-slate-800">{total}</td>
                  </tr>
                );
              })}
              {categoryStats.length === 0 && (
                <tr>
                   <td colSpan={6} className="p-4 text-center text-slate-400 italic">
                     Nenhum dado encontrado.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useMemo } from 'react';
import { DailyRecord, Employee, TaskCategory } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line } from 'recharts';
import { Calendar, Filter, Table2, User, Container, Lock, Unlock } from 'lucide-react';

interface Props {
  history: DailyRecord[];
  employees: Employee[];
}

const Reports: React.FC<Props> = ({ history, employees }) => {
  // Configurar datas iniciais
  // Padrão solicitado: Data Inicial = Hoje - 1 dia, Data Final = Hoje + 2 dias
  const now = new Date();

  const yesterday = new Date(now);
  yesterday.setDate(now.getDate() - 1);
  const defaultStart = yesterday.toISOString().split('T')[0];

  const twoDaysAfter = new Date(now);
  twoDaysAfter.setDate(now.getDate() + 2);
  const defaultEnd = twoDaysAfter.toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(defaultStart);
  const [endDate, setEndDate] = useState<string>(defaultEnd);
  const [selectedEmployeeId, setSelectedEmployeeId] = useState<string>('all');

  // Filtrar o histórico baseado no intervalo selecionado
  const filteredHistory = useMemo(() => {
    return history.filter(rec => {
      return rec.date >= startDate && rec.date <= endDate;
    });
  }, [history, startDate, endDate]);

  // Lista de funcionários a serem exibidos (Todos ou Específico)
  const targetEmployees = useMemo(() => {
    if (selectedEmployeeId === 'all') {
      return employees;
    }
    return employees.filter(e => e.id === selectedEmployeeId);
  }, [employees, selectedEmployeeId]);

  // 1. Prepare data for Volume/Trucks over time using filtered history
  const operationalData = useMemo(() => {
    return filteredHistory
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(rec => {
        // Fix timezone issue for chart labels using string split
        const [year, month, day] = rec.date.split('-');
        return {
          date: `${day}/${month}`,
          volume: rec.volume,
          trucks: rec.trucks
        };
      });
  }, [filteredHistory]);

  // 2. Prepare Heatmap data (Employee vs Task Category count)
  const categoryStats = useMemo(() => {
    return targetEmployees.map(emp => {
      const stats: any = { name: emp.name };

      // Initialize counts
      Object.values(TaskCategory).forEach(cat => stats[cat] = 0);

      filteredHistory.forEach(day => {
        const assignment = day.assignments.find(a => a.employeeId === emp.id);
        if (assignment) {
          const taskDef = TASK_DEFINITIONS.find(t => t.id === assignment.taskId);
          if (taskDef) {
            stats[taskDef.category] = (stats[taskDef.category] || 0) + 1;
          }
        }
      });
      return stats;
    });
  }, [targetEmployees, filteredHistory]);

  // 3. Prepare Specific Task Detail data (Employee vs Specific Task ID)
  const specificTaskStats = useMemo(() => {
    return targetEmployees.map(emp => {
      // Create an object with employee name and all task IDs initialized to 0
      const stats: Record<string, any> = { id: emp.id, name: emp.name };
      TASK_DEFINITIONS.forEach(task => stats[task.id] = 0);

      filteredHistory.forEach(day => {
        const assignment = day.assignments.find(a => a.employeeId === emp.id);
        if (assignment) {
          stats[assignment.taskId] = (stats[assignment.taskId] || 0) + 1;
        }
      });
      return stats;
    });
  }, [targetEmployees, filteredHistory]);

  // 4. Prepare Trips Report Data
  const tripsData = useMemo(() => {
    const allTrips: { date: string; id: string; volume?: number; unsealed: boolean; timestamp?: string }[] = [];

    // Sort history specifically for the table (Newest first)
    const sortedHistory = [...filteredHistory].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    sortedHistory.forEach(day => {
      if (day.trips && day.trips.length > 0) {
        day.trips.forEach(trip => {
          allTrips.push({
            date: day.date,
            id: trip.id,
            volume: trip.volume,
            unsealed: !!trip.unsealed, // Force boolean conversion
            timestamp: trip.unsealTimestamp
          });
        });
      }
    });
    return allTrips;
  }, [filteredHistory]);

  // Helper para formatar data evitando problemas de timezone (UTC vs Local)
  const formatDate = (dateString: string) => {
    if (!dateString) return '-';
    const parts = dateString.split('-');
    if (parts.length === 3) {
      const [year, month, day] = parts;
      return `${day}/${month}/${year}`;
    }
    return dateString;
  };

  return (
    <div className="space-y-8">
      {/* Filtros */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col lg:flex-row items-end gap-4 sticky top-20 z-10">
        <div className="flex items-center gap-2 text-indigo-600 mb-2 lg:mb-1 mr-4 min-w-fit">
          <Filter className="w-5 h-5" />
          <span className="font-semibold">Filtros</span>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
          {/* Data Inicial */}
          <div>
            <label className="block text-xs font-medium text-slate-500 mb-1">Data Inicial</label>
            <div className="relative">
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full"
              />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>

          {/* Data Final */}
          <div>
            <label className="block text-xs font-medium text-slate-500 mb-1">Data Final</label>
            <div className="relative">
              <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full"
              />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>

          {/* Filtro Colaborador */}
          <div>
            <label className="block text-xs font-medium text-slate-500 mb-1">Colaborador</label>
            <div className="relative">
              <select
                value={selectedEmployeeId}
                onChange={(e) => setSelectedEmployeeId(e.target.value)}
                className="pl-9 pr-3 py-2 bg-slate-50 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full appearance-none"
              >
                <option value="all">Todos os Colaboradores</option>
                {employees.filter(e => e.active).map(emp => (
                  <option key={emp.id} value={emp.id}>{emp.name}</option>
                ))}
              </select>
              <User className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Gráfico de Volume */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <div className="flex justify-between items-start mb-6">
             <h3 className="text-lg font-bold text-slate-800">Volume & Carretas</h3>
             <span className="text-xs text-slate-400 font-light px-2 py-1 bg-slate-100 rounded">Dados Gerais da Operação</span>
          </div>
          {operationalData.length > 0 ? (
            <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={operationalData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                  <XAxis dataKey="date" stroke="#64748b" tick={{fontSize: 12}} />
                  <YAxis yAxisId="left" stroke="#3b82f6" label={{ value: 'Volume', angle: -90, position: 'insideLeft', fill: '#3b82f6' }} />
                  <YAxis yAxisId="right" orientation="right" stroke="#ef4444" label={{ value: 'Carretas', angle: 90, position: 'insideRight', fill: '#ef4444' }} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                  <Legend />
                  <Line yAxisId="left" type="monotone" dataKey="volume" stroke="#3b82f6" strokeWidth={2} name="Volume" dot={{r: 4}} />
                  <Line yAxisId="right" type="monotone" dataKey="trucks" stroke="#ef4444" strokeWidth={2} name="Carretas" dot={{r: 4}} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-[300px] flex items-center justify-center text-slate-400 italic">
              Sem dados no período selecionado
            </div>
          )}
        </div>

        {/* Gráfico de Distribuição */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">
            Distribuição por Categoria
            {selectedEmployeeId !== 'all' && <span className="text-indigo-600 ml-2 text-sm font-normal">(Filtrado)</span>}
          </h3>
          {filteredHistory.length > 0 && categoryStats.length > 0 ? (
            <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={categoryStats} layout="vertical" margin={{ left: 40 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e2e8f0" />
                  <XAxis type="number" stroke="#64748b" />
                  <YAxis dataKey="name" type="category" width={100} stroke="#334155" tick={{fontSize: 11}} interval={0} />
                  <Tooltip cursor={{fill: '#f1f5f9'}} />
                  <Legend wrapperStyle={{fontSize: '11px'}} />
                  <Bar dataKey={TaskCategory.UNLOAD} stackId="a" fill="#ef4444" name="Descarregar" radius={[0, 4, 4, 0]} />
                  <Bar dataKey={TaskCategory.FISHING} stackId="a" fill="#3b82f6" name="Pesca (Rota)" />
                  <Bar dataKey={TaskCategory.TURN} stackId="a" fill="#f97316" name="Virar" />
                  <Bar dataKey={TaskCategory.BAGGING} stackId="a" fill="#22c55e" name="Ensacar" />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
             <div className="h-[300px] flex items-center justify-center text-slate-400 italic">
              Sem dados para exibir
            </div>
          )}
        </div>
      </div>

      {/* Tabela de Relatório de Viagens e Lacres (MOVIDA PARA CIMA) */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
           <div className="flex items-center gap-2">
             <Container className="w-5 h-5 text-indigo-600" />
             <h3 className="font-semibold text-slate-800">Relatório de Viagens e Lacres</h3>
           </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-100 text-slate-600 font-semibold border-b border-slate-200">
              <tr>
                <th className="px-6 py-3 w-40">Data</th>
                <th className="px-6 py-3">ID Viagem</th>
                <th className="px-6 py-3 text-right">Volume</th>
                <th className="px-6 py-3">Status</th>
                <th className="px-6 py-3 text-right">Horário Deslacre</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {tripsData.map((trip, idx) => (
                <tr key={`${trip.id}-${idx}`} className="hover:bg-slate-50">
                  <td className="px-6 py-3 font-medium text-slate-700">
                    {formatDate(trip.date)}
                  </td>
                  <td className="px-6 py-3 font-mono text-slate-600">
                    {trip.id}
                  </td>
                  <td className="px-6 py-3 font-mono text-slate-600 text-right font-bold">
                    {trip.volume ? trip.volume.toLocaleString('pt-BR') : '-'}
                  </td>
                  <td className="px-6 py-3">
                    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border ${
                      trip.unsealed 
                        ? 'bg-green-50 text-green-700 border-green-200' 
                        : 'bg-red-50 text-red-700 border-red-200'
                    }`}>
                      {trip.unsealed ? <Unlock className="w-3 h-3" /> : <Lock className="w-3 h-3" />}
                      {trip.unsealed ? 'Deslacrada' : 'Lacrada'}
                    </span>
                  </td>
                  <td className="px-6 py-3 text-right text-slate-500 font-mono">
                    {trip.timestamp ? trip.timestamp : '-'}
                  </td>
                </tr>
              ))}
              {tripsData.length === 0 && (
                <tr>
                   <td colSpan={5} className="p-8 text-center text-slate-400 italic">
                     Nenhuma viagem registrada no período selecionado.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Tabela Detalhada por TAREFA ESPECÍFICA */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
           <div className="flex items-center gap-2">
             <Table2 className="w-5 h-5 text-indigo-600" />
             <h3 className="font-semibold text-slate-800">Detalhamento por Posto Específico (Rotas)</h3>
           </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left border-collapse">
            <thead className="bg-slate-100 text-slate-600 font-semibold border-b border-slate-200">
              <tr>
                <th className="px-4 py-3 sticky left-0 bg-slate-100 z-10 border-r border-slate-200 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">Colaborador</th>
                {TASK_DEFINITIONS.map(task => (
                  <th key={task.id} className="px-3 py-3 whitespace-nowrap min-w-[120px]" title={task.description}>
                    <div className="flex flex-col">
                      <span>{task.name}</span>
                      <span className="text-[10px] text-slate-400 font-normal">{task.category}</span>
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {specificTaskStats.map((stat: any, index) => (
                <tr key={stat.id} className={index % 2 === 0 ? 'bg-white hover:bg-slate-50' : 'bg-slate-50/50 hover:bg-slate-50'}>
                  <td className="px-4 py-3 font-medium text-slate-700 sticky left-0 bg-inherit border-r border-slate-200 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.05)]">
                    {stat.name}
                  </td>
                  {TASK_DEFINITIONS.map(task => {
                    const count = stat[task.id];
                    return (
                      <td key={task.id} className="px-3 py-3 text-center border-r border-slate-50 last:border-0">
                        {count > 0 ? (
                          <span className="inline-flex items-center justify-center w-8 h-6 rounded bg-indigo-50 text-indigo-700 font-medium">
                            {count}
                          </span>
                        ) : (
                          <span className="text-slate-300">-</span>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))}
              {specificTaskStats.length === 0 && (
                <tr>
                   <td colSpan={TASK_DEFINITIONS.length + 1} className="p-4 text-center text-slate-400 italic">
                     Nenhum colaborador encontrado com os filtros atuais.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Tabela Resumo Categorias */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden opacity-80">
        <div className="p-3 border-b border-slate-100 bg-slate-50">
           <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Resumo Geral por Categoria</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 font-medium">
              <tr>
                <th className="px-4 py-3">Colaborador</th>
                {Object.values(TaskCategory).map(cat => (
                  <th key={cat} className="px-4 py-3">{cat}</th>
                ))}
                <th className="px-4 py-3">Total Dias</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {categoryStats.map((stat: any) => {
                const total = 
                  (stat[TaskCategory.UNLOAD] || 0) + 
                  (stat[TaskCategory.FISHING] || 0) + 
                  (stat[TaskCategory.TURN] || 0) + 
                  (stat[TaskCategory.BAGGING] || 0);

                return (
                  <tr key={stat.name} className="hover:bg-slate-50">
                    <td className="px-4 py-3 font-medium text-slate-700">{stat.name}</td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.UNLOAD] > 0 ? stat[TaskCategory.UNLOAD] : '-'}
                    </td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.FISHING] > 0 ? stat[TaskCategory.FISHING] : '-'}
                    </td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.TURN] > 0 ? stat[TaskCategory.TURN] : '-'}
                    </td>
                    <td className="px-4 py-3 text-slate-600">
                      {stat[TaskCategory.BAGGING] > 0 ? stat[TaskCategory.BAGGING] : '-'}
                    </td>
                    <td className="px-4 py-3 font-semibold text-slate-800">{total}</td>
                  </tr>
                );
              })}
              {categoryStats.length === 0 && (
                <tr>
                   <td colSpan={6} className="p-4 text-center text-slate-400 italic">
                     Nenhum dado encontrado.
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Sparkles, Loader2, Calendar, Unlock, Lock, Container, Plus, Trash2, Clock, AlertTriangle, X, BarChart3, Calculator } from 'lucide-react';
import { generateScheduleSuggestion } from '../services/geminiService';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [assignments, setAssignments] = useState<Assignment[]>([]);

  // State for Trips (Dynamic)
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [notifications, setNotifications] = useState<string[]>([]);

  const [loadingAI, setLoadingAI] = useState(false);
  const [aiRationale, setAiRationale] = useState<string | null>(null);

  // Load existing data if editing a past date
  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setAssignments([]);
      setTrips([]);
    }
    setAiRationale(null);
  }, [date, history]);

  // Effect to Auto-Calculate Total Volume based on Trips
  useEffect(() => {
    // Calcula a soma apenas se houver viagens.
    // Se não houver viagens (lista vazia), não forçamos zero para não apagar dados legados imediatamente ao carregar,
    // mas se o usuário começar a interagir, a soma prevalece.
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    } else if (trips.length === 0 && !history.find(h => h.date === date)?.volume) {
       // Se não tem viagens e não tem histórico, zera/limpa
       setVolume('');
    }
  }, [trips, date, history]);

  // Timer Logic: Check every minute
  useEffect(() => {
    const checkTimers = () => {
      const now = new Date();
      const newNotifications: string[] = [];

      trips.forEach(trip => {
        if (trip.unsealed && trip.unsealTimeISO) {
          const unsealTime = new Date(trip.unsealTimeISO);
          const diffMs = now.getTime() - unsealTime.getTime();
          const diffMinutes = diffMs / (1000 * 60);

          // 6 hours = 360 minutes
          // Warning Window: Between 5h30m (330m) and 6h (360m)
          if (diffMinutes >= 330 && diffMinutes < 360) {
            const minutesLeft = 360 - Math.floor(diffMinutes);
            newNotifications.push(`⚠️ Atenção: Viagem ${trip.id} vence o prazo de "Expedido mas não chegou" em ${minutesLeft} min.`);
          }
        }
      });

      // Update notifications if changed
      if (JSON.stringify(newNotifications) !== JSON.stringify(notifications)) {
        setNotifications(newNotifications);
      }
    };

    const timer = setInterval(checkTimers, 60000); // Check every minute
    checkTimers(); // Check immediately on mount/update

    return () => clearInterval(timer);
  }, [trips]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      // Remove any existing assignment for this slot
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      // If employee is assigned elsewhere, remove them from there (optional, but good UX)
      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);

      return [...withoutEmployee, { taskId, employeeId, slotIndex }];
    });
  };

  const handleAddTrip = () => {
    if (trips.length < 5) {
      setTrips(prev => [...prev, { id: '', unsealed: false }]);
    }
  };

  const handleRemoveTrip = (index: number) => {
    setTrips(prev => prev.filter((_, i) => i !== index));
  };

  const handleTripChange = (index: number, value: string) => {
    // Uppercase and limit to 15 chars
    const formattedValue = value.toUpperCase().slice(0, 15);

    setTrips(prev => {
      const newTrips = [...prev];
      newTrips[index] = { ...newTrips[index], id: formattedValue };
      return newTrips;
    });
  };

  const handleTripVolumeChange = (index: number, value: string) => {
    const numValue = value === '' ? undefined : Number(value);
    setTrips(prev => {
      const newTrips = [...prev];
      newTrips[index] = { ...newTrips[index], volume: numValue };
      return newTrips;
    });
  };

  const toggleTripUnsealed = (index: number) => {
    // 1. Calcular o novo estado das viagens
    const newTrips = [...trips];
    const currentTrip = newTrips[index];
    const isNowUnsealed = !currentTrip.unsealed;

    const now = new Date();

    // Se tornou deslacrada, adiciona timestamp. Se lacrou novamente, remove.
    const timestampDisplay = isNowUnsealed 
      ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })
      : undefined;

    const timestampISO = isNowUnsealed
      ? now.toISOString()
      : undefined;

    newTrips[index] = { 
      ...currentTrip, 
      unsealed: isNowUnsealed,
      unsealTimestamp: timestampDisplay,
      unsealTimeISO: timestampISO
    };

    // 2. Atualizar o estado visual local
    setTrips(newTrips);

    // 3. Salvar IMEDIATAMENTE no banco de dados para sincronizar com os relatórios
    const calculatedVolume = newTrips.reduce((acc, t) => acc + (t.volume || 0), 0);

    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      assignments,
      trips: newTrips
    };
    onSaveRecord(record);
  };

  const handleSave = () => {
    // Filtra viagens com ID vazio para não sujar o banco de dados
    const cleanTrips = trips.filter(t => t.id.trim() !== '');
    const calculatedVolume = cleanTrips.reduce((acc, t) => acc + (t.volume || 0), 0);

    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);

    // Atualiza o estado local caso alguma viagem vazia tenha sido removida
    setTrips(cleanTrips);
    setVolume(calculatedVolume > 0 ? calculatedVolume : '');

    alert("Dados salvos com sucesso!");
  };

  const handleSmartSchedule = async () => {
    setLoadingAI(true);
    try {
      const suggestion = await generateScheduleSuggestion(employees, history, date);
      setAiRationale(suggestion.rationale);

      const newAssignments: Assignment[] = [];

      suggestion.assignments.forEach((sug: any) => {
        const emp = employees.find(e => e.name.toLowerCase() === sug.employeeName.toLowerCase());
        const task = TASK_DEFINITIONS.find(t => t.id === sug.taskId);

        if (emp && task) {
          newAssignments.push({
            taskId: task.id,
            slotIndex: sug.slotIndex,
            employeeId: emp.id
          });
        }
      });

      setAssignments(newAssignments);
    } catch (e) {
      alert("Erro ao gerar sugestão. Verifique a API Key.");
    } finally {
      setLoadingAI(false);
    }
  };

  const getElapsedTime = (isoString?: string) => {
    if (!isoString) return null;
    const diff = new Date().getTime() - new Date(isoString).getTime();
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
    return `${hours}h ${minutes}m`;
  };

  const assignedCount = assignments.length;

  return (
    <div className="space-y-6 relative">

      {/* Notifications Area */}
      {notifications.length > 0 && (
        <div className="fixed top-20 right-4 z-50 w-full max-w-sm space-y-2 animate-fade-in">
          {notifications.map((note, idx) => (
            <div key={idx} className="bg-amber-100 border-l-4 border-amber-500 text-amber-900 p-4 rounded shadow-lg flex items-start gap-3">
              <AlertTriangle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-bold text-sm">Prazo de Expedição</p>
                <p className="text-sm">{note}</p>
              </div>
              <button 
                onClick={() => setNotifications(prev => prev.filter((_, i) => i !== idx))}
                className="ml-auto text-amber-500 hover:text-amber-700"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Header Controls */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 justify-between items-end">
        <div className="flex gap-4 items-end w-full md:w-auto">
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Data</label>
            <div className="relative">
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none w-full"
              />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>

          {/* Volumetria Total - READ ONLY (Calculated) */}
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1 flex items-center gap-1">
              Volumetria Total
              <span className="bg-slate-100 text-[10px] px-1.5 rounded-full text-slate-500 font-normal">Soma</span>
            </label>
            <div className="relative">
              <input
                type="number"
                placeholder="0"
                value={volume}
                readOnly
                className="pl-3 pr-8 py-2 bg-slate-100 text-slate-700 font-bold border border-slate-300 rounded-lg text-sm w-full md:w-32 focus:ring-2 focus:ring-slate-300 outline-none cursor-not-allowed"
                title="Soma automática das viagens"
              />
              <Calculator className="w-4 h-4 text-slate-400 absolute right-2.5 top-2.5" />
            </div>
          </div>

          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Carretas</label>
            <input
              type="number"
              placeholder="Ex: 2"
              value={trucks}
              onChange={(e) => setTrucks(Number(e.target.value))}
              className="px-3 py-2 bg-white border border-slate-300 rounded-lg text-sm w-full md:w-24 focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
        </div>

        <div className="flex gap-3 w-full md:w-auto">
           <button
            onClick={handleSmartSchedule}
            disabled={loadingAI}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loadingAI ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
            IA Escala
          </button>

          <button
            onClick={handleSave}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors"
          >
            <Save className="w-4 h-4" />
            Salvar
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Metrics & Trips */}
        <div className="space-y-6 lg:col-span-1">
          {/* Progress Bar */}
          <div className="bg-white px-4 py-3 rounded-xl border border-slate-200 shadow-sm flex flex-col gap-2">
            <span className="text-sm font-medium text-slate-700">
              Alocação da Equipe: {assignedCount} / {employees.length}
            </span>
            <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-500 ${assignedCount === employees.length ? 'bg-green-500' : 'bg-blue-500'}`}
                style={{ width: `${Math.min((assignedCount / employees.length) * 100, 100)}%` }}
              />
            </div>
          </div>

          {/* Trip Registration */}
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Container className="w-4 h-4 text-slate-500" />
                <h3 className="text-sm font-semibold text-slate-700">Registro de Viagens</h3>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-xs bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{trips.length}/5</span>
              </div>
            </div>

            <div className="p-4 space-y-3">
              {trips.length > 0 ? (
                trips.map((trip, idx) => {
                  const elapsedTime = trip.unsealed ? getElapsedTime(trip.unsealTimeISO) : null;
                  // Check if nearing 6 hours (5h30m = 330 min)
                  const isWarning = trip.unsealTimeISO && (new Date().getTime() - new Date(trip.unsealTimeISO).getTime()) > (330 * 60 * 1000);

                  return (
                    <div key={idx} className={`animate-fade-in flex flex-col gap-2 p-3 rounded-lg border ${isWarning ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-100'}`}>
                       <div className="flex items-start gap-2">
                         <div className="flex-1 flex flex-col gap-2">
                            {/* Linha 1: ID e Volume */}
                            <div className="flex gap-2">
                               <div className="flex-grow">
                                  <input
                                    type="text"
                                    maxLength={15}
                                    placeholder="ID Viagem"
                                    value={trip.id}
                                    onChange={(e) => handleTripChange(idx, e.target.value)}
                                    className="w-full px-3 py-2 bg-white border border-slate-300 rounded text-sm font-mono uppercase focus:ring-2 focus:ring-blue-500 outline-none placeholder:normal-case placeholder:font-sans"
                                  />
                               </div>
                               <div className="w-24 relative">
                                  <input
                                    type="number"
                                    placeholder="Vol."
                                    value={trip.volume || ''}
                                    onChange={(e) => handleTripVolumeChange(idx, e.target.value)}
                                    className="w-full pl-3 pr-7 py-2 bg-white border border-slate-300 rounded text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                  />
                                  <BarChart3 className="w-3 h-3 text-slate-400 absolute right-2 top-2.5" />
                               </div>
                            </div>

                            {/* Linha 2: Timestamps */}
                            {trip.unsealed && trip.unsealTimestamp && (
                              <div className="flex justify-between items-center mt-1">
                                <span className="text-[10px] text-slate-500 font-medium px-1 flex items-center gap-1">
                                  <Clock className="w-3 h-3" /> {trip.unsealTimestamp}
                                </span>
                                {elapsedTime && (
                                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${isWarning ? 'bg-amber-200 text-amber-800' : 'bg-slate-100 text-slate-600'}`}>
                                    {elapsedTime}
                                  </span>
                                )}
                              </div>
                            )}
                         </div>

                        <div className="flex flex-col gap-1">
                          <button 
                            onClick={() => toggleTripUnsealed(idx)}
                            className={`flex items-center justify-center w-10 h-[38px] rounded border transition-all duration-200 ${
                              trip.unsealed 
                                ? 'bg-green-100 border-green-300 text-green-600 shadow-inner' 
                                : 'bg-red-100 border-red-300 text-red-600 hover:bg-red-200'
                            }`}
                            title={trip.unsealed ? "Deslacrada" : "Lacrada"}
                          >
                            {trip.unsealed ? <Unlock className="w-5 h-5" /> : <Lock className="w-5 h-5" />}
                          </button>

                          <button
                            onClick={() => handleRemoveTrip(idx)}
                            className="flex items-center justify-center w-10 h-[30px] text-slate-400 hover:text-red-500 hover:bg-red-50 rounded transition-colors"
                            title="Remover Viagem"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })
              ) : (
                <div className="text-center py-4 text-sm text-slate-400 border border-dashed border-slate-200 rounded-lg">
                  Nenhuma viagem registrada hoje
                </div>
              )}

              {trips.length < 5 && (
                <button
                  onClick={handleAddTrip}
                  className="w-full py-2 border border-dashed border-indigo-300 text-indigo-600 rounded-lg text-sm font-medium hover:bg-indigo-50 hover:border-indigo-400 transition-all flex items-center justify-center gap-2"
                >
                  <Plus className="w-4 h-4" />
                  Adicionar Nova Viagem
                </button>
              )}
            </div>
          </div>

          {aiRationale && (
            <div className="bg-purple-50 border border-purple-200 p-4 rounded-xl text-sm text-purple-800 animate-fade-in">
              <strong>Sugestão da IA:</strong> {aiRationale}
            </div>
          )}
        </div>

        {/* Right Column: Assignments Grid */}
        <div className="lg:col-span-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {TASK_DEFINITIONS.map(task => (
              <AssignmentCard
                key={task.id}
                task={task}
                assignments={assignments}
                employees={employees}
                onAssign={handleAssign}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DailyOperations;

import React, { useRef, useState } from 'react';
import { Upload, FileSpreadsheet, FileText, AlertCircle, CheckCircle2, Printer, ImageDown, Camera, BarChart3, LayoutGrid } from 'lucide-react';
import * as XLSX from 'xlsx';
import { Document, Packer, Paragraph, Table, TableCell, TableRow, WidthType, BorderStyle, TextRun, AlignmentType, VerticalAlign, PageOrientation, ImageRun } from 'docx';
import html2canvas from 'html2canvas';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LabelList, Cell } from 'recharts';

interface Props {}

interface ReportItem {
  pdd: string;
  id: string;
  vehicleType: string;
  volume: number;
  capacity: number;
  saturation: number;
  plate: string;
}

interface AnalyticsData {
  base: string;
  count: number;
}

const GenerateReport: React.FC<Props> = () => {
  const [activeTab, setActiveTab] = useState<'visual' | 'analytics'>('visual');

  // --- STATES FOR VISUAL REPORT ---
  const fileInputRef = useRef<HTMLInputElement>(null);
  const photoInputRef = useRef<HTMLInputElement>(null);
  const reportContainerRef = useRef<HTMLDivElement>(null);

  const [importStatus, setImportStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [statusMessage, setStatusMessage] = useState('');
  const [reportData, setReportData] = useState<ReportItem[]>([]);
  const [vehiclePhotos, setVehiclePhotos] = useState<Record<string, string>>({});
  const [activePhotoId, setActivePhotoId] = useState<string | null>(null);

  // --- STATES FOR ANALYTICS REPORT ---
  const analyticsInputRef = useRef<HTMLInputElement>(null);
  const [analyticsStatus, setAnalyticsStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [analyticsData, setAnalyticsData] = useState<AnalyticsData[]>([]);
  const [totalExpedited, setTotalExpedited] = useState<number>(0);

  // --- SHARED HELPERS ---
  const findColumnName = (row: any, candidates: string[]): string | undefined => {
    if (!row) return undefined;
    const keys = Object.keys(row);
    for (const name of candidates) {
      const found = keys.find(k => k.trim().toLowerCase() === name.toLowerCase());
      if (found) return found;
    }
    return undefined;
  };

  const getCapacity = (vehicleType: string): number => {
    const type = vehicleType?.toString().toLowerCase().trim() || '';
    if (type.includes('3/4')) return 2000;
    if (type.includes('van')) return 1100;
    if (type.includes('furg')) return 1100;
    if (type.includes('utilit')) return 300;
    if (type.includes('toco')) return 4000;
    if (type.includes('truck')) return 5000;
    return 0;
  };

  const getTomorrowDate = () => {
    const today = new Date();
    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);
    return tomorrow.toLocaleDateString('pt-BR');
  };

  // --- VISUAL REPORT HANDLERS ---

  const triggerFileInput = () => {
    setImportStatus('idle');
    setReportData([]); 
    setVehiclePhotos({});
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handlePhotoCardClick = (id: string) => {
    setActivePhotoId(id);
    if (photoInputRef.current) {
      photoInputRef.current.value = '';
      photoInputRef.current.click();
    }
  };

  const handlePhotoUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && activePhotoId) {
      const reader = new FileReader();
      reader.onload = (e) => {
        if (e.target?.result) {
          setVehiclePhotos(prev => ({
            ...prev,
            [activePhotoId]: e.target!.result as string
          }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setImportStatus('loading');
    setStatusMessage('Lendo e processando arquivo...');

    const reader = new FileReader();

    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        const jsonData = XLSX.utils.sheet_to_json<any>(worksheet, { defval: "" });

        if (!jsonData || jsonData.length === 0) {
          throw new Error("Arquivo vazio ou formato inválido.");
        }

        const processedReportItems: ReportItem[] = [];

        jsonData.forEach((row: any) => {
          const idViagem = row['Tarefa de transporte No.'] || row['ID Viagem'] || row['Trip ID'];
          const pddChegada = row['PDD de chegada'] || row['Destino'] || '';
          const tipoVeiculo = row['Tipo de veículo utilizado'] || row['Veículo'] || '';
          const placa = row['Placa do carro'] || row['Placa'] || '';
          const pedidoMae = row['Número de " Pedido mãe"'] || row['Pedido mãe'] || '';

          if (!idViagem) return;

          const capacidade = getCapacity(tipoVeiculo);
          let rawVol = pedidoMae.toString();
          if (rawVol.includes(',') && !rawVol.includes('.')) {
              rawVol = rawVol.replace(',', '.');
          }
          const volumetria = parseFloat(rawVol) || 0;
          const saturacao = capacidade > 0 ? (volumetria / capacidade) : 0;

          processedReportItems.push({
            pdd: pddChegada,
            id: idViagem,
            vehicleType: tipoVeiculo,
            volume: volumetria,
            capacity: capacidade,
            saturation: saturacao,
            plate: placa
          });
        });

        if (processedReportItems.length === 0) {
          throw new Error("Nenhuma viagem válida encontrada.");
        }

        setReportData(processedReportItems);
        setImportStatus('success');
        setStatusMessage(`${processedReportItems.length} viagens processadas!`);

        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (err: any) {
        console.error("Erro no processamento:", err);
        setImportStatus('error');
        setStatusMessage(err.message || "Erro ao processar arquivo.");
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- ANALYTICS REPORT HANDLERS ---

  const triggerAnalyticsInput = () => {
    if (analyticsInputRef.current) {
      analyticsInputRef.current.click();
    }
  };

  const handleAnalyticsUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setAnalyticsStatus('loading');
    setAnalyticsData([]);
    setTotalExpedited(0);

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { defval: "" });

        if (!jsonData || jsonData.length === 0) throw new Error("Planilha vazia.");

        // Identificar colunas
        const colOrder = findColumnName(jsonData[0], ['Número de pedido JMS', 'Numero de pedido JMS', 'Pedido', 'Order ID', 'ID']);
        const colBase = findColumnName(jsonData[0], ['Parada anterior ou próxima', 'Parada anterior ou proxima', 'Base', 'Destino', 'Parada']);

        if (!colOrder) throw new Error("Coluna de Pedido não encontrada.");

        let totalCount = 0;
        const baseCounts: Record<string, number> = {};

        jsonData.forEach(row => {
           const id = String(row[colOrder] || '').trim().toUpperCase();

           // Lógica de Exclusão
           // 1. Remover filhos (com hífen)
           if (id.includes('-')) return;

           // 2. Remover lotes (começa com BR)
           if (id.startsWith('BR')) return;

           // Se passou, conta como expedido
           if (id.length > 0) {
             totalCount++;

             // Agrupar por Base
             let baseName = 'INDEFINIDO';
             if (colBase && row[colBase]) {
               baseName = String(row[colBase]).trim().toUpperCase();
               // Limpeza básica do nome da base se necessário (ex: remover prefixos comuns)
               baseName = baseName.replace('CD ', '').replace('HUB ', ''); 
             }

             baseCounts[baseName] = (baseCounts[baseName] || 0) + 1;
           }
        });

        // Formatar para gráfico
        const chartData = Object.entries(baseCounts)
          .map(([base, count]) => ({ base, count }))
          .sort((a, b) => b.count - a.count); // Ordenar maior para menor

        setTotalExpedited(totalCount);
        setAnalyticsData(chartData);
        setAnalyticsStatus('success');

        if (analyticsInputRef.current) analyticsInputRef.current.value = '';

      } catch (err: any) {
        console.error(err);
        setAnalyticsStatus('error');
        alert(err.message || "Erro ao processar planilha.");
      }
    };
    reader.readAsBinaryString(file);
  };


  // --- EXPORT FUNCTIONS (VISUAL) ---
  const handlePrint = () => window.print();

  const handleExportToPNG = async () => {
    if (!reportContainerRef.current) return;
    try {
      const canvas = await html2canvas(reportContainerRef.current, { scale: 2, backgroundColor: '#ffffff', useCORS: true });
      const image = canvas.toDataURL("image/png");
      const link = document.createElement('a');
      link.href = image;
      link.download = `Relatorio_Visual_${new Date().toISOString().split('T')[0]}.png`;
      link.click();
    } catch (err) { alert("Não foi possível gerar a imagem."); }
  };

  const dataUrlToArrayBuffer = async (dataUrl: string) => {
    const res = await fetch(dataUrl);
    return await res.arrayBuffer();
  };

  const handleExportToExcel = async () => {
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet([]);
    const CARDS_PER_ROW = 4;
    const grid: any[][] = [];
    const newMerges: XLSX.Range[] = [];
    const setGridCell = (r: number, c: number, val: any) => {
      if (!grid[r]) grid[r] = [];
      grid[r][c] = val;
    };
    let currentRowBase = 0;

    for (let i = 0; i < reportData.length; i++) {
      const item = reportData[i];
      const colBase = (i % CARDS_PER_ROW) * 3;
      if (i > 0 && i % CARDS_PER_ROW === 0) currentRowBase += 9;
      const r = currentRowBase;
      const c = colBase;
      setGridCell(r, c, "FOTO DO VEÍCULO");
      newMerges.push({ s: { r: r, c: c }, e: { r: r+1, c: c+1 } }); 
      setGridCell(r+2, c, "NOME DA LINHA"); setGridCell(r+2, c+1, item.pdd);
      setGridCell(r+3, c, "ID VIAGEM"); setGridCell(r+3, c+1, item.id);
      setGridCell(r+4, c, "TIPO DE VEICULO"); setGridCell(r+4, c+1, item.vehicleType);
      setGridCell(r+5, c, "VOLUMETRIA REAL"); setGridCell(r+5, c+1, item.volume);
      setGridCell(r+6, c, "CAPACIDADE"); setGridCell(r+6, c+1, item.capacity);
      setGridCell(r+7, c, "SATURAÇÃO"); setGridCell(r+7, c+1, `${(item.saturation * 100).toFixed(0)}%`);
      setGridCell(r+8, c, "PLACA"); setGridCell(r+8, c+1, item.plate);
    }
    XLSX.utils.sheet_add_aoa(ws, grid, { origin: "A1" });
    ws['!merges'] = newMerges;
    XLSX.utils.book_append_sheet(wb, ws, "Relatório");
    XLSX.writeFile(wb, `Relatorio_Operacional_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleExportToWord = async () => {
    const rows: TableRow[] = [];
    let currentCells: TableCell[] = [];

    for (let i = 0; i < reportData.length; i++) {
      const item = reportData[i];
      let photoChildren: any[] = [new Paragraph({ children: [new TextRun({ text: "FOTO DO VEÍCULO", bold: true, size: 20, color: "CCCCCC" })], alignment: AlignmentType.CENTER })];

      if (vehiclePhotos[item.id]) {
        try {
          const imageBuffer = await dataUrlToArrayBuffer(vehiclePhotos[item.id]);
          photoChildren = [new Paragraph({ children: [new ImageRun({ data: imageBuffer, transformation: { width: 250, height: 150 } })], alignment: AlignmentType.CENTER })];
        } catch (e) {}
      }

      const cardTable = new Table({
        width: { size: 100, type: WidthType.PERCENTAGE },
        rows: [
          new TableRow({ height: { value: 2000, rule: 'atLeast' }, children: [new TableCell({ columnSpan: 2, children: photoChildren, verticalAlign: VerticalAlign.CENTER })] }),
          ...[
            ["NOME DA LINHA", item.pdd], ["ID VIAGEM", item.id], ["TIPO DE VEICULO", item.vehicleType],
            ["VOLUMETRIA REAL", item.volume.toString()], ["CAPACIDADE", item.capacity.toString()],
            ["SATURAÇÃO", `${(item.saturation * 100).toFixed(0)}%`], ["PLACA", item.plate]
          ].map(([label, value]) => new TableRow({ children: [
                new TableCell({ width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E5E7EB" }, children: [new Paragraph({ children: [new TextRun({ text: label, bold: true, size: 16 })] })], verticalAlign: VerticalAlign.CENTER }),
                new TableCell({ width: { size: 60, type: WidthType.PERCENTAGE }, children: [new Paragraph({ children: [new TextRun({ text: value, bold: label === "PLACA" || label === "SATURAÇÃO", color: (label === "SATURAÇÃO" && parseFloat(value) > 100) ? "DC2626" : "000000", size: 16 })], alignment: AlignmentType.CENTER })], verticalAlign: VerticalAlign.CENTER })
              ]
            }))
        ]
      });
      currentCells.push(new TableCell({ children: [new Paragraph(""), cardTable, new Paragraph("")], width: { size: 25, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, left: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, right: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" } } }));
      if (currentCells.length === 4 || i === reportData.length - 1) {
        while (currentCells.length < 4) currentCells.push(new TableCell({ children: [], width: { size: 25, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "auto" }, bottom: { style: BorderStyle.NONE, size: 0, color: "auto" }, left: { style: BorderStyle.NONE, size: 0, color: "auto" }, right: { style: BorderStyle.NONE, size: 0, color: "auto" } } }));
        rows.push(new TableRow({ children: currentCells }));
        currentCells = [];
      }
    }
    const doc = new Document({ sections: [{ properties: { page: { size: { orientation: PageOrientation.LANDSCAPE }, margin: { top: 500, bottom: 500, left: 500, right: 500 } } }, children: [new Table({ rows: rows, width: { size: 100, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, left: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, right: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, insideHorizontal: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, insideVertical: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" } } })] }] });
    const blob = await Packer.toBlob(doc);
    const link = document.createElement('a');
    link.href = window.URL.createObjectURL(blob);
    link.download = `Relatorio_Visual_${new Date().toISOString().split('T')[0]}.docx`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-10">
      <input type="file" ref={photoInputRef} onChange={handlePhotoUpload} accept="image/*" className="hidden" />

      {/* Tabs */}
      <div className="print:hidden">
        <div className="bg-indigo-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90 mb-6">
          <h2 className="text-3xl font-bold mb-2">Relatório de Carregamento</h2>
          <p className="text-indigo-100 max-w-xl">
             Gere relatórios visuais de veículos ou analise a volumetria expedida por base.
          </p>
        </div>

        <div className="flex border-b border-slate-200 gap-6 mb-6">
          <button 
            onClick={() => setActiveTab('visual')}
            className={`pb-3 text-sm font-bold flex items-center gap-2 border-b-2 transition-colors ${activeTab === 'visual' ? 'border-indigo-600 text-indigo-700' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
          >
            <LayoutGrid className="w-4 h-4" /> Relatório Visual (Cartões)
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`pb-3 text-sm font-bold flex items-center gap-2 border-b-2 transition-colors ${activeTab === 'analytics' ? 'border-indigo-600 text-indigo-700' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
          >
            <BarChart3 className="w-4 h-4" /> Gráfico de Expedição (Bases)
          </button>
        </div>
      </div>

      {/* === TAB 1: VISUAL REPORT === */}
      {activeTab === 'visual' && (
        <>
          <div className="print:hidden max-w-2xl mx-auto">
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm relative flex flex-col justify-between">
              <div className="text-center">
                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mb-4 mx-auto">
                  <Upload className="w-8 h-8 text-indigo-600" />
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">Gerar Relatório Visual</h3>
                <p className="text-slate-500 text-sm mb-6 max-w-md mx-auto">
                  Carregue a planilha operacional para gerar os cartões de carregamento.
                </p>
              </div>

              <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".csv,.xlsx,.xls" className="hidden" />

              <button 
                onClick={triggerFileInput}
                disabled={importStatus === 'loading'}
                className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-xl font-medium transition-colors disabled:opacity-50 text-lg shadow-lg hover:shadow-xl hover:-translate-y-0.5 transform"
              >
                {importStatus === 'loading' ? 'Processando...' : <><FileText className="w-5 h-5" /> Selecionar Planilha</>}
              </button>

              {importStatus !== 'idle' && (
                <div className={`mt-4 p-3 rounded-lg text-sm flex items-start justify-center gap-2 ${importStatus === 'error' ? 'bg-red-50 text-red-700' : importStatus === 'success' ? 'bg-green-50 text-green-700' : 'bg-slate-50 text-slate-600'}`}>
                  {importStatus === 'error' && <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />}
                  {importStatus === 'success' && <CheckCircle2 className="w-4 h-4 mt-0.5 shrink-0" />}
                  <span>{statusMessage}</span>
                </div>
              )}
            </div>
          </div>

          {reportData.length > 0 && (
            <div className="animate-fade-in">
              <div className="print:hidden flex flex-col sm:flex-row justify-between items-center mb-6 bg-slate-100 p-4 rounded-lg border border-slate-200 gap-4 mt-8">
                <h3 className="text-xl font-bold text-slate-800">Pré-visualização</h3>
                <div className="flex flex-wrap gap-3">
                  <button onClick={handleExportToWord} className="flex items-center gap-2 bg-blue-700 text-white px-4 py-2 rounded-lg hover:bg-blue-800 transition-colors text-sm font-medium"><FileText className="w-4 h-4" /> Word</button>
                  <button onClick={handleExportToExcel} className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors text-sm font-medium"><FileSpreadsheet className="w-4 h-4" /> Excel</button>
                  <button onClick={handleExportToPNG} className="flex items-center gap-2 bg-orange-600 text-white px-4 py-2 rounded-lg hover:bg-orange-700 transition-colors text-sm font-medium"><ImageDown className="w-4 h-4" /> PNG</button>
                  <button onClick={handlePrint} className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-900 transition-colors text-sm font-medium"><Printer className="w-4 h-4" /> Imprimir</button>
                </div>
              </div>

              <div ref={reportContainerRef} className="bg-white p-4">
                <div className="w-full bg-[#FF0000] text-white font-bold text-2xl text-center py-4 mb-4 uppercase">CARREGAMENTO SE AJU - {getTomorrowDate()}</div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 print:grid-cols-4 print:gap-4">
                  {reportData.map((item, idx) => (
                    <div key={idx} className="border-2 border-slate-800 break-inside-avoid bg-white flex flex-col">
                      <div className="h-48 bg-slate-100 border-b-2 border-slate-800 flex flex-col items-center justify-center text-slate-400 cursor-pointer hover:bg-slate-200 transition-colors relative overflow-hidden group" onClick={() => handlePhotoCardClick(item.id)} title="Clique para adicionar foto">
                        {vehiclePhotos[item.id] ? <img src={vehiclePhotos[item.id]} alt={`Veículo ${item.id}`} className="max-w-full max-h-full w-auto h-auto object-contain" /> : <><Camera className="w-10 h-10 mb-2 opacity-40 group-hover:opacity-100 group-hover:scale-110 transition-all text-slate-500" /><span className="text-xs uppercase font-bold tracking-wider text-slate-500">Adicionar Foto</span></>}
                      </div>
                      <div className="text-sm">
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-200 p-2 font-bold text-slate-800 text-xs flex items-center">NOME DA LINHA</div><div className="p-2 font-mono text-slate-900 font-bold flex items-center justify-center text-center">{item.pdd || '-'}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-100 p-2 font-bold text-slate-700 text-xs flex items-center">ID VIAGEM</div><div className="p-2 font-mono text-xs flex items-center justify-center text-center break-all">{item.id}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-200 p-2 font-bold text-slate-700 text-xs flex items-center">TIPO DE VEICULO</div><div className="p-2 text-xs flex items-center justify-center text-center uppercase">{item.vehicleType}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-100 p-2 font-bold text-slate-700 text-xs flex items-center">VOLUMETRIA REAL</div><div className="p-2 text-xs flex items-center justify-center text-center font-mono">{item.volume}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-200 p-2 font-bold text-slate-700 text-xs flex items-center">CAPACIDADE</div><div className="p-2 text-xs flex items-center justify-center text-center font-mono">{item.capacity}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-100 p-2 font-bold text-slate-700 text-xs flex items-center">SATURAÇÃO</div><div className={`p-2 text-xs flex items-center justify-center text-center font-bold ${item.saturation > 1 ? 'text-red-600' : 'text-slate-900'}`}>{(item.saturation * 100).toFixed(0)}%</div></div>
                        <div className="grid grid-cols-2"><div className="bg-slate-200 p-2 font-bold text-slate-700 text-xs flex items-center">PLACA</div><div className="p-2 text-sm flex items-center justify-center text-center font-bold uppercase">{item.plate}</div></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {/* === TAB 2: ANALYTICS REPORT === */}
      {activeTab === 'analytics' && (
        <div className="animate-fade-in space-y-8">

          {/* Upload Box for Analytics */}
          <div className="max-w-2xl mx-auto">
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm relative flex flex-col justify-between">
              <div className="text-center">
                <div className="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center mb-4 mx-auto">
                  <BarChart3 className="w-8 h-8 text-orange-600" />
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">Gráfico de Expedição</h3>
                <p className="text-slate-500 text-sm mb-6 max-w-md mx-auto">
                  Carregue a planilha para calcular o total expedido e gerar o gráfico por base (Filtrando filhos e lotes).
                </p>
              </div>

              <input type="file" ref={analyticsInputRef} onChange={handleAnalyticsUpload} accept=".csv,.xlsx,.xls" className="hidden" />

              <button 
                onClick={triggerAnalyticsInput}
                disabled={analyticsStatus === 'loading'}
