import { GoogleGenAI, Type } from "@google/genai";
import { Employee, TaskDefinition, DailyRecord } from '../types';
import { TASK_DEFINITIONS } from '../constants';

export const generateScheduleSuggestion = async (
  employees: Employee[],
  history: DailyRecord[],
  targetDate: string,
  manualAssignments: { taskId: string, slotIndex: number, employeeId: string }[] = []
) => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare context for the model
  const activeEmployees = employees.filter(e => e.active).map(e => ({
    id: e.id,
    name: e.name,
    gender: e.gender
  }));

  const recentHistory = history
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    .slice(0, 10)
    .map(record => ({
      date: record.date,
      assignments: record.assignments.map(a => {
        const taskName = TASK_DEFINITIONS.find(t => t.id === a.taskId)?.name || a.taskId;
        const empName = employees.find(e => e.id === a.employeeId)?.name || "Unknown";
        return { employeeName: empName, task: taskName, taskId: a.taskId };
      })
    }));

  const prompt = `
    You are a logistics manager AI.
    Active team (${activeEmployees.length} people): ${JSON.stringify(activeEmployees)}.

    CRITICAL RULES:
    1. Gender Rule: Females (gender: 'F') CANNOT be assigned to 'Virar Pacote' (task-turn).
    2. Rotation Rule: Employees should not repeat the same task they did recently until they've rotated through others.
    3. Mandatory Slots: Fill slots for these tasks first: ${JSON.stringify(TASK_DEFINITIONS.filter(t => t.id !== 'task-solto').map(t => ({ id: t.id, name: t.name, capacity: t.capacity })))}.
    4. Surplus Logic: If there are more employees than mandatory task slots, assign the remainder to 'Solto / Reserva' (task-solto).
    5. Manual Overrides: These positions are already filled manually (do not change them): ${JSON.stringify(manualAssignments.map(m => {
        const emp = employees.find(e => e.id === m.employeeId);
        return { taskId: m.taskId, slotIndex: m.slotIndex, employeeName: emp?.name };
    }))}.

    Recent History for rotation:
    ${JSON.stringify(recentHistory)}

    GOAL: Create a fair daily roster for ${targetDate}. Ensure every active employee has a position.
    Return a JSON object with 'rationale' and 'assignments' array.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rationale: { type: Type.STRING },
            assignments: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  taskId: { type: Type.STRING },
                  slotIndex: { type: Type.INTEGER },
                  employeeName: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Employee } from '../types';
import { UserPlus, UserX, UserCheck, Pencil, Check, X, Loader2 } from 'lucide-react';

interface Props {
  employees: Employee[];
  onAddEmployee: (emp: Employee) => Promise<void>;
  onUpdateEmployee: (emp: Employee) => Promise<void>;
}

const TeamManagement: React.FC<Props> = ({ employees, onAddEmployee, onUpdateEmployee }) => {
  const [newName, setNewName] = useState('');
  const [newGender, setNewGender] = useState<'M' | 'F'>('M');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editNameValue, setEditNameValue] = useState('');
  const [editGenderValue, setEditGenderValue] = useState<'M' | 'F'>('M');
  const [loading, setLoading] = useState(false);

  const handleAdd = async () => {
    if (!newName.trim()) return;
    setLoading(true);
    try {
      const newEmp: Employee = {
        id: `emp-${Date.now()}`,
        name: newName,
        active: true,
        gender: newGender
      };
      await onAddEmployee(newEmp);
      setNewName('');
    } catch (error) {
      alert('Erro ao adicionar colaborador. Tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  const toggleStatus = async (emp: Employee) => {
    try {
      await onUpdateEmployee({ ...emp, active: !emp.active });
    } catch (error) {
      alert('Erro ao atualizar status.');
    }
  };

  const startEditing = (emp: Employee) => {
    setEditingId(emp.id);
    setEditNameValue(emp.name);
    setEditGenderValue(emp.gender);
  };

  const saveEdit = async (originalEmp: Employee) => {
    if (editingId && editNameValue.trim()) {
      try {
        await onUpdateEmployee({ ...originalEmp, name: editNameValue, gender: editGenderValue });
        setEditingId(null);
      } catch (error) {
        alert('Erro ao salvar.');
      }
    }
  };

  const cancelEdit = () => {
    setEditingId(null);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-end gap-4">
        <div className="flex-1 w-full">
          <label className="block text-sm font-medium text-slate-700 mb-1">Novo Colaborador</label>
          <input
            type="text"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            placeholder="Nome do colaborador"
            className="w-full px-4 py-2 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
            onKeyDown={(e) => e.key === 'Enter' && handleAdd()}
            disabled={loading}
          />
        </div>
        <div className="w-full md:w-32">
          <label className="block text-sm font-medium text-slate-700 mb-1">Sexo</label>
          <select
            value={newGender}
            onChange={(e) => setNewGender(e.target.value as 'M' | 'F')}
            className="w-full px-4 py-2 bg-white text-slate-900 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
            disabled={loading}
          >
            <option value="M">Masc.</option>
            <option value="F">Fem.</option>
          </select>
        </div>
        <button 
          onClick={handleAdd}
          disabled={loading}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors disabled:opacity-50 whitespace-nowrap"
        >
          {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <UserPlus className="w-4 h-4" />} 
          Adicionar
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <table className="w-full">
          <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-semibold">
            <tr>
              <th className="px-6 py-4 text-left">Nome</th>
              <th className="px-6 py-4 text-center">Sexo</th>
              <th className="px-6 py-4 text-left">Status</th>
              <th className="px-6 py-4 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {employees.map(emp => (
              <tr key={emp.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-medium text-slate-800">
                  {editingId === emp.id ? (
                    <input
                      type="text"
                      value={editNameValue}
                      onChange={(e) => setEditNameValue(e.target.value)}
                      className="w-full px-2 py-1 bg-white text-slate-900 border border-slate-300 rounded focus:ring-2 focus:ring-indigo-500 outline-none"
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') saveEdit(emp);
                        if (e.key === 'Escape') cancelEdit();
                      }}
                      autoFocus
                    />
                  ) : (
                    emp.name
                  )}
                </td>
                <td className="px-6 py-4 text-center">
                  {editingId === emp.id ? (
                    <select
                      value={editGenderValue}
                      onChange={(e) => setEditGenderValue(e.target.value as 'M' | 'F')}
                      className="px-2 py-1 border rounded"
                    >
                      <option value="M">M</option>
                      <option value="F">F</option>
                    </select>
                  ) : (
                    <span className={`px-2 py-1 rounded-md text-xs font-bold ${emp.gender === 'M' ? 'bg-blue-50 text-blue-600' : 'bg-pink-50 text-pink-600'}`}>
                      {emp.gender === 'M' ? 'Masc' : 'Fem'}
                    </span>
                  )}
                </td>
                <td className="px-6 py-4">
                  <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                    emp.active ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
