        <ShippedNotArrived />
      )}
      {view === 'secondary' && (
        <SecondaryTrips />
      )}
      {view === 'supplies' && (
        <SuppliesControl />
      )}
      {view === 'epis' && (
        <EpiControl />
      )}
      {view === 'qrcode' && (
        <QrCodeGenerator />
      )}
    </Layout>
  );
}

