import { Employee, TaskDefinition, DailyRecord, Assignment, TaskCategory } from '../types';
import { TASK_DEFINITIONS } from '../constants';

/**
 * Algoritmo de Escalonamento Automático Baseado em Regras
 * Garante o preenchimento total das vagas antes de alocar como 'Solto'
 */
export const calculateAutoRotation = (
  employees: Employee[],
  history: DailyRecord[],
  currentAssignments: Assignment[]
): Assignment[] => {
  // 1. Identificar colaboradores ativos
  const activeEmployees = employees.filter(e => e.active);

  // 2. Identificar alocações MANUAIS (fixadas pelo usuário)
  // Somente as manuais devem ser preservadas e impedir novas alocações no mesmo slot
  const manualAssignments = currentAssignments.filter(a => a.isManual);
  const manualEmployeeIds = new Set(manualAssignments.map(a => a.employeeId));

  // Pool de funcionários disponíveis (quem não foi fixado manualmente)
  let remainingPool = activeEmployees.filter(e => !manualEmployeeIds.has(e.id));

  // 3. Preparar lista de todos os slots vazios das tarefas PRINCIPAIS (não Solto)
  const taskSlots: { taskId: string; slotIndex: number; category: TaskCategory; priority: number }[] = [];

  TASK_DEFINITIONS.forEach(task => {
    if (task.category !== TaskCategory.SOLTO) {
      for (let i = 0; i < task.capacity; i++) {
        // Verificar se este slot já está ocupado por uma alocação MANUAL
        const isOccupiedManually = manualAssignments.some(a => a.taskId === task.id && a.slotIndex === i);

        if (!isOccupiedManually) {
          // Definição de prioridade de preenchimento:
          // 1: Virar Pacote (Crítico por restrição de gênero)
          // 2: Descarregar Carreta (Crítico por esforço)
          // 3: Outros (Pesca, Ensacar)
          let priority = 3;
          if (task.category === TaskCategory.TURN) priority = 1;
          else if (task.category === TaskCategory.UNLOAD) priority = 2;

          taskSlots.push({ taskId: task.id, slotIndex: i, category: task.category, priority });
        }
      }
    }
  });

  // Ordenar slots para preencher os mais críticos/restritos primeiro
  taskSlots.sort((a, b) => a.priority - b.priority);

  // Começamos o novo conjunto de atribuições com as manuais
  const newAssignments: Assignment[] = [...manualAssignments];

  /**
   * Score de Histórico para evitar repetição excessiva
   */
  const getTaskHistoryScore = (employeeId: string, taskId: string): number => {
    const sortedHistory = [...history].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    for (let i = 0; i < sortedHistory.length; i++) {
      if (sortedHistory[i].assignments.some(a => a.employeeId === employeeId && a.taskId === taskId)) {
        return i; // Quanto menor o número, mais recentemente ele fez a tarefa
      }
    }
    return 999; // Nunca fez
  };

  // 4. Preencher os slots obrigatórios
  taskSlots.forEach(slot => {
    if (remainingPool.length === 0) return;

    // Filtrar quem pode fazer a tarefa (Regra de gênero para Virar Pacote)
    let candidates = remainingPool.filter(emp => {
      if (slot.category === TaskCategory.TURN && emp.gender === 'F') return false;
      return true;
    });

    // Se não houver homens para "Virar Pacote", tentamos qualquer um (fallback de segurança) 
    // ou deixamos vazio se a regra for absoluta. Aqui mantemos a regra absoluta.
    if (candidates.length > 0) {
      // Ordenar candidatos por quem está há mais tempo sem fazer essa tarefa específica
      candidates.sort((a, b) => {
        const scoreA = getTaskHistoryScore(a.id, slot.taskId);
        const scoreB = getTaskHistoryScore(b.id, slot.taskId);
        return scoreB - scoreA;
      });

      const chosen = candidates[0];
      newAssignments.push({
        taskId: slot.taskId,
        slotIndex: slot.slotIndex,
        employeeId: chosen.id,
        isManual: false
      });

      // Remove do pool de disponíveis
      remainingPool = remainingPool.filter(e => e.id !== chosen.id);
    }
  });

  // 5. Alocar EXCEDENTES como "Solto / Reserva"
  const soltoTask = TASK_DEFINITIONS.find(t => t.category === TaskCategory.SOLTO);
  if (soltoTask && remainingPool.length > 0) {
    remainingPool.forEach((emp, index) => {
      // Encontrar próximo slot livre na categoria Solto
      let slotIdx = 0;
      while (newAssignments.some(a => a.taskId === soltoTask.id && a.slotIndex === slotIdx)) {
        slotIdx++;
      }

      newAssignments.push({
        taskId: soltoTask.id,
        slotIndex: slotIdx,
        employeeId: emp.id,
        isManual: false
      });
    });
  }

  return newAssignments;
};

