  const manualAssignments = currentAssignments.filter(a => a.isManual);
  const manualEmployeeIds = new Set(manualAssignments.map(a => a.employeeId));

  // 3. Pool inicial de disponíveis (quem não foi fixado manualmente)
  let availablePool = activeEmployees.filter(e => !manualEmployeeIds.has(e.id));

  // 4. Regra Especial: Identificar Edina para mantê-la em 'Solto'
  // Procuramos por "Edina" no pool de disponíveis
  const edina = availablePool.find(e => e.name.trim().toLowerCase() === 'edina');
  let reservedForSolto: Employee[] = [];

  if (edina) {
    reservedForSolto.push(edina);
    // Removemos a Edina do pool que preenche as tarefas obrigatórias
    availablePool = availablePool.filter(e => e.id !== edina.id);
  }

  // 5. Preparar lista de todos os slots vazios das tarefas PRINCIPAIS (não Solto)
  const taskSlots: { taskId: string; slotIndex: number; category: TaskCategory; priority: number }[] = [];

  TASK_DEFINITIONS.forEach(task => {
    if (task.category !== TaskCategory.SOLTO) {
      for (let i = 0; i < task.capacity; i++) {
        const isOccupiedManually = manualAssignments.some(a => a.taskId === task.id && a.slotIndex === i);
        if (!isOccupiedManually) {
          let priority = 3;
          if (task.category === TaskCategory.TURN) priority = 1; // Prioridade máxima por restrição de gênero
          else if (task.category === TaskCategory.UNLOAD) priority = 2;

          taskSlots.push({ taskId: task.id, slotIndex: i, category: task.category, priority });
        }
      }
    }
  });

  // Ordenar slots por prioridade
  taskSlots.sort((a, b) => a.priority - b.priority);

  const newAssignments: Assignment[] = [...manualAssignments];

  /**
   * Score de Histórico para evitar repetição
   */
  const getTaskHistoryScore = (employeeId: string, taskId: string): number => {
    const sortedHistory = [...history].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    for (let i = 0; i < sortedHistory.length; i++) {
      if (sortedHistory[i].assignments.some(a => a.employeeId === employeeId && a.taskId === taskId)) {
        return i;
      }
    }
    return 999;
  };

  // 6. Preencher os slots obrigatórios com o pool disponível (sem a Edina)
  taskSlots.forEach(slot => {
    if (availablePool.length === 0) return;

    let candidates = availablePool.filter(emp => {
      if (slot.category === TaskCategory.TURN && emp.gender === 'F') return false;
      return true;
    });

    if (candidates.length > 0) {
      candidates.sort((a, b) => {
        const scoreA = getTaskHistoryScore(a.id, slot.taskId);
        const scoreB = getTaskHistoryScore(b.id, slot.taskId);
        return scoreB - scoreA;
      });

      const chosen = candidates[0];
      newAssignments.push({
        taskId: slot.taskId,
        slotIndex: slot.slotIndex,
        employeeId: chosen.id,
        isManual: false
      });

      availablePool = availablePool.filter(e => e.id !== chosen.id);
    }
  });

  // 7. Alocar EXCEDENTES + EDINA na tarefa "Solto / Reserva"
  const soltoTask = TASK_DEFINITIONS.find(t => t.category === TaskCategory.SOLTO);
  if (soltoTask) {
    // A lista final de soltos contém a Edina primeiro, depois o que sobrou das outras tarefas
    const finalSoltos = [...reservedForSolto, ...availablePool];

    finalSoltos.forEach((emp) => {
      // Encontrar próximo slot livre (pulando manuais já existentes no solto)
      let slotIdx = 0;
      while (newAssignments.some(a => a.taskId === soltoTask.id && a.slotIndex === slotIdx)) {
        slotIdx++;
      }

      newAssignments.push({
        taskId: soltoTask.id,
        slotIndex: slotIdx,
        employeeId: emp.id,
        isManual: false
      });
    });
  }

  return newAssignments;
};

import { Employee, TaskDefinition, DailyRecord, Assignment, TaskCategory } from '../types';
import { TASK_DEFINITIONS } from '../constants';

/**
 * Algoritmo de Escalonamento Automático Baseado em Regras
 * 1. Respeita alocações manuais.
 * 2. Reserva 'Edina' para a posição Solto.
 * 3. Preenche todos os postos obrigatórios por prioridade.
 * 4. Aloca excedentes como 'Solto'.
 */
export const calculateAutoRotation = (
  employees: Employee[],
  history: DailyRecord[],
  currentAssignments: Assignment[]
): Assignment[] => {
  // 1. Identificar colaboradores ativos
  const activeEmployees = employees.filter(e => e.active);

  // 2. Identificar alocações MANUAIS (fixadas pelo usuário)
  const manualAssignments = currentAssignments.filter(a => a.isManual);
  const manualEmployeeIds = new Set(manualAssignments.map(a => a.employeeId));

  // 3. Pool inicial de disponíveis (quem não foi fixado manualmente)
  let availablePool = activeEmployees.filter(e => !manualEmployeeIds.has(e.id));

  // 4. Regra Especial: Identificar Edina para mantê-la em 'Solto'
  // Procuramos por "Edina" no pool de disponíveis
  const edina = availablePool.find(e => e.name.trim().toLowerCase() === 'edina');
  let reservedForSolto: Employee[] = [];

  if (edina) {
    reservedForSolto.push(edina);
    // Removemos a Edina do pool que preenche as tarefas obrigatórias
    availablePool = availablePool.filter(e => e.id !== edina.id);
  }

  // 5. Preparar lista de todos os slots vazios das tarefas PRINCIPAIS (não Solto)
  const taskSlots: { taskId: string; slotIndex: number; category: TaskCategory; priority: number }[] = [];

  TASK_DEFINITIONS.forEach(task => {
    if (task.category !== TaskCategory.SOLTO) {
      for (let i = 0; i < task.capacity; i++) {
        const isOccupiedManually = manualAssignments.some(a => a.taskId === task.id && a.slotIndex === i);
        if (!isOccupiedManually) {
          let priority = 3;
          if (task.category === TaskCategory.TURN) priority = 1; // Prioridade máxima por restrição de gênero
          else if (task.category === TaskCategory.UNLOAD) priority = 2;

          taskSlots.push({ taskId: task.id, slotIndex: i, category: task.category, priority });
        }
      }
    }
  });

  // Ordenar slots por prioridade
  taskSlots.sort((a, b) => a.priority - b.priority);

  const newAssignments: Assignment[] = [...manualAssignments];

  /**
   * Score de Histórico para evitar repetição
   */
  const getTaskHistoryScore = (employeeId: string, taskId: string): number => {
    const sortedHistory = [...history].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    for (let i = 0; i < sortedHistory.length; i++) {
      if (sortedHistory[i].assignments.some(a => a.employeeId === employeeId && a.taskId === taskId)) {
        return i;
      }
    }
    return 999;
  };

  // 6. Preencher os slots obrigatórios com o pool disponível (sem a Edina)
  taskSlots.forEach(slot => {
    if (availablePool.length === 0) return;

    let candidates = availablePool.filter(emp => {
      // Regra de Gênero: Mulheres não fazem Virar Pacote nem Descarregar Carreta
      if ((slot.category === TaskCategory.TURN || slot.category === TaskCategory.UNLOAD) && emp.gender === 'F') {
        return false;
      }
      return true;
    });

    if (candidates.length > 0) {
      candidates.sort((a, b) => {
        const scoreA = getTaskHistoryScore(a.id, slot.taskId);
        const scoreB = getTaskHistoryScore(b.id, slot.taskId);
        return scoreB - scoreA;
      });

      const chosen = candidates[0];
      newAssignments.push({
        taskId: slot.taskId,
        slotIndex: slot.slotIndex,
        employeeId: chosen.id,
        isManual: false
      });

      availablePool = availablePool.filter(e => e.id !== chosen.id);
    }
  });

  // 7. Alocar EXCEDENTES + EDINA na tarefa "Solto / Reserva"
  const soltoTask = TASK_DEFINITIONS.find(t => t.category === TaskCategory.SOLTO);
  if (soltoTask) {
    // A lista final de soltos contém a Edina primeiro, depois o que sobrou das outras tarefas
    const finalSoltos = [...reservedForSolto, ...availablePool];

    finalSoltos.forEach((emp) => {
      // Encontrar próximo slot livre (pulando manuais já existentes no solto)
      let slotIdx = 0;
      while (newAssignments.some(a => a.taskId === soltoTask.id && a.slotIndex === slotIdx)) {
        slotIdx++;
      }

      newAssignments.push({
        taskId: soltoTask.id,
        slotIndex: slotIdx,
        employeeId: emp.id,
        isManual: false
      });
    });
  }

  return newAssignments;
};

import { GoogleGenAI, Type } from "@google/genai";
import { Employee, TaskDefinition, DailyRecord } from '../types';
import { TASK_DEFINITIONS } from '../constants';

export const generateScheduleSuggestion = async (
  employees: Employee[],
  history: DailyRecord[],
  targetDate: string,
  manualAssignments: { taskId: string, slotIndex: number, employeeId: string }[] = []
) => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare context for the model
  const activeEmployees = employees.filter(e => e.active).map(e => ({
    id: e.id,
    name: e.name,
    gender: e.gender
  }));

  const recentHistory = history
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    .slice(0, 10)
    .map(record => ({
      date: record.date,
      assignments: record.assignments.map(a => {
        const taskName = TASK_DEFINITIONS.find(t => t.id === a.taskId)?.name || a.taskId;
        const empName = employees.find(e => e.id === a.employeeId)?.name || "Unknown";
        return { employeeName: empName, task: taskName, taskId: a.taskId };
      })
    }));

  const prompt = `
    You are a logistics manager AI.
    Active team (${activeEmployees.length} people): ${JSON.stringify(activeEmployees)}.

    CRITICAL RULES:
    1. Gender Rule: Females (gender: 'F') CANNOT be assigned to 'Virar Pacote' (task-turn) AND CANNOT be assigned to 'Descarregar Carreta' (task-unload).
    2. Rotation Rule: Employees should not repeat the same task they did recently until they've rotated through others.
    3. Mandatory Slots: Fill slots for these tasks first: ${JSON.stringify(TASK_DEFINITIONS.filter(t => t.id !== 'task-solto').map(t => ({ id: t.id, name: t.name, capacity: t.capacity })))}.
    4. Surplus Logic: If there are more employees than mandatory task slots, assign the remainder to 'Solto / Reserva' (task-solto).
    5. Manual Overrides: These positions are already filled manually (do not change them): ${JSON.stringify(manualAssignments.map(m => {
        const emp = employees.find(e => e.id === m.employeeId);
        return { taskId: m.taskId, slotIndex: m.slotIndex, employeeName: emp?.name };
    }))}.

    Recent History for rotation:
    ${JSON.stringify(recentHistory)}

    GOAL: Create a fair daily roster for ${targetDate}. Ensure every active employee has a position.
    Return a JSON object with 'rationale' and 'assignments' array.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rationale: { type: Type.STRING },
            assignments: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  taskId: { type: Type.STRING },
                  slotIndex: { type: Type.INTEGER },
                  employeeName: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
// Added Loader2 to the lucide-react imports to fix the 'Cannot find name Loader2' error
import { Save, Calendar, Unlock, Lock, Container, Plus, Trash2, Clock, AlertTriangle, X, BarChart3, Calculator, RefreshCw, Info, Loader2 } from 'lucide-react';
import { calculateAutoRotation } from '../services/rotationService';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [processing, setProcessing] = useState(false);

  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setAssignments([]);
      setTrips([]);
    }
  }, [date, history]);

  useEffect(() => {
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    } else if (trips.length === 0 && !history.find(h => h.date === date)?.volume) {
       setVolume('');
    }
  }, [trips, date, history]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      // Remove alocação existente desse slot
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      // Remove o colaborador de qualquer outra posição que ele estivesse (evita duplicidade)
      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);

      // Adiciona como manual
      return [...withoutEmployee, { taskId, employeeId, slotIndex, isManual: true }];
    });
  };

  const handleSmartSchedule = () => {
    setProcessing(true);
    // Pequeno timeout apenas para feedback visual de processamento
    setTimeout(() => {
      try {
        const newAssignments = calculateAutoRotation(employees, history, assignments);
        setAssignments(newAssignments);
      } catch (e) {
        alert("Erro ao calcular escala.");
      } finally {
        setProcessing(false);
      }
    }, 300);
  };

  const handleSave = () => {
    const cleanTrips = trips.filter(t => t.id.trim() !== '');
    const calculatedVolume = cleanTrips.reduce((acc, t) => acc + (t.volume || 0), 0);
    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);
    setTrips(cleanTrips);
    setVolume(calculatedVolume > 0 ? calculatedVolume : '');
    alert("Dados salvos com sucesso!");
  };

  const handleAddTrip = () => trips.length < 5 && setTrips(prev => [...prev, { id: '', unsealed: false }]);
  const handleRemoveTrip = (idx: number) => setTrips(prev => prev.filter((_, i) => i !== idx));
  const handleTripChange = (idx: number, val: string) => {
    const formattedValue = val.toUpperCase().slice(0, 15);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], id: formattedValue };
      return next;
    });
  };
  const handleTripVolumeChange = (idx: number, val: string) => {
    const num = val === '' ? undefined : Number(val);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], volume: num };
      return next;
    });
  };
  const toggleTripUnsealed = (idx: number) => {
    const next = [...trips];
    const isNowUnsealed = !next[idx].unsealed;
    const now = new Date();
    next[idx] = { 
      ...next[idx], 
      unsealed: isNowUnsealed,
      unsealTimestamp: isNowUnsealed ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : undefined,
      unsealTimeISO: isNowUnsealed ? now.toISOString() : undefined
    };
    setTrips(next);
  };

  const activeEmployeesCount = employees.filter(e => e.active).length;
  const assignedCount = assignments.length;

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 justify-between items-end">
        <div className="flex gap-4 items-end w-full md:w-auto">
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Data</label>
            <div className="relative">
              <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Volumetria Total</label>
            <div className="relative">
              <input type="number" value={volume} readOnly className="pl-3 pr-8 py-2 bg-slate-100 text-slate-700 font-bold border border-slate-300 rounded-lg text-sm w-full md:w-32 cursor-not-allowed" />
              <Calculator className="w-4 h-4 text-slate-400 absolute right-2.5 top-2.5" />
            </div>
          </div>
          <div className="flex-1 md:flex-none">
            <label className="block text-xs font-medium text-slate-500 mb-1">Carretas</label>
            <input type="number" value={trucks} onChange={(e) => setTrucks(Number(e.target.value))} className="px-3 py-2 border border-slate-300 rounded-lg text-sm w-full md:w-24 outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
           <button 
             onClick={handleSmartSchedule} 
             disabled={processing} 
             className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
             title="Distribui os colaboradores ativos seguindo as regras de rotação e gênero"
           >
            {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
            Distribuir Equipe
          </button>
          <button onClick={handleSave} className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors">
            <Save className="w-4 h-4" /> Salvar
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="space-y-6 lg:col-span-1">
          <div className="bg-white px-4 py-3 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm font-medium text-slate-700">Equipe Alocada</span>
              <span className="text-xs font-bold text-slate-500">{assignedCount} / {activeEmployeesCount}</span>
            </div>
            <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-500 ${assignedCount >= activeEmployeesCount ? 'bg-green-500' : 'bg-indigo-500'}`} 
                style={{ width: `${activeEmployeesCount > 0 ? (assignedCount / activeEmployeesCount) * 100 : 0}%` }} 
              />
            </div>
          </div>

          <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl text-[11px] text-amber-800 space-y-2">
            <div className="flex items-center gap-2 font-bold uppercase mb-1">
              <Info className="w-3 h-3" /> Regras do Sistema
            </div>
            <ul className="list-disc list-inside space-y-1">
              <li>Colaboradores fixados manualmente são preservados.</li>
              <li>Mulheres não fazem "Virar Pacote" nem "Descarregar Carreta".</li>
              <li>O sistema prioriza quem está há mais tempo sem fazer a função.</li>
              <li>Excedentes são movidos automaticamente para "Solto".</li>
            </ul>
          </div>

          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                <Container className="w-4 h-4 text-slate-500" /> Viagens
              </h3>
            </div>
            <div className="p-4 space-y-3">
              {trips.length > 0 ? trips.map((trip, idx) => (
                <div key={idx} className="p-3 rounded-lg border border-slate-100 bg-slate-50/50">
                  <div className="flex gap-2 mb-2">
                    <input type="text" value={trip.id} onChange={(e) => handleTripChange(idx, e.target.value)} placeholder="ID" className="flex-1 px-2 py-1 text-sm border border-slate-300 rounded uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500" />
                    <input type="number" value={trip.volume || ''} onChange={(e) => handleTripVolumeChange(idx, e.target.value)} placeholder="Vol" className="w-20 px-2 py-1 text-sm border border-slate-300 rounded outline-none focus:ring-1 focus:ring-indigo-500" />
                  </div>
                  <div className="flex justify-between items-center">
                    <button onClick={() => toggleTripUnsealed(idx)} className={`p-2 rounded border transition-colors ${trip.unsealed ? 'bg-green-100 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                      {trip.unsealed ? <Unlock className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
                    </button>
                    <button onClick={() => handleRemoveTrip(idx)} className="text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </div>
              )) : (
                <p className="text-center py-4 text-xs text-slate-400 italic">Nenhuma viagem registrada</p>
              )}
              {trips.length < 5 && (
                <button onClick={handleAddTrip} className="w-full py-2 border-dashed border border-indigo-300 text-indigo-600 rounded text-xs font-medium hover:bg-indigo-50 transition-colors">+ Adicionar Viagem</button>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {TASK_DEFINITIONS.map(task => (
              <AssignmentCard
                key={task.id}
                task={task}
                assignments={assignments}
                employees={employees}
                onAssign={handleAssign}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

