import { Employee, TaskDefinition, DailyRecord, Assignment, TaskCategory } from '../types';
import { TASK_DEFINITIONS } from '../constants';

/**
 * Algoritmo de Escalonamento Automático Baseado em Regras
 * 1. Respeita alocações manuais.
 * 2. Aloca Diaristas: 2 na Descarga, TODO O RESTO no Ensacamento (sem limite).
 * 3. Reserva 'Edina' fixamente para 'Solto'.
 * 4. Dá preferência a 'Alex' (P1) e 'Vitória/Sofia' (P2) para 'Solto'.
 * 5. Preenche postos obrigatórios restantes por prioridade.
 */
export const calculateAutoRotation = (
  employees: Employee[],
  history: DailyRecord[],
  currentAssignments: Assignment[],
  diaristaCount: number = 0
): Assignment[] => {
  const activeEmployees = employees.filter(e => e.active);
  const manualAssignments = currentAssignments.filter(a => a.isManual);
  const manualEmployeeIds = new Set(manualAssignments.map(a => a.employeeId));
  let availablePool = activeEmployees.filter(e => !manualEmployeeIds.has(e.id));

  const normalize = (name: string) => 
    name.trim()
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

  // Reservas Especiais de Funcionários
  const edina = availablePool.find(e => normalize(e.name) === 'edina');
  let reservedStrictlyForSolto: Employee[] = [];
  if (edina) {
    reservedStrictlyForSolto.push(edina);
    availablePool = availablePool.filter(e => e.id !== edina.id);
  }

  const p1Names = ['alex'];
  let poolP1 = availablePool.filter(e => p1Names.includes(normalize(e.name)));

  const p2Names = ['vitoria', 'sofia'];
  let poolP2 = availablePool.filter(e => p2Names.includes(normalize(e.name)));

  let standardPool = availablePool.filter(e => 
    !p1Names.includes(normalize(e.name)) && 
    !p2Names.includes(normalize(e.name))
  );

  const newAssignments: Assignment[] = [...manualAssignments];
  let diaristasRemaining = diaristaCount;

  // --- REGRA DE DIARISTAS ---

  // 1. Primeiros 2 Diaristas -> Descarga (task-unload)
  const unloadTask = TASK_DEFINITIONS.find(t => t.id === 'task-unload');
  if (unloadTask) {
    for (let i = 0; i < unloadTask.capacity; i++) {
      const isOccupied = newAssignments.some(a => a.taskId === unloadTask.id && a.slotIndex === i);
      if (!isOccupied && diaristasRemaining > 0) {
        newAssignments.push({ taskId: unloadTask.id, slotIndex: i, employeeId: 'diarista-id', isManual: false });
        diaristasRemaining--;
      }
    }
  }

  // 2. TODO O RESTANTE dos Diaristas -> Ensacamento (task-bagging)
  // Independente da capacidade original, o ensacamento absorve todos
  const baggingTask = TASK_DEFINITIONS.find(t => t.id === 'task-bagging');
  if (baggingTask && diaristasRemaining > 0) {
    let slotIdx = 0;
    while (diaristasRemaining > 0) {
      // Procura o próximo slot vago (respeitando manuais)
      const isOccupied = newAssignments.some(a => a.taskId === baggingTask.id && a.slotIndex === slotIdx);
      if (!isOccupied) {
        newAssignments.push({ taskId: baggingTask.id, slotIndex: slotIdx, employeeId: 'diarista-id', isManual: false });
        diaristasRemaining--;
      }
      slotIdx++;
    }
  }

  // --- FIM REGRA DE DIARISTAS ---

  // Slots vazios restantes em tarefas obrigatórias (excluindo Solto)
  const taskSlots: { taskId: string; slotIndex: number; category: TaskCategory; priority: number }[] = [];
  TASK_DEFINITIONS.forEach(task => {
    if (task.category !== TaskCategory.SOLTO) {
      // Para o ensacamento, a capacidade pode ter sido estourada pelos diaristas, 
      // então só geramos slots de funcionários se ainda estiver dentro da capacidade original
      for (let i = 0; i < task.capacity; i++) {
        const isOccupied = newAssignments.some(a => a.taskId === task.id && a.slotIndex === i);
        if (!isOccupied) {
          let priority = 3;
          if (task.category === TaskCategory.TURN) priority = 1; 
          else if (task.category === TaskCategory.UNLOAD) priority = 2;
          taskSlots.push({ taskId: task.id, slotIndex: i, category: task.category, priority });
        }
      }
    }
  });

  taskSlots.sort((a, b) => a.priority - b.priority);

  const getTaskHistoryScore = (employeeId: string, taskId: string): number => {
    const sortedHistory = [...history].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    for (let i = 0; i < sortedHistory.length; i++) {
      if (sortedHistory[i].assignments.some(a => a.employeeId === employeeId && a.taskId === taskId)) {
        return i;
      }
    }
    return 999;
  };

  // Preencher slots obrigatórios com funcionários fixos
  taskSlots.forEach(slot => {
    let currentCandidatesPool: Employee[] = [];
    if (standardPool.length > 0) currentCandidatesPool = standardPool;
    else if (poolP2.length > 0) currentCandidatesPool = poolP2;
    else currentCandidatesPool = poolP1;

    if (currentCandidatesPool.length === 0) return;

    let candidates = currentCandidatesPool.filter(emp => {
      if ((slot.category === TaskCategory.TURN || slot.category === TaskCategory.UNLOAD) && emp.gender === 'F') return false;
      return true;
    });

    if (candidates.length === 0) {
      const fallbackPools = [poolP2, poolP1];
      for (const fPool of fallbackPools) {
        candidates = fPool.filter(emp => {
          if ((slot.category === TaskCategory.TURN || slot.category === TaskCategory.UNLOAD) && emp.gender === 'F') return false;
          return true;
        });
        if (candidates.length > 0) break;
      }
    }

    if (candidates.length > 0) {
      candidates.sort((a, b) => getTaskHistoryScore(b.id, slot.taskId) - getTaskHistoryScore(a.id, slot.taskId));
      const chosen = candidates[0];
      newAssignments.push({ taskId: slot.taskId, slotIndex: slot.slotIndex, employeeId: chosen.id, isManual: false });
      standardPool = standardPool.filter(e => e.id !== chosen.id);
      poolP2 = poolP2.filter(e => e.id !== chosen.id);
      poolP1 = poolP1.filter(e => e.id !== chosen.id);
    }
  });

  // Alocar funcionários que sobraram no Solto
  const soltoTask = TASK_DEFINITIONS.find(t => t.category === TaskCategory.SOLTO);
  if (soltoTask) {
    const finalSoltos = [...reservedStrictlyForSolto, ...poolP1, ...poolP2, ...standardPool];

    finalSoltos.forEach((emp) => {
      let slotIdx = 0;
      while (newAssignments.some(a => a.taskId === soltoTask.id && a.slotIndex === slotIdx)) slotIdx++;
      newAssignments.push({ taskId: soltoTask.id, slotIndex: slotIdx, employeeId: emp.id, isManual: false });
    });
  }

  return newAssignments;
};

import React from 'react';
import { TaskDefinition, Employee, Assignment, TaskCategory } from '../types';
import { User, Package, Truck, Network, Briefcase, UserPlus } from 'lucide-react';

interface Props {
  task: TaskDefinition;
  assignments: Assignment[];
  employees: Employee[];
  onAssign: (taskId: string, slotIndex: number, employeeId: string) => void;
}

const AssignmentCard: React.FC<Props> = ({ task, assignments, employees, onAssign }) => {
  const getIcon = (cat: TaskCategory) => {
    switch (cat) {
      case TaskCategory.UNLOAD: return <Truck className="w-5 h-5 text-red-500" />;
      case TaskCategory.TURN: return <Package className="w-5 h-5 text-orange-500" />;
      case TaskCategory.FISHING: return <Network className="w-5 h-5 text-blue-500" />;
      case TaskCategory.BAGGING: return <Briefcase className="w-5 h-5 text-green-500" />;
      case TaskCategory.SOLTO: return <User className="w-5 h-5 text-slate-400" />;
    }
  };

  const currentTaskAssignments = assignments.filter(a => a.taskId === task.id);
  const assignedEmployeeIds = new Set(assignments.map(a => a.employeeId));

  const isSolto = task.category === TaskCategory.SOLTO;

  // Encontrar o maior índice de slot ocupado para garantir que todos apareçam
  const maxOccupiedSlot = currentTaskAssignments.length > 0 
    ? Math.max(...currentTaskAssignments.map(a => a.slotIndex)) 
    : -1;

  // Mostra a capacidade original OU o número de alocações (se for maior)
  const displayCapacity = isSolto 
    ? Math.max(currentTaskAssignments.length + 1, 1) 
    : Math.max(task.capacity, maxOccupiedSlot + 1);

  return (
    <div className={`bg-white rounded-lg border shadow-sm hover:shadow-md transition-shadow p-4 ${isSolto ? 'border-slate-300 bg-slate-50/30' : 'border-slate-200'}`}>
      <div className="flex items-start justify-between mb-3">
        <div>
          <div className="flex items-center gap-2">
            {getIcon(task.category)}
            <h3 className="font-semibold text-slate-800">{task.name}</h3>
          </div>
          <p className="text-xs text-slate-500 mt-1">{task.description}</p>
        </div>
        <span className={`text-xs font-mono px-2 py-1 rounded ${isSolto ? 'bg-slate-200 text-slate-700' : 'bg-slate-100 text-slate-600'}`}>
          {currentTaskAssignments.length} {isSolto ? 'alocados' : `/ ${task.capacity}`}
        </span>
      </div>

      <div className="space-y-2">
        {Array.from({ length: displayCapacity }).map((_, idx) => {
          const assignment = currentTaskAssignments.find(a => a.slotIndex === idx);
          const isDiarista = assignment?.employeeId === 'diarista-id';
          const isExtraSlot = !isSolto && idx >= task.capacity;

          return (
            <div key={`${task.id}-${idx}`} className="relative">
              {isDiarista ? (
                <div className={`w-full flex items-center justify-between gap-2 px-3 py-2 border rounded text-sm font-bold ${isExtraSlot ? 'bg-emerald-100 border-emerald-300 text-emerald-900 animate-pulse' : 'bg-emerald-50 border-emerald-200 text-emerald-800'}`}>
                  <div className="flex items-center gap-2">
                    <UserPlus className="w-4 h-4 text-emerald-500" />
                    <span>DIARISTA {isExtraSlot ? '(Extra)' : ''}</span>
                  </div>
                  <button 
                    onClick={() => onAssign(task.id, idx, "")}
                    className="text-[10px] text-emerald-600 hover:underline"
                  >
                    Remover
                  </button>
                </div>
              ) : (
                <select
                  className={`w-full text-sm p-2 rounded border transition-colors ${
                    assignment 
                      ? 'border-indigo-200 bg-indigo-50 text-indigo-900 font-medium' 
                      : 'border-slate-200 bg-white text-slate-400 italic'
                  } focus:outline-none focus:ring-2 focus:ring-indigo-500`}
                  value={assignment?.employeeId || ""}
                  onChange={(e) => onAssign(task.id, idx, e.target.value)}
                >
                  <option value="">-- {assignment ? 'Remover' : 'Vazio'} --</option>
                  <option value="diarista-id">DIARISTA (Manual)</option>
                  {assignment && !isDiarista && (
                    <option value={assignment.employeeId}>
                      {employees.find(e => e.id === assignment.employeeId)?.name}
                    </option>
                  )}
                  {employees
                    .filter(e => !assignedEmployeeIds.has(e.id) && e.active)
                    .sort((a, b) => a.name.localeCompare(b.name))
                    .map(e => (
                      <option key={e.id} value={e.id}>
                        {e.name} ({e.gender})
                      </option>
                    ))}
                </select>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default AssignmentCard;

import React, { useState, useEffect } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Calendar, Unlock, Lock, Container, Trash2, Calculator, RefreshCw, Info, Loader2, UserPlus } from 'lucide-react';
import { calculateAutoRotation } from '../services/rotationService';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [diaristas, setDiaristas] = useState<number>(0);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [processing, setProcessing] = useState(false);

  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setDiaristas(existing.diaristaCount || 0);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setDiaristas(0);
      setAssignments([]);
      setTrips([]);
    }
  }, [date, history]);

  useEffect(() => {
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    } else if (trips.length === 0 && !history.find(h => h.date === date)?.volume) {
       setVolume('');
    }
  }, [trips, date, history]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);
      return [...withoutEmployee, { taskId, employeeId, slotIndex, isManual: true }];
    });
  };

  const handleSmartSchedule = () => {
    setProcessing(true);
    setTimeout(() => {
      try {
        const newAssignments = calculateAutoRotation(employees, history, assignments, diaristas);
        setAssignments(newAssignments);
      } catch (e) {
        alert("Erro ao calcular escala.");
      } finally {
        setProcessing(false);
      }
    }, 300);
  };

  const handleSave = () => {
    const cleanTrips = trips.filter(t => t.id.trim() !== '');
    const calculatedVolume = cleanTrips.reduce((acc, t) => acc + (t.volume || 0), 0);
    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      diaristaCount: diaristas,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);
    alert("Dados salvos com sucesso!");
  };

  const handleAddTrip = () => trips.length < 5 && setTrips(prev => [...prev, { id: '', unsealed: false }]);
  const handleRemoveTrip = (idx: number) => setTrips(prev => prev.filter((_, i) => i !== idx));
  const handleTripChange = (idx: number, val: string) => {
    const formattedValue = val.toUpperCase().slice(0, 15);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], id: formattedValue };
      return next;
    });
  };
  const handleTripVolumeChange = (idx: number, val: string) => {
    const num = val === '' ? undefined : Number(val);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], volume: num };
      return next;
    });
  };
  const toggleTripUnsealed = (idx: number) => {
    const next = [...trips];
    const isNowUnsealed = !next[idx].unsealed;
    const now = new Date();
    next[idx] = { 
      ...next[idx], 
      unsealed: isNowUnsealed,
      unsealTimestamp: isNowUnsealed ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : undefined,
      unsealTimeISO: isNowUnsealed ? now.toISOString() : undefined
    };
    setTrips(next);
  };

  const activeEmployeesCount = employees.filter(e => e.active).length;
  const assignedCount = assignments.filter(a => a.employeeId !== 'diarista-id').length;

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 justify-between items-end">
        <div className="flex flex-wrap gap-4 items-end w-full md:w-auto">
          <div className="min-w-[140px]">
            <label className="block text-xs font-medium text-slate-500 mb-1">Data</label>
            <div className="relative">
              <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
          <div className="min-w-[120px]">
            <label className="block text-xs font-medium text-slate-500 mb-1">Volumetria</label>
            <div className="relative">
              <input type="number" value={volume} readOnly className="pl-3 pr-8 py-2 bg-slate-100 text-slate-700 font-bold border border-slate-300 rounded-lg text-sm w-full cursor-not-allowed" />
              <Calculator className="w-4 h-4 text-slate-400 absolute right-2.5 top-2.5" />
            </div>
          </div>
          <div className="w-20">
            <label className="block text-xs font-medium text-slate-500 mb-1">Carretas</label>
            <input type="number" value={trucks} onChange={(e) => setTrucks(Number(e.target.value))} className="px-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <div className="w-24">
            <label className="block text-xs font-medium text-slate-500 mb-1 flex items-center gap-1">
              Diaristas
              <UserPlus className="w-3 h-3 text-emerald-500" />
            </label>
            <input 
              type="number" 
              min="0"
              max="10"
              value={diaristas} 
              onChange={(e) => setDiaristas(Math.max(0, Number(e.target.value)))} 
              className="px-3 py-2 border border-emerald-200 bg-emerald-50 text-emerald-800 font-bold rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-emerald-500" 
            />
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
           <button 
             onClick={handleSmartSchedule} 
             disabled={processing} 
             className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
           >
            {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
            Distribuir Equipe
          </button>
          <button onClick={handleSave} className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors">
            <Save className="w-4 h-4" /> Salvar
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="space-y-6 lg:col-span-1">
          <div className="bg-white px-4 py-3 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm font-medium text-slate-700">Equipe Alocada</span>
              <span className="text-xs font-bold text-slate-500">{assignedCount} / {activeEmployeesCount}</span>
            </div>
            <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-500 ${assignedCount >= activeEmployeesCount ? 'bg-green-500' : 'bg-indigo-500'}`} 
                style={{ width: `${activeEmployeesCount > 0 ? (assignedCount / activeEmployeesCount) * 100 : 0}%` }} 
              />
            </div>
          </div>

          <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl text-[11px] text-amber-800 space-y-2">
            <div className="flex items-center gap-2 font-bold uppercase mb-1">
              <Info className="w-3 h-3" /> Regras do Sistema
            </div>
            <ul className="list-disc list-inside space-y-1">
              <li><strong>Diaristas:</strong> 2 primeiros na Descarga. <strong>TODO O RESTANTE</strong> vai para o Ensacamento (slots extras criados).</li>
              <li><strong>Diaristas NUNCA</strong> ficam no posto "Solto".</li>
              <li><strong>Edina:</strong> Reserva fixa no "Solto".</li>
              <li><strong>Alex:</strong> Prioridade máxima para ficar "Solto".</li>
              <li><strong>Vitória/Sofia:</strong> Preferência secundária para o "Solto".</li>
            </ul>
          </div>

          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                <Container className="w-4 h-4 text-slate-500" /> Viagens
              </h3>
            </div>
            <div className="p-4 space-y-3">
              {trips.length > 0 ? trips.map((trip, idx) => (
                <div key={idx} className="p-3 rounded-lg border border-slate-100 bg-slate-50/50">
                  <div className="flex gap-2 mb-2">
                    <input type="text" value={trip.id} onChange={(e) => handleTripChange(idx, e.target.value)} placeholder="ID" className="flex-1 px-2 py-1 text-sm border border-slate-300 rounded uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500" />
                    <input type="number" value={trip.volume || ''} onChange={(e) => handleTripVolumeChange(idx, e.target.value)} placeholder="Vol" className="w-20 px-2 py-1 text-sm border border-slate-300 rounded outline-none focus:ring-1 focus:ring-indigo-500" />
                  </div>
                  <div className="flex justify-between items-center">
                    <button onClick={() => toggleTripUnsealed(idx)} className={`p-2 rounded border transition-colors ${trip.unsealed ? 'bg-green-100 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                      {trip.unsealed ? <Unlock className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
                    </button>
                    <button onClick={() => handleRemoveTrip(idx)} className="text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </div>
              )) : (
                <p className="text-center py-4 text-xs text-slate-400 italic">Nenhuma viagem registrada</p>
              )}
              {trips.length < 5 && (
                <button onClick={handleAddTrip} className="w-full py-2 border-dashed border border-indigo-300 text-indigo-600 rounded text-xs font-medium hover:bg-indigo-50 transition-colors">+ Adicionar Viagem</button>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {TASK_DEFINITIONS.map(task => (
              <AssignmentCard
                key={task.id}
                task={task}
                assignments={assignments}
                employees={employees}
                onAssign={handleAssign}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DailyOperations;

import { supabase } from '../lib/supabase';
import { Employee, DailyRecord, SupplyItem, SupplyTransaction, EpiItem, EpiTransaction } from '../types';

export const dataService = {
  // --- Employees ---

  async getEmployees(): Promise<Employee[]> {
    const { data, error } = await supabase
      .from('employees')
      .select('*')
      .order('name');

    if (error) {
      console.error("Erro ao buscar funcionários:", error);
      throw error;
    }
    return data || [];
  },

  async createEmployee(employee: Employee): Promise<void> {
    // Garantimos que os nomes das propriedades batem exatamente com as colunas do DB
    const { error } = await supabase
      .from('employees')
      .insert([
        {
          id: employee.id,
          name: employee.name,
          active: employee.active,
          gender: employee.gender
        }
      ]);

    if (error) {
      console.error("Erro detalhado do Supabase ao criar:", error);
      throw error;
    }
  },

  async updateEmployee(employee: Employee): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .update({ 
        name: employee.name, 
        active: employee.active,
        gender: employee.gender
      })
      .eq('id', employee.id);

    if (error) {
      console.error("Erro detalhado do Supabase ao atualizar:", error);
      throw error;
    }
  },

  async deleteEmployee(id: string): Promise<void> {
    const { error } = await supabase
      .from('employees')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Erro detalhado do Supabase ao excluir:", error);
      throw error;
    }
  },

  // --- Daily Records ---

  async getHistory(): Promise<DailyRecord[]> {
    const { data, error } = await supabase
      .from('daily_records')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((record: any) => ({
      id: record.id,
      date: record.date,
      volume: record.volume,
      trucks: record.trucks,
      diaristaCount: record.diarista_count || 0,
      assignments: Array.isArray(record.assignments) ? record.assignments : [],
      trips: Array.isArray(record.trips) ? record.trips : []
    }));
  },

  async saveDailyRecord(record: DailyRecord): Promise<void> {
    const { error } = await supabase
      .from('daily_records')
      .upsert({
        id: record.id,
        date: record.date,
        volume: record.volume,
        trucks: record.trucks,
        diarista_count: record.diaristaCount,
        assignments: record.assignments || [],
        trips: record.trips || []
      });

    if (error) throw error;
  },

  // --- Supplies ---

  async getSupplies(): Promise<SupplyItem[]> {
    const { data, error } = await supabase
      .from('supplies')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      name: item.name,
      quantity: Number(item.quantity),
      unit: item.unit,
      minStock: Number(item.min_stock)
    }));
  },

  async saveSupply(item: SupplyItem): Promise<void> {
    const { error } = await supabase
      .from('supplies')
      .upsert({
        id: item.id,
        name: item.name,
        quantity: item.quantity,
        unit: item.unit,
        min_stock: item.minStock
      });

    if (error) throw error;
  },

  async deleteSupply(id: string): Promise<void> {
    const { error } = await supabase
      .from('supplies')
      .delete()
      .eq('id', id);

    if (error) throw error;
  },

  // --- Supply Transactions ---

  async getSupplyTransactions(): Promise<SupplyTransaction[]> {
    const { data, error } = await supabase
      .from('supply_transactions')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      supplyId: item.supply_id,
      supplyName: item.supply_name,
      type: item.type,
      quantity: Number(item.quantity),
      date: item.date,
      user: item.user_name
    }));
  },

  async addSupplyTransaction(transaction: SupplyTransaction): Promise<void> {
    const { error } = await supabase
      .from('supply_transactions')
      .insert({
        id: transaction.id,
        supply_id: transaction.supplyId,
        supply_name: transaction.supplyName,
        type: transaction.type,
        quantity: transaction.quantity,
        date: transaction.date,
        user_name: transaction.user
      });

    if (error) throw error;
  },

  // --- EPIs ---

  async getEpis(): Promise<EpiItem[]> {
    const { data, error } = await supabase
      .from('epis')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      name: item.name,
      caNumber: item.ca_number || '',
      quantity: Number(item.quantity),
      minStock: Number(item.min_stock),
      validityDays: Number(item.validity_days || 0)
    }));
  },

  async saveEpi(item: EpiItem): Promise<void> {
    const { error } = await supabase
      .from('epis')
      .upsert({
        id: item.id,
        name: item.name,
        ca_number: item.caNumber,
        quantity: item.quantity,
        min_stock: item.minStock,
        validity_days: item.validityDays
      });

    if (error) throw error;
  },

  async deleteEpi(id: string): Promise<void> {
    const { error } = await supabase
      .from('epis')
      .delete()
      .eq('id', id);

    if (error) throw error;
  },

  async getEpiTransactions(): Promise<EpiTransaction[]> {
    const { data, error } = await supabase
      .from('epi_transactions')
      .select('*')
      .order('date', { ascending: false });

    if (error) throw error;

    return (data || []).map((item: any) => ({
      id: item.id,
      epiId: item.epi_id,
      epiName: item.epi_name,
      type: item.type,
      quantity: Number(item.quantity),
      date: item.date,
      employeeId: item.employee_id,
      employeeName: item.employee_name,
      notes: item.notes
    }));
  },

  async addEpiTransaction(transaction: EpiTransaction): Promise<void> {
    const { error } = await supabase
      .from('epi_transactions')
      .insert({
        id: transaction.id,
        epi_id: transaction.epiId,
        epi_name: transaction.epiName,
        type: transaction.type,
        quantity: transaction.quantity,
        date: transaction.date,
        employee_id: transaction.employeeId,
        employee_name: transaction.employeeName,
        notes: transaction.notes
      });

    if (error) throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { DailyRecord, Employee, TripInfo } from './types';
import Layout from './components/Layout';
import DailyOperations from './components/DailyOperations';
import TeamManagement from './components/TeamManagement';
import Reports from './components/Reports';
import GenerateReport from './components/GenerateReport';
import ManagementReport from './components/ManagementReport';
import ShippedNotArrived from './components/ShippedNotArrived';
import SecondaryTrips from './components/SecondaryTrips';
import SuppliesControl from './components/SuppliesControl';
import EpiControl from './components/EpiControl';
import QrCodeGenerator from './components/QrCodeGenerator';
import { dataService } from './services/dataService';
import { Loader2, AlertTriangle, Database, Copy, Check } from 'lucide-react';

// SQL Script for setup to be displayed in case of missing tables
const SETUP_SQL = `-- Run this in your Supabase SQL Editor

CREATE TABLE IF NOT EXISTS public.employees (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    active BOOLEAN DEFAULT TRUE,
    gender TEXT DEFAULT 'M'
);

-- Ensure gender column exists if table was already created
ALTER TABLE public.employees ADD COLUMN IF NOT EXISTS gender TEXT DEFAULT 'M';

CREATE TABLE IF NOT EXISTS public.daily_records (
    id TEXT PRIMARY KEY, -- YYYY-MM-DD
    date TEXT NOT NULL,
    volume NUMERIC,
    trucks NUMERIC,
    diarista_count NUMERIC DEFAULT 0,
    assignments JSONB DEFAULT '[]'::jsonb,
    trips JSONB DEFAULT '[]'::jsonb
);

-- Ensure diarista_count column exists if table was already created
ALTER TABLE public.daily_records ADD COLUMN IF NOT EXISTS diarista_count NUMERIC DEFAULT 0;

CREATE TABLE IF NOT EXISTS public.supplies (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    quantity NUMERIC DEFAULT 0,
    unit TEXT DEFAULT 'un',
    min_stock NUMERIC DEFAULT 0
);

CREATE TABLE IF NOT EXISTS public.supply_transactions (
    id TEXT PRIMARY KEY,
    supply_id TEXT REFERENCES public.supplies(id) ON DELETE CASCADE,
    supply_name TEXT,
    type TEXT CHECK (type IN ('IN', 'OUT')),
    quantity NUMERIC NOT NULL,
    date TEXT NOT NULL,
    user_name TEXT
);

-- EPIs Tables
CREATE TABLE IF NOT EXISTS public.epis (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    ca_number TEXT,
    quantity NUMERIC DEFAULT 0,
    min_stock NUMERIC DEFAULT 5,
    validity_days NUMERIC DEFAULT 0
);

CREATE TABLE IF NOT EXISTS public.epi_transactions (
    id TEXT PRIMARY KEY,
    epi_id TEXT REFERENCES public.epis(id) ON DELETE CASCADE,
    epi_name TEXT,
    type TEXT CHECK (type IN ('IN', 'OUT')),
    quantity NUMERIC NOT NULL,
    date TEXT NOT NULL,
    employee_id TEXT,
    employee_name TEXT,
    notes TEXT
);

-- Enable Row Level Security (RLS)
ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.daily_records ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.supplies ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.supply_transactions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.epis ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.epi_transactions ENABLE ROW LEVEL SECURITY;

-- Create policies to allow public access (Adjust for production!)
DROP POLICY IF EXISTS "Public Access Employees" ON public.employees;
CREATE POLICY "Public Access Employees" ON public.employees FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Records" ON public.daily_records;
CREATE POLICY "Public Access Records" ON public.daily_records FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Supplies" ON public.supplies;
CREATE POLICY "Public Access Supplies" ON public.supplies FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Transactions" ON public.supply_transactions;
CREATE POLICY "Public Access Transactions" ON public.supply_transactions FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access Epis" ON public.epis;
CREATE POLICY "Public Access Epis" ON public.epis FOR ALL USING (true);

DROP POLICY IF EXISTS "Public Access EpiTrans" ON public.epi_transactions;
CREATE POLICY "Public Access EpiTrans" ON public.epi_transactions FOR ALL USING (true);`;

function App() {
  const [view, setView] = useState<'daily' | 'team' | 'reports' | 'generate' | 'shipped' | 'management' | 'secondary' | 'supplies' | 'epis' | 'qrcode'>('daily');

  const [employees, setEmployees] = useState<Employee[]>([]);
  const [history, setHistory] = useState<DailyRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Initial Load from Supabase
  useEffect(() => {
    const fetchData = async () => {
      try {
        setError(null);
        // We try to fetch all data to check connectivity and table existence
        const [empData, histData] = await Promise.all([
          dataService.getEmployees(),
          dataService.getHistory(),
          dataService.getSupplies(), // Check Supplies table
          dataService.getEpis()      // Check EPIs table
        ]);
        setEmployees(empData);
        setHistory(histData);
      } catch (err: any) {
        console.error("Failed to load data:", JSON.stringify(err));
        // Extract meaningful message from Supabase error
        const msg = err.message || JSON.stringify(err);
        const code = err.code || '';

        // Check for specific "table not found" error
        if (code === 'PGRST205' || msg.includes('does not exist')) {
          setError('MISSING_TABLES');
        } else {
          setError(msg);
        }
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const handleSaveRecord = async (record: DailyRecord) => {
    try {
      await dataService.saveDailyRecord(record);

      setHistory(prev => {
        const idx = prev.findIndex(p => p.date === record.date);
        if (idx >= 0) {
          const newHistory = [...prev];
          newHistory[idx] = record;
          return newHistory;
        }
        return [record, ...prev]; // Add new records to top for easier history view
      });
      return true;
    } catch (error: any) {
      console.error("Error saving record:", error);
      alert(`Erro ao salvar: ${error.message || "Erro desconhecido"}`);
      return false;
    }
  };

  const handleAddEmployee = async (newEmp: Employee) => {
    await dataService.createEmployee(newEmp);
    setEmployees(prev => [...prev, newEmp]);
  };

  const handleUpdateEmployee = async (updatedEmp: Employee) => {
    await dataService.updateEmployee(updatedEmp);
    setEmployees(prev => prev.map(e => e.id === updatedEmp.id ? updatedEmp : e));
  };

  const handleDeleteEmployee = async (id: string) => {
    await dataService.deleteEmployee(id);
    setEmployees(prev => prev.filter(e => e.id !== id));
  };

  const copySqlToClipboard = () => {
    navigator.clipboard.writeText(SETUP_SQL);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center text-slate-500">
        <Loader2 className="w-10 h-10 animate-spin mb-4 text-indigo-600" />
        <p>Carregando sistema...</p>
      </div>
    );
  }

  // Error State Display
  if (error) {
    const isMissingTables = error === 'MISSING_TABLES';

    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="bg-white p-8 rounded-xl shadow-lg border border-slate-200 max-w-2xl w-full">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertTriangle className="w-8 h-8 text-red-600" />
          </div>

          <h2 className="text-2xl font-bold text-slate-800 mb-2 text-center">
            {isMissingTables ? 'Configuração Necessária' : 'Erro de Conexão'}
          </h2>

          <p className="text-slate-600 mb-6 text-center">
            {isMissingTables 
              ? 'O banco de dados do Supabase ainda não possui as tabelas necessárias (Insumos e EPIs). Por favor, execute o script abaixo.' 
              : 'Não foi possível carregar os dados do banco de dados.'}
          </p>

          {isMissingTables ? (
            <div className="space-y-4">
               <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg">
                 <h3 className="font-semibold text-blue-800 text-sm flex items-center gap-2 mb-2">
                   <Database className="w-4 h-4" /> Como Resolver:
                 </h3>
                 <ol className="list-decimal list-inside text-sm text-blue-800 space-y-1 ml-1">
                   <li>Copie o código SQL abaixo.</li>
                   <li>Acesse seu painel do Supabase.</li>
                   <li>Vá até o <strong>SQL Editor</strong>.</li>
                   <li>Cole o código e clique em <strong>RUN</strong>.</li>
                   <li>Recarregue esta página.</li>
                 </ol>
               </div>

               <div className="relative">
                 <pre className="bg-slate-900 text-slate-100 p-4 rounded-lg text-xs font-mono overflow-auto max-h-64 whitespace-pre-wrap">
                   {SETUP_SQL}
                 </pre>
                 <button 
                  onClick={copySqlToClipboard}
                  className="absolute top-2 right-2 bg-white/10 hover:bg-white/20 text-white p-2 rounded transition-colors"
                  title="Copiar SQL"
                 >
                   {copied ? <Check className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4" />}
                 </button>
               </div>
            </div>
          ) : (
            <div className="bg-slate-100 p-3 rounded text-left mb-6 overflow-auto max-h-32">
              <code className="text-xs text-slate-700 font-mono break-all">{error}</code>
            </div>
          )}

          <div className="mt-8 flex justify-center">
            <button 
              onClick={() => window.location.reload()}
              className="bg-indigo-600 text-white px-8 py-3 rounded-lg hover:bg-indigo-700 transition-colors font-medium"
            >
              Recarregar Aplicação
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout currentView={view} onChangeView={setView}>
      {view === 'daily' && (
        <DailyOperations 
          employees={employees} 
          history={history} 
          onSaveRecord={handleSaveRecord} 
        />
      )}
      {view === 'team' && (
        <TeamManagement 
          employees={employees} 
          onAddEmployee={handleAddEmployee}
          onUpdateEmployee={handleUpdateEmployee}
          onDeleteEmployee={handleDeleteEmployee}
        />
      )}
      {view === 'reports' && (
        <Reports 
          history={history} 
          employees={employees} 
        />
      )}
      {view === 'generate' && (
        <GenerateReport />
      )}
      {view === 'management' && (
        <ManagementReport history={history} />
      )}
      {view === 'shipped' && (
        <ShippedNotArrived />
      )}
      {view === 'secondary' && (
        <SecondaryTrips />
      )}
      {view === 'supplies' && (
        <SuppliesControl />
      )}
      {view === 'epis' && (
        <EpiControl />
      )}
      {view === 'qrcode' && (
        <QrCodeGenerator />
      )}
    </Layout>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Calendar, Unlock, Lock, Container, Trash2, Calculator, RefreshCw, Info, Loader2, UserPlus, ImageDown, Share2 } from 'lucide-react';
import { calculateAutoRotation } from '../services/rotationService';
import html2canvas from 'html2canvas';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [diaristas, setDiaristas] = useState<number>(0);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [processing, setProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setDiaristas(existing.diaristaCount || 0);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setDiaristas(0);
      setAssignments([]);
      setTrips([]);
    }
  }, [date, history]);

  useEffect(() => {
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    } else if (trips.length === 0 && !history.find(h => h.date === date)?.volume) {
       setVolume('');
    }
  }, [trips, date, history]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);
      return [...withoutEmployee, { taskId, employeeId, slotIndex, isManual: true }];
    });
  };

  const handleSmartSchedule = () => {
    setProcessing(true);
    setTimeout(() => {
      try {
        const newAssignments = calculateAutoRotation(employees, history, assignments, diaristas);
        setAssignments(newAssignments);
      } catch (e) {
        alert("Erro ao calcular escala.");
      } finally {
        setProcessing(false);
      }
    }, 300);
  };

  const handleSave = () => {
    const cleanTrips = trips.filter(t => t.id.trim() !== '');
    const calculatedVolume = cleanTrips.reduce((acc, t) => acc + (t.volume || 0), 0);
    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      diaristaCount: diaristas,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);
    alert("Dados salvos com sucesso!");
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;

    setIsExporting(true);
    // Pequeno delay para garantir que o estado de "exportando" reflita no DOM (caso queira esconder algo)
    await new Promise(resolve => setTimeout(resolve, 100));

    try {
      const canvas = await html2canvas(reportRef.current, {
        backgroundColor: '#f8fafc',
        scale: 2, // Melhor qualidade
        logging: false,
        useCORS: true,
        ignoreElements: (element) => {
          return element.hasAttribute('data-html2canvas-ignore');
        }
      });

      const image = canvas.toDataURL("image/png");
      const link = document.createElement('a');
      const [year, month, day] = date.split('-');
      link.download = `Escala_Logistica_${day}_${month}_${year}.png`;
      link.href = image;
      link.click();
    } catch (err) {
      console.error("Erro ao gerar imagem:", err);
      alert("Erro ao gerar imagem da escala.");
    } finally {
      setIsExporting(false);
    }
  };

  const handleAddTrip = () => trips.length < 5 && setTrips(prev => [...prev, { id: '', unsealed: false }]);
  const handleRemoveTrip = (idx: number) => setTrips(prev => prev.filter((_, i) => i !== idx));
  const handleTripChange = (idx: number, val: string) => {
    const formattedValue = val.toUpperCase().slice(0, 15);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], id: formattedValue };
      return next;
    });
  };
  const handleTripVolumeChange = (idx: number, val: string) => {
    const num = val === '' ? undefined : Number(val);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], volume: num };
      return next;
    });
  };
  const toggleTripUnsealed = (idx: number) => {
    const next = [...trips];
    const isNowUnsealed = !next[idx].unsealed;
    const now = new Date();
    next[idx] = { 
      ...next[idx], 
      unsealed: isNowUnsealed,
      unsealTimestamp: isNowUnsealed ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : undefined,
      unsealTimeISO: isNowUnsealed ? now.toISOString() : undefined
    };
    setTrips(next);
  };

  const activeEmployeesCount = employees.filter(e => e.active).length;
