                 <Calendar className="w-3.5 h-3.5" /> 
                 {new Date(date + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' })}
               </p>
             </div>
          </div>
          <div className="flex gap-4">
            <div className="bg-slate-50 px-4 py-2 rounded-lg border border-slate-100 text-center">
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Volumetria Total</p>
