                  <div key={idx} className="p-3 rounded-lg border border-slate-100 bg-slate-50/50">
                    <div className="flex gap-2 mb-2">
                      <input type="text" value={trip.id} onChange={(e) => handleTripChange(idx, e.target.value)} placeholder="ID" className="flex-1 px-2 py-1 text-sm border border-slate-300 rounded uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500 font-bold bg-white" data-html2canvas-ignore={false} />
                      <input type="number" value={trip.volume || ''} onChange={(e) => handleTripVolumeChange(idx, e.target.value)} placeholder="Vol" className="w-20 px-2 py-1 text-sm border border-slate-300 rounded outline-none focus:ring-1 focus:ring-indigo-500 font-bold bg-white" />
                    </div>
                    <div className="flex justify-between items-center">
                      <button onClick={() => toggleTripUnsealed(idx)} className={`p-2 rounded border transition-colors ${trip.unsealed ? 'bg-green-100 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                        {trip.unsealed ? <Unlock className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
                      </button>
                      <span className="text-[10px] font-mono text-slate-400">
                        {trip.unsealed ? `Deslacre: ${trip.unsealTimestamp}` : 'Aguardando Deslacre'}
                      </span>
                      <button onClick={() => handleRemoveTrip(idx)} className="text-slate-400 hover:text-red-500 transition-colors" data-html2canvas-ignore><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>
                )) : (
                  <p className="text-center py-4 text-xs text-slate-400 italic">Nenhuma viagem registrada</p>
                )}
                {trips.length < 5 && (
                  <button onClick={handleAddTrip} className="w-full py-2 border-dashed border border-indigo-300 text-indigo-600 rounded text-xs font-medium hover:bg-indigo-50 transition-colors" data-html2canvas-ignore>+ Adicionar Viagem</button>
                )}
              </div>
            </div>
          </div>

          <div className="lg:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {TASK_DEFINITIONS.map(task => (
                <AssignmentCard
                  key={task.id}
                  task={task}
                  assignments={assignments}
                  employees={employees}
                  onAssign={handleAssign}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DailyOperations;

import React from 'react';
import { TaskDefinition, Employee, Assignment, TaskCategory } from '../types';
import { User, Package, Truck, Network, Briefcase, UserPlus, X } from 'lucide-react';

interface Props {
  task: TaskDefinition;
  assignments: Assignment[];
  employees: Employee[];
  onAssign: (taskId: string, slotIndex: number, employeeId: string) => void;
}

const AssignmentCard: React.FC<Props> = ({ task, assignments, employees, onAssign }) => {
  const getIcon = (cat: TaskCategory) => {
    switch (cat) {
      case TaskCategory.UNLOAD: return <Truck className="w-5 h-5 text-red-500" />;
      case TaskCategory.TURN: return <Package className="w-5 h-5 text-orange-500" />;
      case TaskCategory.FISHING: return <Network className="w-5 h-5 text-blue-500" />;
      case TaskCategory.BAGGING: return <Briefcase className="w-5 h-5 text-green-500" />;
      case TaskCategory.SOLTO: return <User className="w-5 h-5 text-slate-400" />;
    }
  };

  const currentTaskAssignments = assignments.filter(a => a.taskId === task.id);
  const assignedEmployeeIds = new Set(assignments.map(a => a.employeeId));

  const isSolto = task.category === TaskCategory.SOLTO;

  // Encontrar o maior índice de slot ocupado para garantir que todos apareçam
  const maxOccupiedSlot = currentTaskAssignments.length > 0 
    ? Math.max(...currentTaskAssignments.map(a => a.slotIndex)) 
    : -1;

  // Mostra a capacidade original OU o número de alocações (se for maior)
  const displayCapacity = isSolto 
    ? Math.max(currentTaskAssignments.length + 1, 1) 
    : Math.max(task.capacity, maxOccupiedSlot + 1);

  return (
    <div className={`bg-white rounded-lg border shadow-sm hover:shadow-md transition-shadow p-4 ${isSolto ? 'border-slate-300 bg-slate-50/30' : 'border-slate-200'}`}>
      <div className="flex items-start justify-between mb-3">
        <div>
          <div className="flex items-center gap-2">
            {getIcon(task.category)}
            <h3 className="font-semibold text-slate-800">{task.name}</h3>
          </div>
          <p className="text-xs text-slate-500 mt-1">{task.description}</p>
        </div>
        <span className={`text-xs font-mono px-2 py-1 rounded ${isSolto ? 'bg-slate-200 text-slate-700' : 'bg-slate-100 text-slate-600'}`}>
          {currentTaskAssignments.length} {isSolto ? 'alocados' : `/ ${task.capacity}`}
        </span>
      </div>

      <div className="space-y-2">
        {Array.from({ length: displayCapacity }).map((_, idx) => {
          const assignment = currentTaskAssignments.find(a => a.slotIndex === idx);
          const isDiarista = assignment?.employeeId === 'diarista-id';
          const isExtraSlot = !isSolto && idx >= task.capacity;
          const employee = assignment ? employees.find(e => e.id === assignment.employeeId) : null;

          return (
            <div key={`${task.id}-${idx}`} className="relative h-9">
              {isDiarista ? (
                <div className={`w-full h-full flex items-center justify-between gap-2 px-3 border rounded text-sm font-bold ${isExtraSlot ? 'bg-emerald-100 border-emerald-300 text-emerald-900 animate-pulse' : 'bg-emerald-50 border-emerald-200 text-emerald-800'}`}>
                  <div className="flex items-center gap-2">
                    <UserPlus className="w-4 h-4 text-emerald-500" />
                    <span>DIARISTA {isExtraSlot ? '(Extra)' : ''}</span>
                  </div>
                  <button 
                    onClick={() => onAssign(task.id, idx, "")}
                    className="text-emerald-400 hover:text-emerald-600 transition-colors"
                    data-html2canvas-ignore
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              ) : assignment ? (
                /* Display de texto para o funcionário - html2canvas captura corretamente */
                <div className="w-full h-full flex items-center justify-between gap-2 px-3 border border-indigo-200 bg-indigo-50 text-indigo-900 font-medium rounded text-sm transition-all">
                  <div className="flex items-center gap-2 truncate">
                    <div className={`w-1.5 h-1.5 rounded-full ${employee?.gender === 'M' ? 'bg-blue-400' : 'bg-pink-400'}`} />
                    <span className="truncate">{employee?.name || "Desconhecido"}</span>
                  </div>
                  <button 
                    onClick={() => onAssign(task.id, idx, "")}
                    className="text-indigo-300 hover:text-indigo-600 transition-colors"
                    data-html2canvas-ignore
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              ) : (
                /* Select apenas quando o slot está vazio */
                <select
                  className="w-full h-full text-sm px-2 rounded border border-slate-200 bg-white text-slate-400 italic focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none"
                  value=""
                  onChange={(e) => onAssign(task.id, idx, e.target.value)}
                >
                  <option value="">-- Vazio --</option>
                  <option value="diarista-id">+ DIARISTA</option>
                  {employees
                    .filter(e => !assignedEmployeeIds.has(e.id) && e.active)
                    .sort((a, b) => a.name.localeCompare(b.name))
                    .map(e => (
                      <option key={e.id} value={e.id}>
                        {e.name} ({e.gender})
                      </option>
                    ))}
                </select>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default AssignmentCard;

import React, { useState, useEffect, useRef } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Calendar, Unlock, Lock, Container, Trash2, Calculator, RefreshCw, Info, Loader2, UserPlus, ImageDown, Share2 } from 'lucide-react';
import { calculateAutoRotation } from '../services/rotationService';
import html2canvas from 'html2canvas';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [diaristas, setDiaristas] = useState<number>(0);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [processing, setProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setDiaristas(existing.diaristaCount || 0);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setDiaristas(0);
      setAssignments([]);
      setTrips([]);
    }
  }, [date, history]);

  useEffect(() => {
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    } else if (trips.length === 0 && !history.find(h => h.date === date)?.volume) {
       setVolume('');
    }
  }, [trips, date, history]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);
      return [...withoutEmployee, { taskId, employeeId, slotIndex, isManual: true }];
    });
  };

  const handleSmartSchedule = () => {
    setProcessing(true);
    setTimeout(() => {
      try {
        const newAssignments = calculateAutoRotation(employees, history, assignments, diaristas);
        setAssignments(newAssignments);
      } catch (e) {
        alert("Erro ao calcular escala.");
      } finally {
        setProcessing(false);
      }
    }, 300);
  };

  const handleSave = () => {
    const cleanTrips = trips.filter(t => t.id.trim() !== '');
    const calculatedVolume = cleanTrips.reduce((acc, t) => acc + (t.volume || 0), 0);
    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      diaristaCount: diaristas,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);
    alert("Dados salvos com sucesso!");
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;

    setIsExporting(true);
    // Pequeno delay para o React atualizar o estado (removendo inputs e mostrando texto)
    await new Promise(resolve => setTimeout(resolve, 300));

    try {
      const canvas = await html2canvas(reportRef.current, {
        backgroundColor: '#f8fafc',
        scale: 2, 
        logging: false,
        useCORS: true,
        allowTaint: true,
        onclone: (clonedDoc) => {
          // Garante que o fundo esteja correto no clone
          const el = clonedDoc.querySelector('[data-report-container]') as HTMLElement;
          if (el) el.style.padding = '20px';
        }
      });

      const image = canvas.toDataURL("image/png");
      const link = document.createElement('a');
      const [year, month, day] = date.split('-');
      link.download = `Escala_${day}_${month}_${year}.png`;
      link.href = image;
      link.click();
    } catch (err) {
      console.error("Erro ao gerar imagem:", err);
      alert("Erro ao gerar imagem da escala.");
    } finally {
      setIsExporting(false);
    }
  };

  const handleAddTrip = () => trips.length < 5 && setTrips(prev => [...prev, { id: '', unsealed: false }]);
  const handleRemoveTrip = (idx: number) => setTrips(prev => prev.filter((_, i) => i !== idx));
  const handleTripChange = (idx: number, val: string) => {
    const formattedValue = val.toUpperCase().slice(0, 15);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], id: formattedValue };
      return next;
    });
  };
  const handleTripVolumeChange = (idx: number, val: string) => {
    const num = val === '' ? undefined : Number(val);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], volume: num };
      return next;
    });
  };
  const toggleTripUnsealed = (idx: number) => {
    const next = [...trips];
    const isNowUnsealed = !next[idx].unsealed;
    const now = new Date();
    next[idx] = { 
      ...next[idx], 
      unsealed: isNowUnsealed,
      unsealTimestamp: isNowUnsealed ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : undefined,
      unsealTimeISO: isNowUnsealed ? now.toISOString() : undefined
    };
    setTrips(next);
  };

  const activeEmployeesCount = employees.filter(e => e.active).length;
  const assignedCount = assignments.filter(a => a.employeeId !== 'diarista-id').length;

  return (
    <div className="space-y-6">
      {/* Botões Superiores de Ação - SEMPRE OCULTOS NO PNG */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 justify-between items-end" data-html2canvas-ignore>
        <div className="flex flex-wrap gap-4 items-end w-full md:w-auto">
          <div className="min-w-[140px]">
            <label className="block text-xs font-medium text-slate-500 mb-1">Data</label>
            <div className="relative">
              <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
          <div className="min-w-[120px]">
            <label className="block text-xs font-medium text-slate-500 mb-1">Volumetria</label>
            <div className="relative">
              <input type="number" value={volume} readOnly className="pl-3 pr-8 py-2 bg-slate-100 text-slate-700 font-bold border border-slate-300 rounded-lg text-sm w-full cursor-not-allowed" />
              <Calculator className="w-4 h-4 text-slate-400 absolute right-2.5 top-2.5" />
            </div>
          </div>
          <div className="w-20">
            <label className="block text-xs font-medium text-slate-500 mb-1">Carretas</label>
            <input type="number" value={trucks} onChange={(e) => setTrucks(Number(e.target.value))} className="px-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <div className="w-24">
            <label className="block text-xs font-medium text-slate-500 mb-1 flex items-center gap-1">
              Diaristas
              <UserPlus className="w-3 h-3 text-emerald-500" />
            </label>
            <input 
              type="number" 
              min="0"
              max="10"
              value={diaristas} 
              onChange={(e) => setDiaristas(Math.max(0, Number(e.target.value)))} 
              className="px-3 py-2 border border-emerald-200 bg-emerald-50 text-emerald-800 font-bold rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-emerald-500" 
            />
          </div>
        </div>
        <div className="flex flex-wrap gap-3 w-full md:w-auto">
           <button 
             onClick={handleSmartSchedule} 
             disabled={processing} 
             className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
           >
            {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
            Distribuir Equipe
          </button>

          <button 
            onClick={handleExportImage}
            disabled={isExporting}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
          >
            {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <ImageDown className="w-4 h-4" />}
            {isExporting ? 'Exportando...' : 'Exportar PNG'}
          </button>

          <button onClick={handleSave} className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm">
            <Save className="w-4 h-4" /> Salvar
          </button>
        </div>
      </div>

      {/* Área Capturável */}
      <div ref={reportRef} data-report-container className="bg-slate-50 p-2 rounded-xl">
        {/* Cabeçalho da Escala */}
        <div className="mb-6 bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
             <div className="bg-indigo-600 p-3 rounded-xl shadow-lg shadow-indigo-200">
                <Share2 className="w-6 h-6 text-white" />
             </div>
             <div>
               <h2 className="text-2xl font-black text-slate-800 tracking-tight">ESCALA OPERACIONAL</h2>
               <p className="text-slate-500 text-sm font-medium flex items-center gap-2 uppercase tracking-widest">
                 <Calendar className="w-3.5 h-3.5" /> 
                 {new Date(date + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' })}
               </p>
             </div>
          </div>
          <div className="flex gap-4">
            <div className="bg-slate-50 px-5 py-3 rounded-lg border border-slate-100 text-center min-w-[120px]">
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mb-1">Volumetria Total</p>
               <p className="text-2xl font-black text-indigo-600 leading-none">{volume || 0}</p>
            </div>
            <div className="bg-slate-50 px-5 py-3 rounded-lg border border-slate-100 text-center min-w-[120px]">
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mb-1">Carretas</p>
               <p className="text-2xl font-black text-slate-700 leading-none">{trucks || 0}</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="space-y-6 lg:col-span-1">
            <div className="bg-white px-4 py-3 rounded-xl border border-slate-200 shadow-sm" data-html2canvas-ignore>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-slate-700">Equipe Alocada</span>
                <span className="text-xs font-bold text-slate-500">{assignedCount} / {activeEmployeesCount}</span>
              </div>
              <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                <div 
                  className={`h-full transition-all duration-500 ${assignedCount >= activeEmployeesCount ? 'bg-green-500' : 'bg-indigo-500'}`} 
                  style={{ width: `${activeEmployeesCount > 0 ? (assignedCount / activeEmployeesCount) * 100 : 0}%` }} 
                />
              </div>
            </div>

            <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl text-[11px] text-amber-800 space-y-2">
              <div className="flex items-center gap-2 font-bold uppercase mb-1">
                <Info className="w-3 h-3" /> Regras Ativas
              </div>
              <ul className="list-disc list-inside space-y-1">
                <li><strong>Diaristas:</strong> Descarga (2) e Ensacamento.</li>
                <li><strong>Gênero:</strong> Tarefas pesadas exclusivas para homens.</li>
                <li><strong>Restrições:</strong> Edina fixa em posto reserva.</li>
                <li><strong>Prioridades:</strong> Alex, Vitória e Sofia no posto reserva.</li>
              </ul>
            </div>

            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex items-center justify-between">
                <h3 className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                  <Container className="w-4 h-4 text-slate-500" /> Detalhe das Viagens
                </h3>
              </div>
              <div className="p-4 space-y-3">
                {trips.length > 0 ? trips.map((trip, idx) => (
                  <div key={idx} className="p-3 rounded-lg border border-slate-100 bg-slate-50/50">
                    <div className="flex gap-2 mb-2 items-center">
                      {isExporting ? (
                        <div className="flex-1 px-3 py-1.5 bg-white border border-slate-200 rounded text-sm font-bold text-slate-800">
                          ID: {trip.id || "---"}
                        </div>
                      ) : (
                        <input type="text" value={trip.id} onChange={(e) => handleTripChange(idx, e.target.value)} placeholder="ID" className="flex-1 px-2 py-1 text-sm border border-slate-300 rounded uppercase font-mono outline-none focus:ring-1 focus:ring-indigo-500 font-bold bg-white" />
                      )}

                      {isExporting ? (
                        <div className="w-20 px-3 py-1.5 bg-white border border-slate-200 rounded text-sm font-bold text-indigo-600 text-center">
                          {trip.volume || 0}
                        </div>
                      ) : (
                        <input type="number" value={trip.volume || ''} onChange={(e) => handleTripVolumeChange(idx, e.target.value)} placeholder="Vol" className="w-20 px-2 py-1 text-sm border border-slate-300 rounded outline-none focus:ring-1 focus:ring-indigo-500 font-bold bg-white" />
                      )}
                    </div>
                    <div className="flex justify-between items-center">
                      <button onClick={() => toggleTripUnsealed(idx)} className={`p-2 rounded border transition-colors ${trip.unsealed ? 'bg-green-100 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                        {trip.unsealed ? <Unlock className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
                      </button>
                      <span className="text-[10px] font-mono text-slate-500 font-medium">
                        {trip.unsealed ? `Deslacre: ${trip.unsealTimestamp}` : 'Aguardando Deslacre'}
                      </span>
                      <button onClick={() => handleRemoveTrip(idx)} className="text-slate-400 hover:text-red-500 transition-colors" data-html2canvas-ignore><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>
                )) : (
                  <p className="text-center py-4 text-xs text-slate-400 italic">Nenhuma viagem registrada</p>
                )}
                {trips.length < 5 && (
                  <button onClick={handleAddTrip} className="w-full py-2 border-dashed border border-indigo-300 text-indigo-600 rounded text-xs font-medium hover:bg-indigo-50 transition-colors" data-html2canvas-ignore>+ Adicionar Viagem</button>
                )}
              </div>
            </div>
          </div>

          <div className="lg:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {TASK_DEFINITIONS.map(task => (
                <AssignmentCard
                  key={task.id}
                  task={task}
                  assignments={assignments}
                  employees={employees}
                  onAssign={handleAssign}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DailyOperations;

import React from 'react';
import { TaskDefinition, Employee, Assignment, TaskCategory } from '../types';
import { User, Package, Truck, Network, Briefcase, UserPlus, X } from 'lucide-react';

interface Props {
  task: TaskDefinition;
  assignments: Assignment[];
  employees: Employee[];
  onAssign: (taskId: string, slotIndex: number, employeeId: string) => void;
}

const AssignmentCard: React.FC<Props> = ({ task, assignments, employees, onAssign }) => {
  const getIcon = (cat: TaskCategory) => {
    switch (cat) {
      case TaskCategory.UNLOAD: return <Truck className="w-5 h-5 text-red-500" />;
      case TaskCategory.TURN: return <Package className="w-5 h-5 text-orange-500" />;
      case TaskCategory.FISHING: return <Network className="w-5 h-5 text-blue-500" />;
      case TaskCategory.BAGGING: return <Briefcase className="w-5 h-5 text-green-500" />;
      case TaskCategory.SOLTO: return <User className="w-5 h-5 text-slate-400" />;
    }
  };

  const currentTaskAssignments = assignments.filter(a => a.taskId === task.id);
  const assignedEmployeeIds = new Set(assignments.map(a => a.employeeId));

  const isSolto = task.category === TaskCategory.SOLTO;

  const maxOccupiedSlot = currentTaskAssignments.length > 0 
    ? Math.max(...currentTaskAssignments.map(a => a.slotIndex)) 
    : -1;

  const displayCapacity = isSolto 
    ? Math.max(currentTaskAssignments.length + 1, 1) 
    : Math.max(task.capacity, maxOccupiedSlot + 1);

  return (
    <div className={`bg-white rounded-lg border shadow-sm hover:shadow-md transition-shadow p-4 ${isSolto ? 'border-slate-300 bg-slate-50/30' : 'border-slate-200'}`}>
      <div className="flex items-start justify-between mb-3">
        <div>
          <div className="flex items-center gap-2">
            {getIcon(task.category)}
            <h3 className="font-bold text-slate-800">{task.name}</h3>
          </div>
          <p className="text-[10px] text-slate-500 mt-0.5 uppercase font-medium tracking-tight">{task.description}</p>
        </div>
        <span className={`text-[10px] font-black px-2 py-0.5 rounded shadow-sm border ${isSolto ? 'bg-slate-200 text-slate-700 border-slate-300' : 'bg-slate-100 text-slate-600 border-slate-200'}`}>
          {currentTaskAssignments.length} {isSolto ? 'ALOCADOS' : `/ ${task.capacity}`}
        </span>
      </div>

      <div className="space-y-2">
        {Array.from({ length: displayCapacity }).map((_, idx) => {
          const assignment = currentTaskAssignments.find(a => a.slotIndex === idx);
          const isDiarista = assignment?.employeeId === 'diarista-id';
          const isExtraSlot = !isSolto && idx >= task.capacity;
          const employee = assignment ? employees.find(e => e.id === assignment.employeeId) : null;

          return (
            <div key={`${task.id}-${idx}`} className="relative h-9">
              {isDiarista ? (
                <div className={`w-full h-full flex items-center justify-between gap-2 px-3 border rounded text-xs font-black ${isExtraSlot ? 'bg-emerald-100 border-emerald-400 text-emerald-900' : 'bg-emerald-50 border-emerald-300 text-emerald-800'}`}>
                  <div className="flex items-center gap-2">
                    <UserPlus className="w-3.5 h-3.5 text-emerald-600" />
                    <span>DIARISTA {isExtraSlot ? '(EXTRA)' : ''}</span>
                  </div>
                  <button 
                    onClick={() => onAssign(task.id, idx, "")}
                    className="text-emerald-400 hover:text-emerald-600 transition-colors"
                    data-html2canvas-ignore
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              ) : assignment ? (
                <div className="w-full h-full flex items-center justify-between gap-2 px-3 border border-indigo-300 bg-indigo-50/80 text-slate-900 font-bold rounded text-xs transition-all relative">
                  <div className="flex items-center gap-2 overflow-hidden">
                    <div className={`w-2 h-2 rounded-full flex-shrink-0 ${employee?.gender === 'M' ? 'bg-blue-500 shadow-[0_0_4px_rgba(59,130,246,0.5)]' : 'bg-pink-500 shadow-[0_0_4px_rgba(236,72,153,0.5)]'}`} />
                    <span className="whitespace-nowrap">{employee?.name || "Desconhecido"}</span>
                  </div>
                  <button 
                    onClick={() => onAssign(task.id, idx, "")}
                    className="text-indigo-300 hover:text-indigo-600 transition-colors bg-white/50 rounded-full p-0.5 ml-1"
                    data-html2canvas-ignore
                  >
                    <X className="w-3.5 h-3.5" />
                  </button>
                </div>
              ) : (
                <select
                  className="w-full h-full text-xs px-2 rounded border border-slate-200 bg-white text-slate-400 italic focus:outline-none focus:ring-2 focus:ring-indigo-500 appearance-none shadow-inner"
                  value=""
                  onChange={(e) => onAssign(task.id, idx, e.target.value)}
                >
                  <option value="">-- Selecionar --</option>
                  <option value="diarista-id">+ DIARISTA</option>
                  {employees
                    .filter(e => !assignedEmployeeIds.has(e.id) && e.active)
                    .sort((a, b) => a.name.localeCompare(b.name))
                    .map(e => (
                      <option key={e.id} value={e.id}>
                        {e.name} ({e.gender})
                      </option>
                    ))}
                </select>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default AssignmentCard;

import React, { useState, useEffect, useRef } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Calendar, Unlock, Lock, Container, Trash2, Calculator, RefreshCw, Info, Loader2, UserPlus, ImageDown, Share2 } from 'lucide-react';
import { calculateAutoRotation } from '../services/rotationService';
import html2canvas from 'html2canvas';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [diaristas, setDiaristas] = useState<number>(0);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [processing, setProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setDiaristas(existing.diaristaCount || 0);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setDiaristas(0);
      setAssignments([]);
      setTrips([]);
    }
  }, [date, history]);

  useEffect(() => {
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    } else if (trips.length === 0 && !history.find(h => h.date === date)?.volume) {
       setVolume('');
    }
  }, [trips, date, history]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;

      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);
      return [...withoutEmployee, { taskId, employeeId, slotIndex, isManual: true }];
    });
  };

  const handleSmartSchedule = () => {
    setProcessing(true);
    setTimeout(() => {
      try {
        const newAssignments = calculateAutoRotation(employees, history, assignments, diaristas);
        setAssignments(newAssignments);
      } catch (e) {
        alert("Erro ao calcular escala.");
      } finally {
        setProcessing(false);
      }
    }, 300);
  };

  const handleSave = () => {
    const cleanTrips = trips.filter(t => t.id.trim() !== '');
    const calculatedVolume = cleanTrips.reduce((acc, t) => acc + (t.volume || 0), 0);
    const record: DailyRecord = {
      id: date,
      date,
      volume: calculatedVolume,
      trucks: Number(trucks) || 0,
      diaristaCount: diaristas,
      assignments,
      trips: cleanTrips
    };
    onSaveRecord(record);
    alert("Dados salvos com sucesso!");
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;

    setIsExporting(true);
    // Delay maior para garantir que o DOM renderize os estados de texto puro
    await new Promise(resolve => setTimeout(resolve, 500));

    try {
      const canvas = await html2canvas(reportRef.current, {
        backgroundColor: '#f8fafc',
        scale: 3, // Qualidade Ultra (3x)
        logging: false,
        useCORS: true,
        allowTaint: true,
        windowWidth: 1200, // Força uma largura estável para o cálculo de layout
        onclone: (clonedDoc) => {
          const container = clonedDoc.querySelector('[data-report-container]') as HTMLElement;
          if (container) {
            container.style.width = '1200px';
            container.style.padding = '30px';
          }
        }
      });

      const image = canvas.toDataURL("image/png", 1.0);
      const link = document.createElement('a');
      const [year, month, day] = date.split('-');
      link.download = `Escala_Equipe_${day}_${month}_${year}.png`;
      link.href = image;
      link.click();
    } catch (err) {
      console.error("Erro na exportação:", err);
      alert("Erro ao gerar imagem.");
    } finally {
      setIsExporting(false);
    }
  };

  const handleAddTrip = () => trips.length < 5 && setTrips(prev => [...prev, { id: '', unsealed: false }]);
  const handleRemoveTrip = (idx: number) => setTrips(prev => prev.filter((_, i) => i !== idx));
  const handleTripChange = (idx: number, val: string) => {
    const formattedValue = val.toUpperCase().slice(0, 15);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], id: formattedValue };
      return next;
    });
  };
  const handleTripVolumeChange = (idx: number, val: string) => {
    const num = val === '' ? undefined : Number(val);
    setTrips(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], volume: num };
      return next;
    });
  };
  const toggleTripUnsealed = (idx: number) => {
    const next = [...trips];
    const isNowUnsealed = !next[idx].unsealed;
    const now = new Date();
    next[idx] = { 
      ...next[idx], 
      unsealed: isNowUnsealed,
      unsealTimestamp: isNowUnsealed ? now.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }) : undefined,
      unsealTimeISO: isNowUnsealed ? now.toISOString() : undefined
    };
    setTrips(next);
  };

  const activeEmployeesCount = employees.filter(e => e.active).length;
  const assignedCount = assignments.filter(a => a.employeeId !== 'diarista-id').length;

  return (
    <div className="space-y-6">
      {/* Botões Superiores - Ocultos na exportação */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 justify-between items-end" data-html2canvas-ignore>
        <div className="flex flex-wrap gap-4 items-end w-full md:w-auto">
          <div className="min-w-[140px]">
            <label className="block text-xs font-medium text-slate-500 mb-1">Data da Escala</label>
            <div className="relative">
              <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
              <Calendar className="w-4 h-4 text-slate-400 absolute left-3 top-2.5" />
            </div>
          </div>
          <div className="w-20">
            <label className="block text-xs font-medium text-slate-500 mb-1">Carretas</label>
            <input type="number" value={trucks} onChange={(e) => setTrucks(Number(e.target.value))} className="px-3 py-2 border border-slate-300 rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-indigo-500" />
          </div>
          <div className="w-24">
            <label className="block text-xs font-medium text-slate-500 mb-1 flex items-center gap-1">
              Diaristas
              <UserPlus className="w-3 h-3 text-emerald-500" />
            </label>
            <input 
              type="number" 
              min="0"
              max="10"
              value={diaristas} 
              onChange={(e) => setDiaristas(Math.max(0, Number(e.target.value)))} 
              className="px-3 py-2 border border-emerald-200 bg-emerald-50 text-emerald-800 font-bold rounded-lg text-sm w-full outline-none focus:ring-2 focus:ring-emerald-500" 
            />
          </div>
        </div>
        <div className="flex flex-wrap gap-3 w-full md:w-auto">
           <button 
             onClick={handleSmartSchedule} 
             disabled={processing} 
             className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
           >
            {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
            Distribuir Equipe
          </button>

          <button 
            onClick={handleExportImage}
            disabled={isExporting}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
          >
            {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <ImageDown className="w-4 h-4" />}
            {isExporting ? 'Processando...' : 'Exportar PNG'}
          </button>

          <button onClick={handleSave} className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm">
            <Save className="w-4 h-4" /> Salvar
          </button>
        </div>
      </div>

      {/* ÁREA DE CAPTURA */}
      <div ref={reportRef} data-report-container className="bg-slate-50 p-2 rounded-xl">
        {/* Cabeçalho Visual da Imagem */}
        <div className="mb-6 bg-white p-6 rounded-xl border-2 border-slate-200 shadow-md flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-5">
             <div className="bg-indigo-600 p-4 rounded-2xl shadow-lg shadow-indigo-100">
                <Share2 className="w-8 h-8 text-white" />
             </div>
             <div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tighter leading-none">ESCALA OPERACIONAL</h2>
               <p className="text-indigo-600 text-sm font-bold flex items-center gap-2 uppercase tracking-widest mt-2">
                 <Calendar className="w-4 h-4" /> 
                 {new Date(date + 'T12:00:00').toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' })}
               </p>
             </div>
          </div>
          <div className="flex gap-4">
            <div className="bg-slate-900 px-6 py-3 rounded-xl text-center min-w-[140px] shadow-lg">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Volumetria</p>
               <p className="text-3xl font-black text-white leading-none">{volume || 0}</p>
            </div>
            <div className="bg-white px-6 py-3 rounded-xl border-2 border-slate-100 text-center min-w-[140px] shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Carretas</p>
               <p className="text-3xl font-black text-slate-800 leading-none">{trucks || 0}</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="space-y-6 lg:col-span-1">
            <div className="bg-white px-5 py-4 rounded-xl border border-slate-200 shadow-sm" data-html2canvas-ignore>
              <div className="flex justify-between items-center mb-3">
                <span className="text-xs font-bold text-slate-600 uppercase">Equipe Alocada</span>
                <span className="text-xs font-black text-indigo-600">{assignedCount} / {activeEmployeesCount}</span>
              </div>
              <div className="h-3 w-full bg-slate-100 rounded-full overflow-hidden border border-slate-200">
                <div 
                  className={`h-full transition-all duration-700 ${assignedCount >= activeEmployeesCount ? 'bg-emerald-500' : 'bg-indigo-600'}`} 
                  style={{ width: `${activeEmployeesCount > 0 ? (assignedCount / activeEmployeesCount) * 100 : 0}%` }} 
                />
              </div>
            </div>

            <div className="bg-amber-50 border-l-4 border-amber-400 p-5 rounded-r-xl shadow-sm space-y-3">
              <div className="flex items-center gap-2 font-black text-amber-800 uppercase text-xs">
                <Info className="w-4 h-4" /> Regras da Escala
              </div>
              <ul className="text-[11px] text-amber-900 font-medium space-y-1.5 list-disc list-inside">
                <li>Diaristas: Descarga (2) e Ensacamento.</li>
                <li>Gênero: Cargas pesadas exclusivas Masculinas.</li>
                <li>Restrições: Edina fixa no posto reserva.</li>
                <li>Prioridades: Alex, Vitória e Sofia (Reserva).</li>
              </ul>
            </div>

            <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
              <div className="bg-slate-900 px-4 py-3 flex items-center justify-between">
                <h3 className="text-xs font-black text-white uppercase tracking-widest flex items-center gap-2">
                  <Container className="w-4 h-4 text-indigo-400" /> Detalhes da Viagem
                </h3>
              </div>
              <div className="p-4 space-y-3">
                {trips.length > 0 ? trips.map((trip, idx) => (
                  <div key={idx} className="p-3 rounded-lg border border-slate-200 bg-white">
                    <div className="flex gap-2 mb-2 items-center">
                      {isExporting ? (
                        <div className="flex-1 px-3 py-1.5 bg-slate-50 border border-slate-200 rounded text-xs font-black text-slate-800 uppercase">
                          ID: {trip.id || "---"}
                        </div>
                      ) : (
                        <input type="text" value={trip.id} onChange={(e) => handleTripChange(idx, e.target.value)} placeholder="ID VIAGEM" className="flex-1 px-2 py-1.5 text-xs border border-slate-300 rounded uppercase font-bold outline-none focus:ring-2 focus:ring-indigo-500 bg-white" />
                      )}

                      {isExporting ? (
                        <div className="w-24 px-3 py-1.5 bg-indigo-50 border border-indigo-200 rounded text-xs font-black text-indigo-700 text-center">
                          {trip.volume || 0}
                        </div>
                      ) : (
                        <input type="number" value={trip.volume || ''} onChange={(e) => handleTripVolumeChange(idx, e.target.value)} placeholder="VOL" className="w-20 px-2 py-1.5 text-xs border border-slate-300 rounded outline-none focus:ring-2 focus:ring-indigo-500 font-bold bg-white text-center" />
                      )}
                    </div>
                    <div className="flex justify-between items-center mt-1">
                      <div className={`px-2 py-1 rounded text-[10px] font-black uppercase flex items-center gap-1 ${trip.unsealed ? 'bg-emerald-100 text-emerald-700' : 'bg-red-50 text-red-600'}`}>
                        {trip.unsealed ? <Unlock className="w-3 h-3" /> : <Lock className="w-3 h-3" />}
                        {trip.unsealed ? 'Deslacrado' : 'Lacrado'}
                      </div>
                      <span className="text-[9px] font-bold text-slate-400 uppercase">
                        {trip.unsealed ? `${trip.unsealTimestamp}` : 'Pendente'}
                      </span>
                      {!isExporting && (
                        <button onClick={() => handleRemoveTrip(idx)} className="text-slate-300 hover:text-red-500 transition-colors ml-2" data-html2canvas-ignore><Trash2 className="w-3.5 h-3.5" /></button>
                      )}
                    </div>
                  </div>
                )) : (
                  <p className="text-center py-6 text-[10px] text-slate-400 font-bold uppercase italic tracking-widest">Nenhuma viagem ativa</p>
                )}
                {!isExporting && trips.length < 5 && (
                  <button onClick={handleAddTrip} className="w-full py-2 border-2 border-dashed border-indigo-200 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 transition-colors" data-html2canvas-ignore>+ Viagem</button>
                )}
              </div>
            </div>
          </div>

          <div className="lg:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              {TASK_DEFINITIONS.map(task => (
                <AssignmentCard
                  key={task.id}
                  task={task}
                  assignments={assignments}
                  employees={employees}
                  onAssign={handleAssign}
                />
              ))}
            </div>
          </div>
        </div>

        {/* Rodapé da Imagem (Somente Exportação) */}
        <div className="mt-8 pt-4 border-t border-slate-200 flex justify-between items-center px-4">
           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">LogiTeam Manager &copy; 2025</span>
           <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">Relatório Operacional Oficial</span>
        </div>
      </div>
    </div>
  );
};

export default DailyOperations;

import React from 'react';
import { TaskDefinition, Employee, Assignment, TaskCategory } from '../types';
import { User, Package, Truck, Network, Briefcase, UserPlus, X } from 'lucide-react';

interface Props {
  task: TaskDefinition;
  assignments: Assignment[];
  employees: Employee[];
  onAssign: (taskId: string, slotIndex: number, employeeId: string) => void;
}

const AssignmentCard: React.FC<Props> = ({ task, assignments, employees, onAssign }) => {
  const getIcon = (cat: TaskCategory) => {
    switch (cat) {
      case TaskCategory.UNLOAD: return <Truck className="w-4 h-4 text-rose-500" />;
      case TaskCategory.TURN: return <Package className="w-4 h-4 text-orange-500" />;
      case TaskCategory.FISHING: return <Network className="w-4 h-4 text-blue-500" />;
      case TaskCategory.BAGGING: return <Briefcase className="w-4 h-4 text-emerald-500" />;
      case TaskCategory.SOLTO: return <User className="w-4 h-4 text-slate-400" />;
    }
  };

  const currentTaskAssignments = assignments.filter(a => a.taskId === task.id);
  const assignedEmployeeIds = new Set(assignments.map(a => a.employeeId));
  const isSolto = task.category === TaskCategory.SOLTO;

  const maxOccupiedSlot = currentTaskAssignments.length > 0 
    ? Math.max(...currentTaskAssignments.map(a => a.slotIndex)) 
    : -1;

  const displayCapacity = isSolto 
    ? Math.max(currentTaskAssignments.length + 1, 1) 
    : Math.max(task.capacity, maxOccupiedSlot + 1);

  return (
    <div className={`bg-white rounded-xl border border-slate-200 shadow-sm p-4 flex flex-col ${isSolto ? 'bg-slate-50/50' : ''}`}>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2.5">
          <div className="p-2 bg-slate-100 rounded-lg">
            {getIcon(task.category)}
          </div>
          <div>
            <h3 className="text-sm font-bold text-slate-900 leading-none">{task.name}</h3>
            <p className="text-[10px] text-slate-500 mt-1 font-medium">{task.description}</p>
          </div>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
            {currentTaskAssignments.length} / {isSolto ? '∞' : task.capacity}
          </span>
        </div>
      </div>

      <div className="space-y-1.5">
        {Array.from({ length: displayCapacity }).map((_, idx) => {
          const assignment = currentTaskAssignments.find(a => a.slotIndex === idx);
          const isDiarista = assignment?.employeeId === 'diarista-id';
          const employee = assignment ? employees.find(e => e.id === assignment.employeeId) : null;

          return (
