import { Employee, TaskDefinition, DailyRecord, Assignment, TaskCategory } from '../types';
import { TASK_DEFINITIONS } from '../constants';

/**
 * Algoritmo de Escalonamento Automático LogiTeam v2.0
 * 
 * PRIORIDADES PARA FICAR SOLTO (RESERVA):
 * 1. EDINA: Fixa (Nunca sai do Solto)
 * 2. ALEX: Prioridade Máxima (Só sai do Solto se não houver MAIS NINGUÉM disponível)
 * 3. VITÓRIA / SOFIA: Prioridade Alta (Só saem do Solto se os funcionários padrão acabarem)
 */
export const calculateAutoRotation = (
  employees: Employee[],
  history: DailyRecord[],
  currentAssignments: Assignment[],
  diaristaCount: number = 0,
  volume: number = 0
): Assignment[] => {
  const activeEmployees = employees.filter(e => e.active);
  const manualAssignments = currentAssignments.filter(a => a.isManual);
  const manualEmployeeIds = new Set(manualAssignments.map(a => a.employeeId));

  // Pool de funcionários disponíveis (sem os manuais)
  let availablePool = activeEmployees.filter(e => !manualEmployeeIds.has(e.id));

  const normalize = (name: string) => 
    name.trim()
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

  // Regra de Elite para Virada (Volume Alto)
  const eliteTurnTeam = ['gabriel', 'cleverton', 'jamisson', 'robson', 'ryan', 'pedro'];
  const isHighVolume = volume > 12000;

  // 1. Identificar e Separar Grupos de Prioridade
  const edina = availablePool.find(e => normalize(e.name) === 'edina');
  if (edina) availablePool = availablePool.filter(e => e.id !== edina.id);

  const p1Names = ['alex'];
  const poolP1 = availablePool.filter(e => p1Names.includes(normalize(e.name)));

  const p2Names = ['vitoria', 'sofia'];
  const poolP2 = availablePool.filter(e => p2Names.includes(normalize(e.name)));

  // O pool padrão são todos que não são P1 nem P2
  let standardPool = availablePool.filter(e => 
    !p1Names.includes(normalize(e.name)) && 
    !p2Names.includes(normalize(e.name))
  );

  const newAssignments: Assignment[] = [...manualAssignments];
  let diaristasRemaining = diaristaCount;

  // --- REGRA DE DIARISTAS (Prioridade Total em Descarga e Ensacar) ---
  const unloadTask = TASK_DEFINITIONS.find(t => t.id === 'task-unload');
  if (unloadTask) {
    for (let i = 0; i < unloadTask.capacity; i++) {
      const isOccupied = newAssignments.some(a => a.taskId === unloadTask.id && a.slotIndex === i);
      if (!isOccupied && diaristasRemaining > 0) {
        newAssignments.push({ taskId: unloadTask.id, slotIndex: i, employeeId: 'diarista-id', isManual: false });
        diaristasRemaining--;
      }
    }
  }

  const baggingTask = TASK_DEFINITIONS.find(t => t.id === 'task-bagging');
  if (baggingTask && diaristasRemaining > 0) {
    let slotIdx = 0;
    while (diaristasRemaining > 0) {
      const isOccupied = newAssignments.some(a => a.taskId === baggingTask.id && a.slotIndex === slotIdx);
      if (!isOccupied) {
        newAssignments.push({ taskId: baggingTask.id, slotIndex: slotIdx, employeeId: 'diarista-id', isManual: false });
        diaristasRemaining--;
      }
      slotIdx++;
    }
  }

  // --- DEFINIÇÃO DE SLOTS OBRIGATÓRIOS (EXCETO SOLTO) ---
  const taskSlots: { taskId: string; slotIndex: number; category: TaskCategory; priority: number }[] = [];
  TASK_DEFINITIONS.forEach(task => {
    if (task.category !== TaskCategory.SOLTO) {
      for (let i = 0; i < task.capacity; i++) {
        const isOccupied = newAssignments.some(a => a.taskId === task.id && a.slotIndex === i);
        if (!isOccupied) {
          // Virada e Descarga são prioridades máximas de preenchimento
          let priority = 3;
          if (task.category === TaskCategory.TURN) priority = 1; 
          else if (task.category === TaskCategory.UNLOAD) priority = 2;
          taskSlots.push({ taskId: task.id, slotIndex: i, category: task.category, priority });
        }
      }
    }
  });

  // Ordenar slots por criticidade (Virada > Descarga > Outros)
  taskSlots.sort((a, b) => a.priority - b.priority);

  const getTaskHistoryScore = (employeeId: string, taskId: string): number => {
    const sortedHistory = [...history].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    for (let i = 0; i < sortedHistory.length; i++) {
      if (sortedHistory[i].assignments.some(a => a.employeeId === employeeId && a.taskId === taskId)) {
        return i;
      }
    }
    return 999;
  };

  // Preencher slots seguindo a hierarquia de disponibilidade
  taskSlots.forEach(slot => {
    // Ordem de preferência de quem vai TRABALHAR na tarefa:
    // 1. Standard (Geral)
    // 2. Pool P2 (Vitória/Sofia) - Só se Standard acabar
    // 3. Pool P1 (Alex) - Só se TUDO acabar

    const priorityBuckets = [standardPool, poolP2, poolP1];
    let chosen: Employee | null = null;

    for (const bucket of priorityBuckets) {
      let candidates = bucket.filter(emp => {
        // Restrição de Gênero para Descarga e Virada
        if ((slot.category === TaskCategory.TURN || slot.category === TaskCategory.UNLOAD) && emp.gender === 'F') return false;

        // Regra de Elite para Virada se Volume > 12000
        if (isHighVolume && slot.category === TaskCategory.TURN) {
          return eliteTurnTeam.includes(normalize(emp.name));
        }

        return true;
      });

      if (candidates.length > 0) {
        // Rotacionar baseado no histórico (quem não fez essa tarefa há mais tempo)
        candidates.sort((a, b) => getTaskHistoryScore(b.id, slot.taskId) - getTaskHistoryScore(a.id, slot.taskId));
        chosen = candidates[0];
        break; 
      }
    }

    if (chosen) {
      newAssignments.push({ taskId: slot.taskId, slotIndex: slot.slotIndex, employeeId: chosen.id, isManual: false });

      // Remover dos pools para não duplicar
      const id = chosen.id;
      standardPool = standardPool.filter(e => e.id !== id);
      const idxP2 = poolP2.findIndex(e => e.id === id);
      if (idxP2 > -1) poolP2.splice(idxP2, 1);
      const idxP1 = poolP1.findIndex(e => e.id === id);
      if (idxP1 > -1) poolP1.splice(idxP1, 1);
    }
  });

  // --- TUDO O QUE SOBROU VAI PARA O SOLTO ---
  const soltoTask = TASK_DEFINITIONS.find(t => t.category === TaskCategory.SOLTO);
  if (soltoTask) {
    // Edina entra aqui primeiro por ser fixa
    const leftovers = [];
    if (edina) leftovers.push(edina);
    leftovers.push(...poolP1, ...poolP2, ...standardPool);

    leftovers.forEach((emp) => {
      let slotIdx = 0;
      while (newAssignments.some(a => a.taskId === soltoTask.id && a.slotIndex === slotIdx)) slotIdx++;
      newAssignments.push({ taskId: soltoTask.id, slotIndex: slotIdx, employeeId: emp.id, isManual: false });
    });
  }

  return newAssignments;
};

import React, { useState, useEffect, useRef } from 'react';
import { DailyRecord, Employee, TaskDefinition, Assignment, TripInfo } from '../types';
import { TASK_DEFINITIONS } from '../constants';
import AssignmentCard from './AssignmentCard';
import { Save, Calendar, Unlock, Lock, Container, Trash2, Calculator, RefreshCw, Info, Loader2, UserPlus, ImageDown, Share2, Plus } from 'lucide-react';
import { calculateAutoRotation } from '../services/rotationService';
import html2canvas from 'html2canvas';

interface Props {
  employees: Employee[];
  history: DailyRecord[];
  onSaveRecord: (record: DailyRecord) => void;
}

const DailyOperations: React.FC<Props> = ({ employees, history, onSaveRecord }) => {
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [volume, setVolume] = useState<number | ''>('');
  const [trucks, setTrucks] = useState<number | ''>('');
  const [diaristas, setDiaristas] = useState<number>(0);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [trips, setTrips] = useState<TripInfo[]>([]);
  const [processing, setProcessing] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const reportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const existing = history.find(h => h.date === date);
    if (existing) {
      setVolume(existing.volume);
      setTrucks(existing.trucks);
      setDiaristas(existing.diaristaCount || 0);
      setAssignments(existing.assignments);
      setTrips(existing.trips || []);
    } else {
      setVolume('');
      setTrucks('');
      setDiaristas(0);
      setAssignments([]);
      setTrips([]);
    }
  }, [date, history]);

  useEffect(() => {
    if (trips.length > 0) {
      const total = trips.reduce((acc, trip) => acc + (trip.volume || 0), 0);
      setVolume(total > 0 ? total : '');
    }
  }, [trips]);

  const handleAssign = (taskId: string, slotIndex: number, employeeId: string) => {
    setAssignments(prev => {
      const filtered = prev.filter(a => !(a.taskId === taskId && a.slotIndex === slotIndex));
      if (!employeeId) return filtered;
      const withoutEmployee = filtered.filter(a => a.employeeId !== employeeId);
      return [...withoutEmployee, { taskId, employeeId, slotIndex, isManual: true }];
    });
  };

  const handleSmartSchedule = () => {
    setProcessing(true);
    setTimeout(() => {
      try {
        const currentVolume = Number(volume) || 0;
        const newAssignments = calculateAutoRotation(employees, history, assignments, diaristas, currentVolume);
        setAssignments(newAssignments);
      } finally {
        setProcessing(false);
      }
    }, 400);
  };

  const handleSave = () => {
    const record: DailyRecord = {
      id: date,
      date,
      volume: Number(volume) || 0,
      trucks: Number(trucks) || 0,
      diaristaCount: diaristas,
      assignments,
      trips: trips.filter(t => t.id.trim() !== '')
    };
    onSaveRecord(record);
    alert("Dados salvos com sucesso!");
  };

  const handleExportImage = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);
    await new Promise(r => setTimeout(r, 600));

    try {
      const canvas = await html2canvas(reportRef.current, {
        backgroundColor: '#ffffff',
        scale: 2.5,
        logging: false,
        useCORS: true,
        windowWidth: 1200,
        onclone: (clonedDoc) => {
           const container = clonedDoc.querySelector('[data-report-container]') as HTMLElement;
           if (container) {
             container.style.width = '1200px';
             container.style.padding = '40px';
           }
        }
      });

      const image = canvas.toDataURL("image/png", 1.0);
      const link = document.createElement('a');
      const [y, m, d] = date.split('-');
      link.download = `ESCALA_${d}_${m}_${y}.png`;
      link.href = image;
      link.click();
    } finally {
      setIsExporting(false);
    }
  };

  const handleAddTrip = () => setTrips(prev => [...prev, { id: '', unsealed: false }]);
  const handleRemoveTrip = (idx: number) => setTrips(prev => prev.filter((_, i) => i !== idx));

  const handleTripChange = (idx: number, id: string) => {
    const next = [...trips];
    next[idx] = { ...next[idx], id: id.toUpperCase() };
    setTrips(next);
  };

  const handleTripVolumeChange = (idx: number, vol: string) => {
    const next = [...trips];
    next[idx] = { ...next[idx], volume: vol === '' ? undefined : Number(vol) };
    setTrips(next);
  };

  const toggleUnseal = (idx: number) => {
    const next = [...trips];
    const isUnsealing = !next[idx].unsealed;
    const now = new Date();
    next[idx] = { 
      ...next[idx], 
      unsealed: isUnsealing,
      unsealTimestamp: isUnsealing ? now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) : undefined
    };
    setTrips(next);
  };

  const activeEmployeesCount = employees.filter(e => e.active).length;
  const assignedCount = assignments.filter(a => a.employeeId !== 'diarista-id').length;

  return (
    <div className="space-y-6">
      {/* Menu Superior - Oculto no PNG */}
      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex flex-wrap gap-4 items-end justify-between" data-html2canvas-ignore>
        <div className="flex flex-wrap gap-4">
          <div className="w-40">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Data Operação</label>
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500/20" />
          </div>
          <div className="w-24">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Diaristas</label>
            <input type="number" min="0" value={diaristas} onChange={(e) => setDiaristas(Number(e.target.value))} className="w-full px-3 py-2 border border-emerald-200 bg-emerald-50 rounded-xl text-sm font-black text-emerald-700" />
          </div>
          <div className="w-24">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Carretas</label>
            <input type="number" min="0" value={trucks} onChange={(e) => setTrucks(Number(e.target.value))} className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm font-bold" />
          </div>
        </div>

        <div className="flex gap-2">
          <button onClick={handleSmartSchedule} disabled={processing} className="flex items-center gap-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl text-sm font-black hover:bg-indigo-700 transition-all disabled:opacity-50">
            {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
            DISTRIBUIR
          </button>
          <button onClick={handleExportImage} disabled={isExporting} className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-xl text-sm font-black hover:bg-black transition-all">
            {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <ImageDown className="w-4 h-4" />}
            PNG
          </button>
          <button onClick={handleSave} className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl text-sm font-black hover:bg-blue-700 transition-all">
            <Save className="w-4 h-4" /> SALVAR
          </button>
        </div>
      </div>

      {/* ÁREA DE CAPTURA (PNG) */}
