                      </div>
                      {!isExporting && (
                        <button onClick={() => handleRemoveTrip(idx)} className="text-slate-300 hover:text-red-500 p-1" data-html2canvas-ignore>
                          <Trash2 className="w-4 h-4" />
                        </button>
                      )}
                    </div>
