              </div>
            </div>
          </div>

          {/* Grid de Tarefas */}
          <div className="col-span-8">
            <div className="grid grid-cols-2 gap-5">
              {TASK_DEFINITIONS.map(task => (
                <AssignmentCard
                  key={task.id}
                  task={task}
                  assignments={assignments}
                  employees={employees}
                  onAssign={handleAssign}
                />
