  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadBatches();
  }, []);

  const loadBatches = async () => {
    setLoading(true);
    try {
      const data = await dataService.getBatchNumbers();
      setBatches(data);
    } catch (error) {
      console.error("Erro ao carregar lotes:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleAddBatch = async () => {
    if (!newNumber.trim()) return;
    setProcessing(true);
    try {
      const batch: BatchNumber = {
        id: `batch-${Date.now()}`,
        number: newNumber.trim().toUpperCase(),
        description: newDesc.trim(),
        created_at: new Date().toISOString()
      };
      await dataService.saveBatchNumber(batch);
      await loadBatches();
      setShowAddModal(false);
      setNewNumber('');
      setNewDesc('');
    } catch (error) {
      alert("Erro ao salvar lote.");
    } finally {
      setProcessing(false);
    }
  };

  const handleDelete = async () => {
    if (!itemToDelete) return;
    setProcessing(true);
    try {
      await dataService.deleteBatchNumber(itemToDelete.id);
      await loadBatches();
      setItemToDelete(null);
    } catch (error) {
      alert("Erro ao excluir lote.");
    } finally {
      setProcessing(false);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setProcessing(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { header: 1 });

        const newBatches: BatchNumber[] = [];
        jsonData.forEach((row: any, index: number) => {
          if (row && row[0]) {
            const val = String(row[0]).trim().toUpperCase();
            if (val && !['LOTE', 'CÓDIGO', 'ID'].includes(val)) {
              newBatches.push({
                id: `batch-${Date.now()}-${index}`,
                number: val,
                description: 'Importação Massiva',
                created_at: new Date().toISOString()
              });
            }
          }
        });

        if (newBatches.length > 0) {
          // Processar um por um ou via Promise.all (Supabase upsert individual aqui)
          await Promise.all(newBatches.map(b => dataService.saveBatchNumber(b)));
          await loadBatches();
          alert(`${newBatches.length} lotes importados com sucesso!`);
        }
      } catch (error) {
        alert("Erro ao processar planilha.");
      } finally {
        setProcessing(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const filteredBatches = batches.filter(b => 
    b.number.toLowerCase().includes(searchTerm.toLowerCase()) ||
    b.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10">
      {/* Header */}
      <div className="bg-slate-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1580674285054-bed31e145f59?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <Hash className="w-8 h-8 text-indigo-400" />
          Gerenciamento de Lotes
        </h2>
        <p className="text-slate-300 max-w-xl">
          Visualize, cadastre e gerencie os números de lotes da operação logística.
        </p>
      </div>

      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
        {/* Toolbar */}
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
          <div className="relative w-full md:w-96">
            <input 
              type="text" 
              placeholder="Buscar lote por número..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
