import React, { useState, useEffect, useRef } from 'react';
import { Hash, Search, Plus, Trash2, Upload, FileSpreadsheet, Loader2, AlertTriangle, CheckCircle2, RefreshCw, BarChart2, PackageCheck, Info } from 'lucide-react';
import { BatchNumber } from '../types';
import { dataService } from '../services/dataService';
import * as XLSX from 'xlsx';

interface AnalysisResult {
  base: string;
  orderCount: number;
  batchesNeeded: number;
}

const BatchNumbers: React.FC = () => {
  const [batches, setBatches] = useState<BatchNumber[]>([]);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Estados para Análise de Planilha
  const [analysisResults, setAnalysisResults] = useState<AnalysisResult[]>([]);
  const [totalValidOrders, setTotalValidOrders] = useState(0);
  const [showAnalysis, setShowAnalysis] = useState(false);

  const [showAddModal, setShowAddModal] = useState(false);
  const [newNumber, setNewNumber] = useState('');
  const [newDesc, setNewDesc] = useState('');

  const [itemToDelete, setItemToDelete] = useState<BatchNumber | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadBatches();
  }, []);

  const loadBatches = async () => {
    setLoading(true);
    try {
      const data = await dataService.getBatchNumbers();
      setBatches(data);
    } catch (error) {
      console.error("Erro ao carregar lotes:", error);
    } finally {
      setLoading(false);
    }
  };

  const cleanValue = (val: any): string => {
    if (val === null || val === undefined) return '';
    return String(val).trim().toUpperCase();
  };

  const findColumn = (row: any, candidates: string[]): string => {
    if (!row) return '';
    const keys = Object.keys(row);
    for (const key of keys) {
      if (candidates.some(c => key.toLowerCase().includes(c))) {
        return key;
      }
    }
    return '';
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setProcessing(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { defval: "" });

        if (jsonData.length === 0) {
          alert("Planilha vazia.");
          return;
        }

        // Identificar Colunas
        const colOrder = findColumn(jsonData[0], ['número de pedido jms', 'numero de pedido jms', 'pedido', 'order id', 'jms']);
        const colBase = findColumn(jsonData[0], ['parada anterior ou próxima', 'parada anterior ou proxima', 'base', 'destino', 'parada']);

        if (!colOrder || !colBase) {
          alert("Não foi possível identificar as colunas de 'Pedido' ou 'Base' na planilha.");
          return;
        }

        const baseCounts: Record<string, number> = {};
        let validTotal = 0;

        jsonData.forEach(row => {
          const orderId = cleanValue(row[colOrder]);
          const baseName = cleanValue(row[colBase]) || 'INDEFINIDO';

          // Regra: Desconsiderar pedidos filhos (contém hífen)
          if (orderId && !orderId.includes('-') && !orderId.startsWith('BR')) {
            validTotal++;
            baseCounts[baseName] = (baseCounts[baseName] || 0) + 1;
          }
        });

        // Formatar resultados e calcular lotes (Limite de 80 por lote)
        const results: AnalysisResult[] = Object.entries(baseCounts).map(([base, count]) => ({
          base,
          orderCount: count,
          batchesNeeded: Math.ceil(count / 80)
        })).sort((a, b) => b.orderCount - a.orderCount);

        setTotalValidOrders(validTotal);
        setAnalysisResults(results);
        setShowAnalysis(true);

      } catch (error) {
        console.error(error);
        alert("Erro ao processar planilha.");
      } finally {
        setProcessing(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleAddBatch = async () => {
    if (!newNumber.trim()) return;
    setProcessing(true);
    try {
      const batch: BatchNumber = {
        id: `batch-${Date.now()}`,
        number: newNumber.trim().toUpperCase(),
        description: newDesc.trim(),
        created_at: new Date().toISOString()
      };
      await dataService.saveBatchNumber(batch);
      await loadBatches();
      setShowAddModal(false);
      setNewNumber('');
      setNewDesc('');
    } catch (error) {
      alert("Erro ao salvar lote.");
    } finally {
      setProcessing(false);
    }
  };

  const handleDelete = async () => {
    if (!itemToDelete) return;
    setProcessing(true);
    try {
      await dataService.deleteBatchNumber(itemToDelete.id);
      await loadBatches();
      setItemToDelete(null);
    } catch (error) {
      alert("Erro ao excluir lote.");
    } finally {
      setProcessing(false);
    }
  };

  const filteredBatches = batches.filter(b => 
    b.number.toLowerCase().includes(searchTerm.toLowerCase()) ||
    b.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10">
      {/* Header */}
      <div className="bg-slate-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1580674285054-bed31e145f59?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <Hash className="w-8 h-8 text-indigo-400" />
          Números de Lotes
        </h2>
        <p className="text-slate-300 max-w-xl">
          Analise a volumetria de pedidos para calcular a necessidade de lotes e gerencie os números ativos.
        </p>
      </div>

      {/* --- SEÇÃO DE ANÁLISE DE VOLUMETRIA --- */}
      {showAnalysis && (
        <div className="bg-white rounded-xl border-2 border-indigo-100 shadow-lg overflow-hidden animate-fade-in">
          <div className="bg-indigo-50 px-6 py-4 flex justify-between items-center border-b border-indigo-100">
             <div className="flex items-center gap-2">
                <BarChart2 className="w-5 h-5 text-indigo-600" />
                <h3 className="font-black text-indigo-900 uppercase tracking-tighter">Análise de Necessidade de Lotes</h3>
             </div>
             <button onClick={() => setShowAnalysis(false)} className="text-indigo-400 hover:text-indigo-600">
                <RefreshCw className="w-4 h-4" />
             </button>
          </div>

          <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-1 space-y-4">
               <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Pedidos Válidos (Sem Filhos)</p>
                  <p className="text-4xl font-black text-slate-900">{totalValidOrders.toLocaleString('pt-BR')}</p>
               </div>
               <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
                  <p className="text-[10px] font-bold text-emerald-600 uppercase tracking-widest mb-1">Total de Lotes Necessários</p>
                  <p className="text-4xl font-black text-emerald-700">
                    {analysisResults.reduce((acc, curr) => acc + curr.batchesNeeded, 0)}
                  </p>
               </div>
               <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 flex gap-3">
                  <Info className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
                  <p className="text-xs text-amber-800 leading-relaxed">
                    <strong>Regra Operacional:</strong> Máximo de <strong>80 pedidos</strong> por lote físico. Pedidos duplicados ou 'filhos' (-001, -002) foram removidos desta contagem.
                  </p>
               </div>
            </div>

            <div className="lg:col-span-2 overflow-hidden rounded-xl border border-slate-200 shadow-inner max-h-[400px] overflow-y-auto">
              <table className="w-full text-sm text-left border-collapse">
                <thead className="bg-slate-100 text-slate-600 font-black uppercase text-[10px] sticky top-0 z-10">
                  <tr>
                    <th className="px-6 py-3 border-b border-slate-200">Base Atendida</th>
                    <th className="px-6 py-3 border-b border-slate-200 text-center">Qtd. Pedidos</th>
                    <th className="px-6 py-3 border-b border-slate-200 text-right">Lotes Necessários</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {analysisResults.map((res, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 transition-colors">
                      <td className="px-6 py-3 font-bold text-slate-700">{res.base}</td>
                      <td className="px-6 py-3 text-center font-mono">{res.orderCount}</td>
                      <td className="px-6 py-3 text-right">
                        <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-black border ${res.batchesNeeded > 1 ? 'bg-orange-100 text-orange-700 border-orange-200' : 'bg-indigo-100 text-indigo-700 border-indigo-200'}`}>
                           <PackageCheck className="w-3.5 h-3.5" />
                           {res.batchesNeeded} {res.batchesNeeded === 1 ? 'LOTE' : 'LOTES'}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* --- GERENCIAMENTO DE NÚMEROS DE LOTES --- */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
        {/* Toolbar */}
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
          <div className="relative w-full md:w-96">
            <input 
              type="text" 
              placeholder="Buscar lote por número..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <Search className="w-5 h-5 text-slate-400 absolute left-3 top-2.5" />
          </div>

          <div className="flex gap-3 w-full md:w-auto">
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls" className="hidden" />
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={processing}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 font-medium transition-colors shadow-sm"
            >
              <FileSpreadsheet className="w-4 h-4" /> Analisar Planilha
            </button>
            <button 
              onClick={() => setShowAddModal(true)}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium transition-colors shadow-sm"
            >
              <Plus className="w-4 h-4" /> Cadastrar Lote
            </button>
          </div>
        </div>

        {/* Lista de Lotes */}
        {loading ? (
          <div className="py-20 flex flex-col items-center justify-center text-slate-400">
            <Loader2 className="w-10 h-10 animate-spin mb-4 text-indigo-600" />
            <p>Carregando registros...</p>
          </div>
        ) : (
          <div className="overflow-hidden rounded-lg border border-slate-100">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-500 font-bold uppercase text-[10px] tracking-widest">
                <tr>
                  <th className="px-6 py-4">Número do Lote</th>
                  <th className="px-6 py-4">Descrição/Referência</th>
                  <th className="px-6 py-4 text-center">Cadastrado em</th>
                  <th className="px-6 py-4 text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredBatches.map((batch) => (
                  <tr key={batch.id} className="hover:bg-slate-50 group transition-colors">
                    <td className="px-6 py-4 font-black text-slate-900 font-mono">
                      {batch.number}
                    </td>
                    <td className="px-6 py-4 text-slate-600">
                      {batch.description || '---'}
                    </td>
                    <td className="px-6 py-4 text-center text-slate-400">
                      {new Date(batch.created_at).toLocaleDateString('pt-BR')}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => setItemToDelete(batch)}
                        className="text-slate-300 hover:text-red-600 transition-colors p-2 rounded-lg hover:bg-red-50"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))}
                {filteredBatches.length === 0 && (
                  <tr>
                    <td colSpan={4} className="py-20 text-center text-slate-400 italic">
