            validTotal++;
            baseCounts[baseName] = (baseCounts[baseName] || 0) + 1;
          }
        });

        // Formatar resultados e calcular lotes (Limite de 80 por lote)
        const results: AnalysisResult[] = Object.entries(baseCounts).map(([base, count]) => ({
          base,
          orderCount: count,
          batchesNeeded: Math.ceil(count / 80)
        })).sort((a, b) => b.orderCount - a.orderCount);

        setTotalValidOrders(validTotal);
        setAnalysisResults(results);
        setShowAnalysis(true);

      } catch (error) {
        console.error(error);
        alert("Erro técnico ao processar planilha.");
      } finally {
        setProcessing(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

