              >
                Cancelar
              </button>
              <button 
                onClick={handleAddBatch}
                disabled={processing || !newNumber.trim()}
                className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black uppercase text-xs tracking-widest hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg active:scale-95"
              >
                {processing && <Loader2 className="w-4 h-4 animate-spin" />}
                Salvar Lote
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Deletar Lote */}
      {itemToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 border-t-8 border-red-600">
            <div className="flex items-center gap-3 text-red-600 mb-4">
              <AlertTriangle className="w-8 h-8" />
