                Excluir Agora
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BatchNumbers;

import React, { useState, useEffect, useRef } from 'react';
import { Hash, Search, Plus, Trash2, Upload, FileSpreadsheet, Loader2, AlertTriangle, CheckCircle2, RefreshCw, BarChart2, PackageCheck, Info, MapPin, ListChecks, ArrowRight } from 'lucide-react';
import { BatchNumber } from '../types';
import { dataService } from '../services/dataService';
import * as XLSX from 'xlsx';

interface AnalysisResult {
  base: string;
  orderCount: number;
  batchesNeeded: number;
}

const BatchNumbers: React.FC = () => {
  const [batches, setBatches] = useState<BatchNumber[]>([]);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Estados para Análise de Planilha
  const [analysisResults, setAnalysisResults] = useState<AnalysisResult[]>([]);
  const [totalValidOrders, setTotalValidOrders] = useState(0);
  const [showAnalysis, setShowAnalysis] = useState(false);

  const [showAddModal, setShowAddModal] = useState(false);
  const [newNumber, setNewNumber] = useState('');
  const [newDesc, setNewDesc] = useState('');

  const [itemToDelete, setItemToDelete] = useState<BatchNumber | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadBatches();
  }, []);

  const loadBatches = async () => {
    setLoading(true);
    try {
      const data = await dataService.getBatchNumbers();
      setBatches(data);
    } catch (error) {
      console.error("Erro ao carregar lotes:", error);
    } finally {
      setLoading(false);
    }
  };

  const cleanValue = (val: any): string => {
    if (val === null || val === undefined) return '';
    return String(val).trim().toUpperCase();
  };

  const findColumn = (row: any, candidates: string[]): string => {
    if (!row) return '';
    const keys = Object.keys(row);
    for (const name of candidates) {
      const found = keys.find(k => k.trim().toLowerCase() === name.toLowerCase());
      if (found) return found;
    }
    // Fallback para busca parcial se exata falhar
    for (const key of keys) {
      const kLow = key.toLowerCase();
      if (candidates.some(c => kLow.includes(c))) {
        return key;
      }
    }
    return '';
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setProcessing(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { defval: "" });

        if (jsonData.length === 0) {
          alert("A planilha está vazia.");
          return;
        }

        // Busca a coluna de pedido e a coluna de base/destino
        // Prioridade absoluta para 'Base Destino' conforme solicitado
        const colOrder = findColumn(jsonData[0], ['número de pedido jms', 'numero de pedido jms', 'pedido', 'order id', 'jms', 'referencia']);
        const colBase = findColumn(jsonData[0], ['base destino', 'destino', 'base de destino', 'parada anterior ou próxima', 'parada anterior ou proxima', 'base', 'parada']);

        if (!colOrder || !colBase) {
          alert(`Não conseguimos localizar as colunas necessárias.\nBuscando Pedido e Base Destino.\nEncontrado: ${colOrder || '---'} e ${colBase || '---'}`);
          return;
        }

        const baseCounts: Record<string, number> = {};
        let validTotal = 0;

        jsonData.forEach(row => {
          const orderId = cleanValue(row[colOrder]);
          const baseName = cleanValue(row[colBase]) || 'SEM BASE';

          // Regras:
          // 1. Ignorar pedidos filhos (contêm hífen como -001, -002)
          // 2. Ignorar números que já são lotes (iniciam com BR)
          if (orderId && !orderId.includes('-') && !orderId.startsWith('BR')) {
            validTotal++;
            baseCounts[baseName] = (baseCounts[baseName] || 0) + 1;
          }
        });

        // Formatar resultados e calcular lotes (Limite de 80 pedidos por lote)
        const results: AnalysisResult[] = Object.entries(baseCounts).map(([base, count]) => ({
          base,
          orderCount: count,
          batchesNeeded: Math.ceil(count / 80)
        })).sort((a, b) => a.base.localeCompare(b.base));

        setTotalValidOrders(validTotal);
        setAnalysisResults(results);
        setShowAnalysis(true);

      } catch (error) {
        console.error(error);
        alert("Erro técnico ao processar a planilha.");
      } finally {
        setProcessing(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleAddBatch = async () => {
    if (!newNumber.trim()) return;
    setProcessing(true);
    try {
      const batch: BatchNumber = {
        id: `batch-${Date.now()}`,
        number: newNumber.trim().toUpperCase(),
        description: newDesc.trim(),
        created_at: new Date().toISOString()
      };
      await dataService.saveBatchNumber(batch);
      await loadBatches();
      setShowAddModal(false);
      setNewNumber('');
      setNewDesc('');
    } catch (error) {
      alert("Erro ao salvar o número do lote.");
    } finally {
      setProcessing(false);
    }
  };

  const handleDelete = async () => {
    if (!itemToDelete) return;
    setProcessing(true);
    try {
      await dataService.deleteBatchNumber(itemToDelete.id);
      await loadBatches();
      setItemToDelete(null);
    } catch (error) {
      alert("Erro ao excluir o lote.");
    } finally {
      setProcessing(false);
    }
  };

  const filteredBatches = batches.filter(b => 
    b.number.toLowerCase().includes(searchTerm.toLowerCase()) ||
    b.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10">
      {/* Header */}
      <div className="bg-slate-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <Hash className="w-8 h-8 text-indigo-400" />
          Gerenciador de Lotes
        </h2>
        <p className="text-slate-300 max-w-xl font-medium">
          Triagem automática de pedidos e cálculo de lotes por Base Destino.
        </p>
      </div>

      {/* --- PAINEL DE ANÁLISE --- */}
      {showAnalysis && (
        <div className="bg-white rounded-xl border-2 border-indigo-100 shadow-2xl overflow-hidden animate-fade-in">
          <div className="bg-indigo-800 px-6 py-4 flex justify-between items-center text-white">
             <div className="flex items-center gap-2">
                <ListChecks className="w-5 h-5" />
                <h3 className="font-black uppercase tracking-tight text-sm">Cálculo de Necessidade de Lotes</h3>
             </div>
             <button onClick={() => setShowAnalysis(false)} className="bg-white/10 hover:bg-white/20 p-1.5 rounded-lg transition-colors">
                <RefreshCw className="w-4 h-4" />
             </button>
          </div>

          <div className="p-6">
            {/* Resumo Geral */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
               <div className="bg-slate-50 p-5 rounded-xl border border-slate-200 shadow-inner">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Pedidos Pais Identificados</p>
                  <p className="text-3xl font-black text-slate-900">{totalValidOrders.toLocaleString('pt-BR')}</p>
               </div>
               <div className="bg-indigo-50 p-5 rounded-xl border border-indigo-100 shadow-inner">
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-1">Total de Lotes Necessários</p>
                  <p className="text-3xl font-black text-indigo-700">
                    {analysisResults.reduce((acc, curr) => acc + curr.batchesNeeded, 0)}
                  </p>
               </div>
               <div className="p-5 bg-amber-50 rounded-xl border border-amber-100 flex items-center gap-3 shadow-inner">
                  <Info className="w-6 h-6 text-amber-600 shrink-0" />
                  <p className="text-xs text-amber-800 font-medium">
                    Máximo de <strong>80 pedidos</strong> por lote. Pedidos filhos (-001) e números de lotes existentes (BR) foram excluídos da triagem.
                  </p>
               </div>
            </div>

            {/* Listagem por Base Destino (Formato solicitado) */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {analysisResults.map((res, idx) => (
                <div key={idx} className={`p-5 rounded-xl border-2 flex flex-col justify-between h-40 transition-all hover:shadow-lg hover:border-indigo-300 ${res.batchesNeeded > 1 ? 'border-orange-100 bg-orange-50/20' : 'border-slate-100 bg-slate-50/50'}`}>
                  <div>
                    <div className="flex items-center justify-between mb-2">
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Base de Destino</span>
                       <MapPin className="w-3.5 h-3.5 text-slate-300" />
                    </div>
                    <h4 className="text-xl font-black text-slate-900 leading-tight truncate mb-1" title={res.base}>
                      {res.base}
                    </h4>
                  </div>

                  <div className="space-y-2">
                    <div className="flex items-center gap-1.5 text-slate-500 font-bold text-xs">
                       <PackageCheck className="w-4 h-4 text-indigo-500" />
                       {res.orderCount} pedidos válidos
                    </div>
                    {/* Formato solicitado: Nome da Base + Quantidade de Lotes */}
                    <div className={`flex items-center gap-2 px-3 py-2 rounded-lg font-black text-sm shadow-sm ${res.batchesNeeded > 1 ? 'bg-orange-600 text-white' : 'bg-indigo-700 text-white'}`}>
                      <ArrowRight className="w-4 h-4" />
                      {res.base} {res.batchesNeeded} {res.batchesNeeded === 1 ? 'LOTE' : 'LOTES'}
                    </div>
                  </div>
                </div>
              ))}
              {analysisResults.length === 0 && (
                <div className="col-span-full py-12 text-center text-slate-400 font-medium italic">
                  Nenhum destino identificado. Verifique se a coluna 'Base Destino' existe na planilha.
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* --- GERENCIAMENTO DE CADASTROS --- */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
        {/* Barra de Ferramentas */}
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
          <div className="relative w-full md:w-96">
            <input 
              type="text" 
              placeholder="Pesquisar registro de lote..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-300 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium transition-all"
            />
            <Search className="w-5 h-5 text-slate-400 absolute left-3 top-3" />
          </div>

          <div className="flex gap-3 w-full md:w-auto">
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls,.csv" className="hidden" />
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={processing}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 font-black text-[10px] uppercase tracking-widest transition-all shadow-lg active:scale-95 disabled:opacity-50"
            >
              {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <FileSpreadsheet className="w-4 h-4" />}
              Analisar Planilha
            </button>
            <button 
              onClick={() => setShowAddModal(true)}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-black text-[10px] uppercase tracking-widest transition-all shadow-lg active:scale-95"
            >
              <Plus className="w-4 h-4" />
              Novo Registro
            </button>
          </div>
        </div>

        {/* Listagem de Lotes Cadastrados */}
        {loading ? (
          <div className="py-24 flex flex-col items-center justify-center text-slate-400">
            <Loader2 className="w-10 h-10 animate-spin mb-4 text-indigo-600" />
