  );
};

export default BatchNumbers;

import React, { useState, useEffect, useRef } from 'react';
import { Hash, Search, Plus, Trash2, Upload, FileSpreadsheet, Loader2, AlertTriangle, CheckCircle2, RefreshCw, BarChart2, PackageCheck, Info, MapPin, ListChecks, ArrowRight, FilterX, Files, Eraser } from 'lucide-react';
import { BatchNumber } from '../types';
import { dataService } from '../services/dataService';
import * as XLSX from 'xlsx';

// Lista exata das 17 bases homologadas da operação SE AJU
const ALLOWED_BASES = [
  'NSS-SE', 'NSG-SE', 'IBN-SE', 'F LAG-SE', 'PRO-SE', 'F EST-SE', 
  'CDM-SE', 'BUG-SE', 'ARP-AL', 'PMI-AL', 'STI-AL', 'CAL-AL', 
  'CRP-AL', 'MDC-AL', 'JCN-AL', 'JGA-AL', 'F MCZ-AL'
];

interface AnalysisResult {
  base: string;
  orderCount: number;
  batchesNeeded: number;
}

const BatchNumbers: React.FC = () => {
  const [batches, setBatches] = useState<BatchNumber[]>([]);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Estados Acumuladores para Multi-Planilha
  const [cumulativeBaseCounts, setCumulativeBaseCounts] = useState<Record<string, number>>({});
  const [cumulativeValidOrders, setCumulativeValidOrders] = useState<Set<string>>(new Set());
  const [cumulativeIgnoredCount, setCumulativeIgnoredCount] = useState(0);
  const [filesProcessed, setFilesProcessed] = useState(0);

  const [analysisResults, setAnalysisResults] = useState<AnalysisResult[]>([]);
  const [showAnalysis, setShowAnalysis] = useState(false);

  const [showAddModal, setShowAddModal] = useState(false);
  const [newNumber, setNewNumber] = useState('');
  const [newDesc, setNewDesc] = useState('');

  const [itemToDelete, setItemToDelete] = useState<BatchNumber | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadBatches();
  }, []);

  const loadBatches = async () => {
    setLoading(true);
    try {
      const data = await dataService.getBatchNumbers();
      setBatches(data);
    } catch (error) {
      console.error("Erro ao carregar lotes:", error);
    } finally {
      setLoading(false);
    }
  };

  const cleanValue = (val: any): string => {
    if (val === null || val === undefined) return '';
    return String(val).trim().toUpperCase();
  };

  const normalize = (str: string) => str.replace(/\s+/g, '').toUpperCase();

  const findColumn = (row: any, candidates: string[]): string => {
    if (!row) return '';
    const keys = Object.keys(row);
    for (const name of candidates) {
      const found = keys.find(k => normalize(k) === normalize(name));
      if (found) return found;
    }
    for (const key of keys) {
      if (candidates.some(c => normalize(key).includes(normalize(c)))) {
        return key;
      }
    }
    return '';
  };

  const processFile = (file: File): Promise<{baseCounts: Record<string, number>, validOrders: Set<string>, ignoredCount: number}> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const data = e.target?.result;
          const workbook = XLSX.read(data, { type: 'binary' });
          const sheet = workbook.Sheets[workbook.SheetNames[0]];
          const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { defval: "" });

          if (jsonData.length === 0) {
            resolve({ baseCounts: {}, validOrders: new Set(), ignoredCount: 0 });
            return;
          }

          const colOrder = findColumn(jsonData[0], ['número de pedido jms', 'numero de pedido jms', 'pedido', 'order id', 'jms', 'referencia']);
          const colBase = findColumn(jsonData[0], ['base destino', 'destino', 'base de destino', 'parada anterior ou próxima', 'parada anterior ou proxima', 'base', 'parada']);

          const baseCounts: Record<string, number> = {};
          const validOrders = new Set<string>();
          let ignoredCount = 0;

          if (!colOrder || !colBase) {
             resolve({ baseCounts: {}, validOrders: new Set(), ignoredCount: 0 });
             return;
          }

          jsonData.forEach(row => {
            const orderId = cleanValue(row[colOrder]);
            let baseNameRaw = cleanValue(row[colBase]) || '';

            if (!orderId) return;

            const normalizedInput = normalize(baseNameRaw);
            const matchedBase = ALLOWED_BASES.find(b => {
              const normalizedAllowed = normalize(b);
              return normalizedInput.includes(normalizedAllowed);
            });

            if (!orderId.includes('-') && !orderId.startsWith('BR')) {
              if (matchedBase) {
                validOrders.add(orderId);
                baseCounts[matchedBase] = (baseCounts[matchedBase] || 0) + 1;
              } else {
                ignoredCount++;
              }
            }
          });

          resolve({ baseCounts, validOrders, ignoredCount });
        } catch (err) {
          reject(err);
        }
      };
      reader.onerror = (err) => reject(err);
      reader.readAsBinaryString(file);
    });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setProcessing(true);

    try {
      // Criar cópias dos acumuladores atuais
      const newBaseCounts = { ...cumulativeBaseCounts };
      const newValidOrders = new Set(cumulativeValidOrders);
      let newIgnoredCount = cumulativeIgnoredCount;
      let newFilesCount = filesProcessed + files.length;

      // Processar os novos arquivos
      const results = await Promise.all(Array.from(files).map((file: File) => processFile(file)));

      // Consolidar novos dados aos existentes
      results.forEach(res => {
        newIgnoredCount += res.ignoredCount;

        // Iterar sobre cada pedido encontrado na planilha
        res.validOrders.forEach(orderId => {
          if (!newValidOrders.has(orderId)) {
            newValidOrders.add(orderId);
          }
        });

        Object.entries(res.baseCounts).forEach(([base, count]) => {
          newBaseCounts[base] = (newBaseCounts[base] || 0) + count;
        });
      });

      // Atualizar Estados
      setCumulativeBaseCounts(newBaseCounts);
      setCumulativeValidOrders(newValidOrders);
      setCumulativeIgnoredCount(newIgnoredCount);
      setFilesProcessed(newFilesCount);

      // Fix: Cast count to number to resolve "Type unknown is not assignable to number" and arithmetic errors.
      // Calcular Resultados Finais
      const finalResults: AnalysisResult[] = Object.entries(newBaseCounts).map(([base, count]) => {
        const numCount = count as number;
        return {
          base,
          orderCount: numCount,
          batchesNeeded: Math.ceil(numCount / 80)
        };
      }).sort((a, b) => b.orderCount - a.orderCount);

      setAnalysisResults(finalResults);
      setShowAnalysis(true);

    } catch (error) {
      console.error(error);
      alert("Erro ao processar arquivos.");
    } finally {
      setProcessing(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleResetAnalysis = () => {
    setCumulativeBaseCounts({});
    setCumulativeValidOrders(new Set());
    setCumulativeIgnoredCount(0);
    setFilesProcessed(0);
    setAnalysisResults([]);
    setShowAnalysis(false);
  };

  const handleAddBatch = async () => {
    if (!newNumber.trim()) return;
    setProcessing(true);
    try {
      const batch: BatchNumber = {
        id: `batch-${Date.now()}`,
        number: newNumber.trim().toUpperCase(),
        description: newDesc.trim(),
        created_at: new Date().toISOString()
      };
      await dataService.saveBatchNumber(batch);
      await loadBatches();
      setShowAddModal(false);
      setNewNumber('');
      setNewDesc('');
    } catch (error) {
      alert("Erro ao salvar o lote.");
    } finally {
      setProcessing(false);
    }
  };

  const handleDelete = async () => {
    if (!itemToDelete) return;
    setProcessing(true);
    try {
      await dataService.deleteBatchNumber(itemToDelete.id);
      await loadBatches();
      setItemToDelete(null);
    } catch (error) {
      alert("Erro ao excluir.");
    } finally {
      setProcessing(false);
    }
  };

  const filteredBatches = batches.filter(b => 
    b.number.toLowerCase().includes(searchTerm.toLowerCase()) ||
    b.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-10">
      {/* Header */}
      <div className="bg-slate-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <Hash className="w-8 h-8 text-indigo-400" />
          Dimensionamento Acumulativo de Lotes
        </h2>
        <p className="text-slate-300 max-w-xl font-medium">
          Soma automática de múltiplas planilhas para as 17 bases homologadas. (Limite: 80 pedidos/lote)
        </p>
      </div>

      {/* --- PAINEL DE ANÁLISE CONSOLIDADA --- */}
      {showAnalysis && (
        <div className="bg-white rounded-xl border-2 border-indigo-100 shadow-2xl overflow-hidden animate-fade-in">
          <div className="bg-indigo-900 px-6 py-4 flex justify-between items-center text-white">
             <div className="flex items-center gap-2">
                <Files className="w-5 h-5 text-indigo-300" />
                <h3 className="font-black uppercase tracking-tight text-sm">Volume Somado ({filesProcessed} arquivos)</h3>
             </div>
             <div className="flex items-center gap-2">
                <button 
                  onClick={handleResetAnalysis} 
                  className="flex items-center gap-2 bg-red-600/20 hover:bg-red-600 text-red-200 hover:text-white px-3 py-1.5 rounded-lg transition-all text-[10px] font-black uppercase"
                  title="Limpar todos os dados e começar nova soma"
                >
                  <Eraser className="w-3.5 h-3.5" />
                  Reiniciar Soma
                </button>
                <button onClick={() => setShowAnalysis(false)} className="bg-white/10 hover:bg-white/20 p-1.5 rounded-lg transition-colors">
                  <RefreshCw className="w-4 h-4" />
                </button>
             </div>
          </div>

          <div className="p-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
               <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 shadow-inner">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Pedidos Únicos</p>
                  <p className="text-3xl font-black text-slate-900">{cumulativeValidOrders.size.toLocaleString('pt-BR')}</p>
               </div>
               <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 shadow-inner">
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-1">Necessidade de Lotes</p>
                  <p className="text-3xl font-black text-indigo-700">
                    {analysisResults.reduce((acc, curr) => acc + curr.batchesNeeded, 0)}
                  </p>
               </div>
               <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-inner opacity-60">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Arquivos na Soma</p>
                  <p className="text-3xl font-black text-slate-400">{filesProcessed}</p>
               </div>
               <div className="p-4 bg-emerald-50 rounded-xl border border-emerald-100 flex items-center gap-3">
                  <CheckCircle2 className="w-5 h-5 text-emerald-600 shrink-0" />
                  <p className="text-[10px] text-emerald-800 font-bold leading-tight">
                    Soma ativa. Novos arquivos adicionados serão somados ao total acima mantendo a regra das 17 bases.
                  </p>
               </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {analysisResults.map((res, idx) => (
                <div key={idx} className={`p-5 rounded-xl border-2 flex flex-col justify-between h-40 transition-all hover:shadow-lg hover:border-indigo-400 ${res.batchesNeeded > 1 ? 'border-orange-200 bg-orange-50/20' : 'border-slate-100 bg-slate-50/50'}`}>
                  <div>
                    <div className="flex items-center justify-between mb-1">
                       <span className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">BASE DESTINO</span>
                       <MapPin className="w-3.5 h-3.5 text-slate-300" />
                    </div>
                    <h4 className="text-xl font-black text-slate-900 leading-tight truncate">
                      {res.base}
                    </h4>
                  </div>

                  <div className="space-y-2">
                    <div className={`flex items-center justify-between px-3 py-2 rounded-lg font-black text-sm shadow-sm ${res.batchesNeeded > 1 ? 'bg-orange-600 text-white' : 'bg-slate-800 text-white'}`}>
                      <span className="truncate mr-2 uppercase">{res.base}</span>
                      <span className="whitespace-nowrap uppercase tracking-tighter">
                        {res.batchesNeeded} {res.batchesNeeded === 1 ? 'LOTE' : 'LOTES'}
                      </span>
                    </div>
                    <p className="text-[9px] font-bold text-slate-400 text-right px-1">
                      VOLUME ACUMULADO: {res.orderCount}
                    </p>
                  </div>
                </div>
              ))}
              {analysisResults.length === 0 && (
                <div className="col-span-full py-16 text-center bg-slate-50 rounded-xl border border-dashed border-slate-300">
                  <FilterX className="w-10 h-10 mx-auto mb-3 text-slate-300" />
                  <p className="text-slate-500 font-bold uppercase text-xs">Aguardando dados das 17 bases homologadas.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* --- FERRAMENTAS --- */}
      <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
          <div className="relative w-full md:w-96">
            <input 
              type="text" 
              placeholder="Pesquisar registro de lote..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-300 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium transition-all"
            />
            <Search className="w-5 h-5 text-slate-400 absolute left-3 top-3" />
          </div>

          <div className="flex gap-3 w-full md:w-auto">
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".xlsx,.xls,.csv" className="hidden" multiple />
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={processing}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 font-black text-[10px] uppercase tracking-widest transition-all shadow-lg active:scale-95 disabled:opacity-50"
            >
              {processing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Plus className="w-4 h-4" />}
              Adicionar Planilha à Soma
            </button>
            <button 
              onClick={() => setShowAddModal(true)}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-black text-[10px] uppercase tracking-widest transition-all shadow-lg active:scale-95"
            >
              <Plus className="w-4 h-4" />
              Novo Registro Individual
            </button>
          </div>
        </div>

        {loading ? (
          <div className="py-24 flex flex-col items-center justify-center text-slate-400">
            <Loader2 className="w-10 h-10 animate-spin mb-4 text-indigo-600" />
            <p className="font-bold uppercase text-[10px] tracking-widest">Sincronizando...</p>
          </div>
        ) : (
          <div className="overflow-hidden rounded-xl border border-slate-100 shadow-inner">
            <table className="w-full text-sm text-left border-collapse">
              <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4">Código do Lote</th>
                  <th className="px-6 py-4">Unidade / Obs</th>
                  <th className="px-6 py-4 text-center">Data</th>
                  <th className="px-6 py-4 text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredBatches.map((batch) => (
                  <tr key={batch.id} className="hover:bg-indigo-50/30 group transition-colors">
                    <td className="px-6 py-4 font-black text-slate-900 font-mono text-base">
                      {batch.number}
                    </td>
                    <td className="px-6 py-4 text-slate-600 font-medium">
                      {batch.description || '---'}
                    </td>
                    <td className="px-6 py-4 text-center text-slate-400 text-[10px] font-bold">
                      {new Date(batch.created_at).toLocaleDateString('pt-BR')}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => setItemToDelete(batch)}
                        className="text-slate-200 hover:text-red-600 transition-all p-2 rounded-lg hover:bg-red-50"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))}
                {filteredBatches.length === 0 && (
                  <tr>
                    <td colSpan={4} className="py-24 text-center text-slate-300 font-medium italic">
                      Sem registros individuais.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Modal Cadastro */}
      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in duration-200 border-t-8 border-indigo-600">
            <h3 className="text-xl font-black text-slate-800 mb-5 uppercase tracking-tighter">Registrar Lote Individual</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-widest">Número do Lote</label>
                <input 
                  type="text" 
                  value={newNumber}
                  onChange={(e) => setNewNumber(e.target.value)}
                  placeholder="EX: BR00000000"
                  className="w-full p-3 border-2 border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 uppercase font-mono font-bold text-lg shadow-inner"
                  autoFocus
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-widest">Base de Destino</label>
                <input 
                  type="text" 
                  value={newDesc}
                  onChange={(e) => setNewDesc(e.target.value)}
                  placeholder="Ex: PMI-AL"
                  className="w-full p-3 border-2 border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium shadow-inner uppercase"
                />
              </div>
            </div>
            <div className="flex gap-3 mt-8">
              <button 
                onClick={() => setShowAddModal(false)}
                className="flex-1 py-3 border-2 border-slate-100 rounded-xl text-slate-600 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={handleAddBatch}
                disabled={processing || !newNumber.trim()}
                className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg active:scale-95"
              >
                {processing && <Loader2 className="w-4 h-4 animate-spin" />}
                Salvar Lote
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Exclusão */}
      {itemToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-8 border-t-8 border-red-600">
            <div className="flex items-center gap-4 text-red-600 mb-6">
              <AlertTriangle className="w-10 h-10" />
              <h3 className="text-xl font-black uppercase tracking-tighter">Apagar Registro?</h3>
            </div>
            <p className="text-slate-600 mb-8 font-medium leading-relaxed">
              Deseja remover o lote <strong className="text-slate-900 underline font-black">{itemToDelete.number}</strong>?
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setItemToDelete(null)}
                className="flex-1 py-3 border-2 border-slate-100 rounded-xl text-slate-600 font-black uppercase text-[10px] tracking-widest hover:bg-slate-50 transition-colors"
              >
                Manter
              </button>
              <button 
                onClick={handleDelete}
                disabled={processing}
                className="flex-1 py-3 bg-red-600 text-white rounded-xl font-black uppercase text-[10px] tracking-widest hover:bg-red-700 transition-all flex items-center justify-center gap-2 shadow-lg active:scale-95"
              >
                {processing && <Loader2 className="w-4 h-4 animate-spin" />}
                Excluir
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BatchNumbers;

import React, { useRef, useState } from 'react';
import { Upload, FileSpreadsheet, FileText, AlertCircle, CheckCircle2, Printer, ImageDown, Camera, BarChart3, LayoutGrid, Calendar } from 'lucide-react';
import * as XLSX from 'xlsx';
import { Document, Packer, Paragraph, Table, TableCell, TableRow, WidthType, BorderStyle, TextRun, AlignmentType, VerticalAlign, PageOrientation, ImageRun } from 'docx';
import html2canvas from 'html2canvas';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LabelList, Cell } from 'recharts';

interface Props {}

interface ReportItem {
  pdd: string;
  id: string;
  vehicleType: string;
  volume: number;
  capacity: number;
  saturation: number;
  plate: string;
}

interface AnalyticsData {
  base: string;
  count: number;
}

const GenerateReport: React.FC<Props> = () => {
  const [activeTab, setActiveTab] = useState<'visual' | 'analytics'>('visual');

  // --- STATES FOR VISUAL REPORT ---
  const fileInputRef = useRef<HTMLInputElement>(null);
  const photoInputRef = useRef<HTMLInputElement>(null);
  const reportContainerRef = useRef<HTMLDivElement>(null);

  const [importStatus, setImportStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [statusMessage, setStatusMessage] = useState('');
  const [reportData, setReportData] = useState<ReportItem[]>([]);
  const [vehiclePhotos, setVehiclePhotos] = useState<Record<string, string>>({});
  const [activePhotoId, setActivePhotoId] = useState<string | null>(null);

  // Data selecionada para o relatório (Padrão: Hoje)
  const [opDate, setOpDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // --- STATES FOR ANALYTICS REPORT ---
  const analyticsInputRef = useRef<HTMLInputElement>(null);
  const [analyticsStatus, setAnalyticsStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [analyticsData, setAnalyticsData] = useState<AnalyticsData[]>([]);
  const [totalExpedited, setTotalExpedited] = useState<number>(0);

  // --- SHARED HELPERS ---
  const findColumnName = (row: any, possibleNames: string[]): string | undefined => {
    if (!row) return undefined;
    const keys = Object.keys(row);
    for (const name of possibleNames) {
      const found = keys.find(k => k.trim().toLowerCase() === name.toLowerCase());
      if (found) return found;
    }
    return undefined;
  };

  const getCapacity = (vehicleType: string): number => {
    const type = vehicleType?.toString().toLowerCase().trim() || '';
    if (type.includes('3/4')) return 2000;
    if (type.includes('van')) return 1100;
    if (type.includes('furg')) return 1100;
    if (type.includes('utilit')) return 300;
    if (type.includes('toco')) return 4000;
    if (type.includes('truck')) return 5000;
    return 0;
  };

  const formatDisplayDate = (dateStr: string) => {
    if (!dateStr) return '';
    const [year, month, day] = dateStr.split('-');
    return `${day}/${month}/${year}`;
  };

  // --- VISUAL REPORT HANDLERS ---

  const handlePddChange = (idx: number, newValue: string) => {
    setReportData(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], pdd: newValue.toUpperCase() };
      return next;
    });
  };

  const triggerFileInput = () => {
    setImportStatus('idle');
    setReportData([]); 
    setVehiclePhotos({});
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handlePhotoCardClick = (id: string) => {
    setActivePhotoId(id);
    if (photoInputRef.current) {
      photoInputRef.current.value = '';
      photoInputRef.current.click();
    }
  };

  const handlePhotoUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && activePhotoId) {
      const reader = new FileReader();
      reader.onload = (e) => {
        if (e.target?.result) {
          setVehiclePhotos(prev => ({
            ...prev,
            [activePhotoId]: e.target!.result as string
          }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setImportStatus('loading');
    setStatusMessage('Lendo e processando arquivo...');

    const reader = new FileReader();

    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        const jsonData = XLSX.utils.sheet_to_json<any>(worksheet, { defval: "" });

        if (!jsonData || jsonData.length === 0) {
          throw new Error("Arquivo vazio ou formato inválido.");
        }

        const processedReportItems: ReportItem[] = [];

        jsonData.forEach((row: any) => {
          const idViagem = row['Tarefa de transporte No.'] || row['ID Viagem'] || row['Trip ID'];
          const pddChegada = row['PDD de chegada'] || row['Destino'] || '';
          const tipoVeiculo = row['Tipo de veículo utilizado'] || row['Veículo'] || '';
          const placa = row['Placa do carro'] || row['Placa'] || '';
          const pedidoMae = row['Número de " Pedido mãe"'] || row['Pedido mãe'] || '';

          if (!idViagem) return;

          const capacidade = getCapacity(tipoVeiculo);
          let rawVol = pedidoMae.toString();
          if (rawVol.includes(',') && !rawVol.includes('.')) {
              rawVol = rawVol.replace(',', '.');
          }
          const volumetria = parseFloat(rawVol) || 0;
          const saturacao = capacidade > 0 ? (volumetria / capacidade) : 0;

          processedReportItems.push({
            pdd: pddChegada,
            id: idViagem,
            vehicleType: tipoVeiculo,
            volume: volumetria,
            capacity: capacidade,
            saturation: saturacao,
            plate: placa
          });
        });

        if (processedReportItems.length === 0) {
          throw new Error("Nenhuma viagem válida encontrada.");
        }

        setReportData(processedReportItems);
        setImportStatus('success');
        setStatusMessage(`${processedReportItems.length} viagens processadas!`);

        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (err: any) {
        console.error("Erro no processamento:", err);
        setImportStatus('error');
        setStatusMessage(err.message || "Erro ao processar arquivo.");
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- ANALYTICS REPORT HANDLERS ---

  const triggerAnalyticsInput = () => {
    if (analyticsInputRef.current) {
      analyticsInputRef.current.click();
    }
  };

  const handleAnalyticsUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setAnalyticsStatus('loading');
    setAnalyticsData([]);
    setTotalExpedited(0);

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { defval: "" });

        if (!jsonData || jsonData.length === 0) throw new Error("Planilha vazia.");

        // Identificar colunas
        const colOrder = findColumnName(jsonData[0], ['Número de pedido JMS', 'Numero de pedido JMS', 'Pedido', 'Order ID', 'ID']);
        const colBase = findColumnName(jsonData[0], ['Parada anterior ou próxima', 'Parada anterior ou proxima', 'Base', 'Destino', 'Parada']);

        if (!colOrder) throw new Error("Coluna de Pedido não encontrada.");

        let totalCount = 0;
        const baseCounts: Record<string, number> = {};

        jsonData.forEach(row => {
           const id = String(row[colOrder] || '').trim().toUpperCase();

           // Lógica de Exclusão
           // 1. Remover filhos (com hífen)
           if (id.includes('-')) return;

           // 2. Remover lotes (começa com BR)
           if (id.startsWith('BR')) return;

           // Se passou, conta como expedido
           if (id.length > 0) {
             totalCount++;

             // Agrupar por Base
             let baseName = 'INDEFINIDO';
             if (colBase && row[colBase]) {
               baseName = String(row[colBase]).trim().toUpperCase();
               baseName = baseName.replace('CD ', '').replace('HUB ', ''); 
             }

             baseCounts[baseName] = (baseCounts[baseName] || 0) + 1;
           }
        });

        const chartData = Object.entries(baseCounts)
          .map(([base, count]) => ({ base, count }))
          .sort((a, b) => b.count - a.count);

        setTotalExpedited(totalCount);
        setAnalyticsData(chartData);
        setAnalyticsStatus('success');

        if (analyticsInputRef.current) analyticsInputRef.current.value = '';

      } catch (err: any) {
        console.error(err);
        setAnalyticsStatus('error');
        alert(err.message || "Erro ao processar planilha.");
      }
    };
    reader.readAsBinaryString(file);
  };


  // --- EXPORT FUNCTIONS (VISUAL) ---
  const handlePrint = () => window.print();

  const handleExportToPNG = async () => {
    if (!reportContainerRef.current) return;
    try {
      const canvas = await html2canvas(reportContainerRef.current, { 
        scale: 2.5, 
        backgroundColor: '#ffffff', 
        useCORS: true,
        logging: false 
      });
      const image = canvas.toDataURL("image/png", 1.0);
      const link = document.createElement('a');
      link.href = image;
      link.download = `Relatorio_Visual_${opDate}.png`;
      link.click();
    } catch (err) { alert("Não foi possível gerar a imagem."); }
  };

  const dataUrlToArrayBuffer = async (dataUrl: string) => {
    const res = await fetch(dataUrl);
    return await res.arrayBuffer();
  };

  const handleExportToExcel = async () => {
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet([]);
    const CARDS_PER_ROW = 4;
    const grid: any[][] = [];
    const newMerges: XLSX.Range[] = [];
    const setGridCell = (r: number, c: number, val: any) => {
      if (!grid[r]) grid[r] = [];
      grid[r][c] = val;
    };
    let currentRowBase = 0;

    for (let i = 0; i < reportData.length; i++) {
      const item = reportData[i];
      const colBase = (i % CARDS_PER_ROW) * 3;
      if (i > 0 && i % CARDS_PER_ROW === 0) currentRowBase += 9;
      const r = currentRowBase;
      const c = colBase;
      setGridCell(r, c, "FOTO DO VEÍCULO");
      newMerges.push({ s: { r: r, c: c }, e: { r: r+1, c: c+1 } }); 
      setGridCell(r+2, c, "NOME DA LINHA"); setGridCell(r+2, c+1, item.pdd);
      setGridCell(r+3, c, "ID VIAGEM"); setGridCell(r+3, c+1, item.id);
      setGridCell(r+4, c, "TIPO DE VEICULO"); setGridCell(r+4, c+1, item.vehicleType);
      setGridCell(r+5, c, "VOLUMETRIA REAL"); setGridCell(r+5, c+1, item.volume);
      setGridCell(r+6, c, "CAPACIDADE"); setGridCell(r+6, c+1, item.capacity);
      setGridCell(r+7, c, "SATURAÇÃO"); setGridCell(r+7, c+1, `${(item.saturation * 100).toFixed(0)}%`);
      setGridCell(r+8, c, "PLACA"); setGridCell(r+8, c+1, item.plate);
    }
    XLSX.utils.sheet_add_aoa(ws, grid, { origin: "A1" });
    ws['!merges'] = newMerges;
    XLSX.utils.book_append_sheet(wb, ws, "Relatório");
    XLSX.writeFile(wb, `Relatorio_Operacional_${opDate}.xlsx`);
  };

  const handleExportToWord = async () => {
    const rows: TableRow[] = [];
    let currentCells: TableCell[] = [];

    for (let i = 0; i < reportData.length; i++) {
      const item = reportData[i];
      let photoChildren: any[] = [new Paragraph({ children: [new TextRun({ text: "FOTO DO VEÍCULO", bold: true, size: 20, color: "CCCCCC" })], alignment: AlignmentType.CENTER })];

      if (vehiclePhotos[item.id]) {
        try {
          const imageBuffer = await dataUrlToArrayBuffer(vehiclePhotos[item.id]);
          photoChildren = [new Paragraph({ children: [new ImageRun({ data: imageBuffer, transformation: { width: 250, height: 150 } })], alignment: AlignmentType.CENTER })];
        } catch (e) {}
      }

      const cardTable = new Table({
        width: { size: 100, type: WidthType.PERCENTAGE },
        rows: [
          new TableRow({ height: { value: 2000, rule: 'atLeast' }, children: [new TableCell({ columnSpan: 2, children: photoChildren, verticalAlign: VerticalAlign.CENTER })] }),
          ...[
            ["NOME DA LINHA", item.pdd], ["ID VIAGEM", item.id], ["TIPO DE VEICULO", item.vehicleType],
            ["VOLUMETRIA REAL", item.volume.toString()], ["CAPACIDADE", item.capacity.toString()],
            ["SATURAÇÃO", `${(item.saturation * 100).toFixed(0)}%`], ["PLACA", item.plate]
          ].map(([label, value]) => new TableRow({ children: [
                new TableCell({ width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E5E7EB" }, children: [new Paragraph({ children: [new TextRun({ text: label, bold: true, size: 16 })] })], verticalAlign: VerticalAlign.CENTER }),
                new TableCell({ width: { size: 60, type: WidthType.PERCENTAGE }, children: [new Paragraph({ children: [new TextRun({ text: value, bold: label === "PLACA" || label === "SATURAÇÃO", color: (label === "SATURAÇÃO" && parseFloat(value) > 100) ? "DC2626" : "000000", size: 16 })], alignment: AlignmentType.CENTER })], verticalAlign: VerticalAlign.CENTER })
              ]
            }))
        ]
      });
      currentCells.push(new TableCell({ children: [new Paragraph(""), cardTable, new Paragraph("")], width: { size: 25, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, left: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, right: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" } } }));
      if (currentCells.length === 4 || i === reportData.length - 1) {
        while (currentCells.length < 4) currentCells.push(new TableCell({ children: [], width: { size: 25, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "auto" }, bottom: { style: BorderStyle.NONE, size: 0, color: "auto" }, left: { style: BorderStyle.NONE, size: 0, color: "auto" }, right: { style: BorderStyle.NONE, size: 0, color: "auto" } } }));
        rows.push(new TableRow({ children: currentCells }));
        currentCells = [];
      }
    }
    const doc = new Document({ sections: [{ properties: { page: { size: { orientation: PageOrientation.LANDSCAPE }, margin: { top: 500, bottom: 500, left: 500, right: 500 } } }, children: [new Table({ rows: rows, width: { size: 100, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, left: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, right: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, insideHorizontal: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, insideVertical: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" } } })] }] });
    const blob = await Packer.toBlob(doc);
    const link = document.createElement('a');
    link.href = window.URL.createObjectURL(blob);
    link.download = `Relatorio_Visual_${opDate}.docx`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-10">
      <input type="file" ref={photoInputRef} onChange={handlePhotoUpload} accept="image/*" className="hidden" />

      {/* Tabs */}
      <div className="print:hidden">
        <div className="bg-indigo-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90 mb-6">
          <h2 className="text-3xl font-bold mb-2">Relatório de Carregamento</h2>
          <p className="text-indigo-100 max-w-xl">
             Gere relatórios visuais de veículos ou analise a volumetria expedida por base.
          </p>
        </div>

        <div className="flex border-b border-slate-200 gap-6 mb-6">
          <button 
            onClick={() => setActiveTab('visual')}
            className={`pb-3 text-sm font-bold flex items-center gap-2 border-b-2 transition-colors ${activeTab === 'visual' ? 'border-indigo-600 text-indigo-700' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
          >
            <LayoutGrid className="w-4 h-4" /> Relatório Visual (Cartões)
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`pb-3 text-sm font-bold flex items-center gap-2 border-b-2 transition-colors ${activeTab === 'analytics' ? 'border-indigo-600 text-indigo-700' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
          >
            <BarChart3 className="w-4 h-4" /> Gráfico de Expedição (Bases)
          </button>
        </div>
      </div>

      {/* === TAB 1: VISUAL REPORT === */}
      {activeTab === 'visual' && (
        <>
          <div className="print:hidden flex flex-col md:flex-row gap-6 items-start">
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex-1 w-full">
              <div className="text-center md:text-left flex flex-col md:flex-row items-center gap-6">
                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center shrink-0">
                  <Upload className="w-8 h-8 text-indigo-600" />
                </div>
                <div className="flex-1">
                  <h3 className="text-xl font-bold text-slate-800 mb-1">Configurar Relatório Visual</h3>
                  <p className="text-slate-500 text-sm mb-4">
                    Selecione a data da operação e carregue a planilha de carregamento.
                  </p>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="relative">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Data da Operação</label>
                      <div className="relative">
                        <input 
                          type="date" 
                          value={opDate} 
                          onChange={(e) => setOpDate(e.target.value)} 
                          className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500/20" 
                        />
                        <Calendar className="w-4 h-4 text-indigo-400 absolute left-3 top-2.5 pointer-events-none" />
                      </div>
                    </div>

                    <div className="flex items-end">
                      <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept=".csv,.xlsx,.xls" className="hidden" />
                      <button 
                        onClick={triggerFileInput}
                        disabled={importStatus === 'loading'}
                        className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2 rounded-xl font-medium transition-colors disabled:opacity-50 shadow-md"
                      >
                        {importStatus === 'loading' ? <Loader2 className="w-4 h-4 animate-spin" /> : <FileText className="w-4 h-4" />} 
                        {importStatus === 'loading' ? 'Lendo...' : 'Selecionar Planilha'}
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              {importStatus !== 'idle' && (
                <div className={`mt-4 p-3 rounded-lg text-sm flex items-start gap-2 ${importStatus === 'error' ? 'bg-red-50 text-red-700' : importStatus === 'success' ? 'bg-green-50 text-green-700' : 'bg-slate-50 text-slate-600'}`}>
                  {importStatus === 'error' && <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />}
                  {importStatus === 'success' && <CheckCircle2 className="w-4 h-4 mt-0.5 shrink-0" />}
                  <span className="font-medium">{statusMessage}</span>
                </div>
              )}
            </div>
          </div>

          {reportData.length > 0 && (
            <div className="animate-fade-in">
              <div className="print:hidden flex flex-col sm:flex-row justify-between items-center mb-6 bg-slate-100 p-4 rounded-lg border border-slate-200 gap-4 mt-8">
                <h3 className="text-xl font-bold text-slate-800">Pré-visualização do Relatório</h3>
                <div className="flex flex-wrap gap-3">
                  <button onClick={handleExportToWord} className="flex items-center gap-2 bg-blue-700 text-white px-4 py-2 rounded-lg hover:bg-blue-800 transition-colors text-sm font-medium"><FileText className="w-4 h-4" /> Word</button>
                  <button onClick={handleExportToExcel} className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors text-sm font-medium"><FileSpreadsheet className="w-4 h-4" /> Excel</button>
                  <button onClick={handleExportToPNG} className="flex items-center gap-2 bg-orange-600 text-white px-4 py-2 rounded-lg hover:bg-orange-700 transition-colors text-sm font-medium"><ImageDown className="w-4 h-4" /> PNG</button>
                  <button onClick={handlePrint} className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg hover:bg-slate-900 transition-colors text-sm font-medium"><Printer className="w-4 h-4" /> Imprimir</button>
                </div>
              </div>

              <div ref={reportContainerRef} className="bg-white p-4">
                <div className="w-full bg-[#FF0000] text-white font-black text-2xl text-center py-4 mb-4 uppercase tracking-tighter">
                  CARREGAMENTO SE AJU - {formatDisplayDate(opDate)}
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 print:grid-cols-4 print:gap-4">
                  {reportData.map((item, idx) => (
                    <div key={idx} className="border-2 border-slate-800 break-inside-avoid bg-white flex flex-col">
                      <div className="h-48 bg-slate-100 border-b-2 border-slate-800 flex flex-col items-center justify-center text-slate-400 cursor-pointer hover:bg-slate-200 transition-colors relative overflow-hidden group" onClick={() => handlePhotoCardClick(item.id)} title="Clique para adicionar foto">
                        {vehiclePhotos[item.id] ? <img src={vehiclePhotos[item.id]} alt={`Veículo ${item.id}`} className="max-w-full max-h-full w-auto h-auto object-contain" /> : <><Camera className="w-10 h-10 mb-2 opacity-40 group-hover:opacity-100 group-hover:scale-110 transition-all text-slate-500" /><span className="text-xs uppercase font-bold tracking-wider text-slate-500">Adicionar Foto</span></>}
                      </div>
                      <div className="text-sm">
                        <div className="grid grid-cols-2 border-b border-slate-300">
                          <div className="bg-slate-200 p-2 font-bold text-slate-800 text-xs flex items-center">NOME DA LINHA</div>
                          <div className="flex items-center justify-center bg-indigo-50/20 p-1">
                            <input
                              type="text"
                              value={item.pdd || ''}
                              onChange={(e) => handlePddChange(idx, e.target.value)}
                              placeholder="PDD"
                              className="w-full h-10 bg-white border border-slate-300 rounded pl-2 text-left font-mono text-slate-900 font-bold uppercase focus:ring-1 focus:ring-indigo-500 outline-none text-[13px] leading-[38px] tracking-tighter"
                              autoComplete="off"
                            />
                          </div>
                        </div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-100 p-2 font-bold text-slate-700 text-xs flex items-center">ID VIAGEM</div><div className="p-2 font-mono text-xs flex items-center justify-center text-center break-all">{item.id}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-200 p-2 font-bold text-slate-700 text-xs flex items-center">TIPO DE VEICULO</div><div className="p-2 text-xs flex items-center justify-center text-center uppercase">{item.vehicleType}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-100 p-2 font-bold text-slate-700 text-xs flex items-center">VOLUMETRIA REAL</div><div className="p-2 text-xs flex items-center justify-center text-center font-mono">{item.volume}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-200 p-2 font-bold text-slate-700 text-xs flex items-center">CAPACIDADE</div><div className="p-2 text-xs flex items-center justify-center text-center font-mono">{item.capacity}</div></div>
                        <div className="grid grid-cols-2 border-b border-slate-300"><div className="bg-slate-100 p-2 font-bold text-slate-700 text-xs flex items-center">SATURAÇÃO</div><div className={`p-2 text-xs flex items-center justify-center text-center font-bold ${item.saturation > 1 ? 'text-red-600' : 'text-slate-900'}`}>{(item.saturation * 100).toFixed(0)}%</div></div>
                        <div className="grid grid-cols-2"><div className="bg-slate-200 p-2 font-bold text-slate-700 text-xs flex items-center">PLACA</div><div className="p-2 text-sm flex items-center justify-center text-center font-bold uppercase">{item.plate}</div></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {/* === TAB 2: ANALYTICS REPORT === */}
      {activeTab === 'analytics' && (
        <div className="animate-fade-in space-y-8">
          <div className="max-w-2xl mx-auto">
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm relative flex flex-col justify-between">
              <div className="text-center">
                <div className="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center mb-4 mx-auto">
                  <BarChart3 className="w-8 h-8 text-orange-600" />
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">Gráfico de Expedição</h3>
                <p className="text-slate-500 text-sm mb-6 max-w-md mx-auto">
                  Carregue a planilha para calcular o total expedido e gerar o gráfico por base (Filtrando filhos e lotes).
                </p>
              </div>

              <input type="file" ref={analyticsInputRef} onChange={handleAnalyticsUpload} accept=".csv,.xlsx,.xls" className="hidden" />

              <button 
                onClick={triggerAnalyticsInput}
                disabled={analyticsStatus === 'loading'}
                className="w-full flex items-center justify-center gap-2 bg-orange-600 hover:bg-orange-700 text-white py-4 rounded-xl font-medium transition-colors disabled:opacity-50 text-lg shadow-lg hover:shadow-xl hover:-translate-y-0.5 transform"
              >
                {analyticsStatus === 'loading' ? 'Processando...' : <><FileText className="w-5 h-5" /> Importar Dados</>}
              </button>
            </div>
          </div>

          {analyticsStatus === 'success' && analyticsData.length > 0 && (
            <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
               <div className="text-center mb-8">
                  <h3 className="text-2xl font-bold text-slate-500 uppercase tracking-wide">Total Expedido</h3>
                  <p className="text-6xl font-extrabold text-orange-600 mt-2">{totalExpedited.toLocaleString('pt-BR')}</p>
                  <p className="text-sm text-slate-400 mt-2">Pedidos únicos (Filhos e Lotes removidos)</p>
               </div>

               <div className="h-[400px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart
                      data={analyticsData}
                      margin={{ top: 20, right: 30, left: 20, bottom: 60 }}
                    >
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                      <XAxis 
                        dataKey="base" 
                        angle={-45} 
                        textAnchor="end" 
                        interval={0} 
                        height={60} 
                        tick={{fontSize: 10}}
                        stroke="#64748b"
                      />
                      <YAxis stroke="#64748b" />
                      <Tooltip 
                        cursor={{fill: '#fff7ed'}}
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                      />
                      <Bar dataKey="count" name="Quantidade" fill="#f97316" radius={[4, 4, 0, 0]}>
                         <LabelList dataKey="count" position="top" fill="#ea580c" fontWeight="bold" />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
               </div>

               <div className="mt-8 border-t border-slate-100 pt-6">
                 <h4 className="font-bold text-slate-700 mb-4">Detalhamento por Base</h4>
                 <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
                    {analyticsData.map((item, idx) => (
                      <div key={idx} className="bg-slate-50 p-3 rounded border border-slate-200 text-center">
                         <div className="text-xs font-bold text-slate-500 uppercase truncate" title={item.base}>{item.base}</div>
                         <div className="text-xl font-bold text-slate-800">{item.count}</div>
                      </div>
                    ))}
                 </div>
               </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default GenerateReport;

import React, { useRef, useState } from 'react';
/* Added Loader2 to imports from lucide-react */
import { Upload, FileSpreadsheet, FileText, AlertCircle, CheckCircle2, Printer, ImageDown, Camera, BarChart3, LayoutGrid, Calendar, Loader2 } from 'lucide-react';
import * as XLSX from 'xlsx';
import { Document, Packer, Paragraph, Table, TableCell, TableRow, WidthType, BorderStyle, TextRun, AlignmentType, VerticalAlign, PageOrientation, ImageRun } from 'docx';
import html2canvas from 'html2canvas';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LabelList, Cell } from 'recharts';

interface Props {}

interface ReportItem {
  pdd: string;
  id: string;
  vehicleType: string;
  volume: number;
  capacity: number;
  saturation: number;
  plate: string;
}

interface AnalyticsData {
  base: string;
  count: number;
}

const GenerateReport: React.FC<Props> = () => {
  const [activeTab, setActiveTab] = useState<'visual' | 'analytics'>('visual');

  // --- STATES FOR VISUAL REPORT ---
  const fileInputRef = useRef<HTMLInputElement>(null);
  const photoInputRef = useRef<HTMLInputElement>(null);
  const reportContainerRef = useRef<HTMLDivElement>(null);

  const [importStatus, setImportStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [statusMessage, setStatusMessage] = useState('');
  const [reportData, setReportData] = useState<ReportItem[]>([]);
  const [vehiclePhotos, setVehiclePhotos] = useState<Record<string, string>>({});
  const [activePhotoId, setActivePhotoId] = useState<string | null>(null);

  // Data selecionada para o relatório (Padrão: Hoje)
  const [opDate, setOpDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // --- STATES FOR ANALYTICS REPORT ---
  const analyticsInputRef = useRef<HTMLInputElement>(null);
  const [analyticsStatus, setAnalyticsStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [analyticsData, setAnalyticsData] = useState<AnalyticsData[]>([]);
  const [totalExpedited, setTotalExpedited] = useState<number>(0);

  // --- SHARED HELPERS ---
  const findColumnName = (row: any, possibleNames: string[]): string | undefined => {
    if (!row) return undefined;
    const keys = Object.keys(row);
    for (const name of possibleNames) {
      const found = keys.find(k => k.trim().toLowerCase() === name.toLowerCase());
      if (found) return found;
    }
    return undefined;
  };

  const getCapacity = (vehicleType: string): number => {
    const type = vehicleType?.toString().toLowerCase().trim() || '';
    if (type.includes('3/4')) return 2000;
    if (type.includes('van')) return 1100;
    if (type.includes('furg')) return 1100;
    if (type.includes('utilit')) return 300;
    if (type.includes('toco')) return 4000;
    if (type.includes('truck')) return 5000;
    return 0;
  };

  const formatDisplayDate = (dateStr: string) => {
    if (!dateStr) return '';
    const [year, month, day] = dateStr.split('-');
    return `${day}/${month}/${year}`;
  };

  // --- VISUAL REPORT HANDLERS ---

  const handlePddChange = (idx: number, newValue: string) => {
    setReportData(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], pdd: newValue.toUpperCase() };
      return next;
    });
  };

  const triggerFileInput = () => {
    setImportStatus('idle');
    setReportData([]); 
    setVehiclePhotos({});
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handlePhotoCardClick = (id: string) => {
    setActivePhotoId(id);
    if (photoInputRef.current) {
      photoInputRef.current.value = '';
      photoInputRef.current.click();
    }
  };

  const handlePhotoUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && activePhotoId) {
      const reader = new FileReader();
      reader.onload = (e) => {
        if (e.target?.result) {
          setVehiclePhotos(prev => ({
            ...prev,
            [activePhotoId]: e.target!.result as string
          }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setImportStatus('loading');
    setStatusMessage('Lendo e processando arquivo...');

    const reader = new FileReader();

    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];

        const jsonData = XLSX.utils.sheet_to_json<any>(worksheet, { defval: "" });

        if (!jsonData || jsonData.length === 0) {
          throw new Error("Arquivo vazio ou formato inválido.");
        }

        const processedReportItems: ReportItem[] = [];

        jsonData.forEach((row: any) => {
          const idViagem = row['Tarefa de transporte No.'] || row['ID Viagem'] || row['Trip ID'];
          const pddChegada = row['PDD de chegada'] || row['Destino'] || '';
          const tipoVeiculo = row['Tipo de veículo utilizado'] || row['Veículo'] || '';
          const placa = row['Placa do carro'] || row['Placa'] || '';
          const pedidoMae = row['Número de " Pedido mãe"'] || row['Pedido mãe'] || '';

          if (!idViagem) return;

          const capacidade = getCapacity(tipoVeiculo);
          let rawVol = pedidoMae.toString();
          if (rawVol.includes(',') && !rawVol.includes('.')) {
              rawVol = rawVol.replace(',', '.');
          }
          const volumetria = parseFloat(rawVol) || 0;
          const saturacao = capacidade > 0 ? (volumetria / capacidade) : 0;

          processedReportItems.push({
            pdd: pddChegada,
            id: idViagem,
            vehicleType: tipoVeiculo,
            volume: volumetria,
            capacity: capacidade,
            saturation: saturacao,
            plate: placa
          });
        });

        if (processedReportItems.length === 0) {
          throw new Error("Nenhuma viagem válida encontrada.");
        }

        setReportData(processedReportItems);
        setImportStatus('success');
        setStatusMessage(`${processedReportItems.length} viagens processadas!`);

        if (fileInputRef.current) fileInputRef.current.value = '';

      } catch (err: any) {
        console.error("Erro no processamento:", err);
        setImportStatus('error');
        setStatusMessage(err.message || "Erro ao processar arquivo.");
      }
    };

    reader.readAsBinaryString(file);
  };

  // --- ANALYTICS REPORT HANDLERS ---

  const triggerAnalyticsInput = () => {
    if (analyticsInputRef.current) {
      analyticsInputRef.current.click();
    }
  };

  const handleAnalyticsUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setAnalyticsStatus('loading');
    setAnalyticsData([]);
    setTotalExpedited(0);

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(sheet, { defval: "" });

        if (!jsonData || jsonData.length === 0) throw new Error("Planilha vazia.");

        // Identificar colunas
        const colOrder = findColumnName(jsonData[0], ['Número de pedido JMS', 'Numero de pedido JMS', 'Pedido', 'Order ID', 'ID']);
        const colBase = findColumnName(jsonData[0], ['Parada anterior ou próxima', 'Parada anterior ou proxima', 'Base', 'Destino', 'Parada']);

        if (!colOrder) throw new Error("Coluna de Pedido não encontrada.");

        let totalCount = 0;
        const baseCounts: Record<string, number> = {};

        jsonData.forEach(row => {
           const id = String(row[colOrder] || '').trim().toUpperCase();

           // Lógica de Exclusão
           // 1. Remover filhos (com hífen)
           if (id.includes('-')) return;

           // 2. Remover lotes (começa com BR)
           if (id.startsWith('BR')) return;

           // Se passou, conta como expedido
           if (id.length > 0) {
             totalCount++;

             // Agrupar por Base
             let baseName = 'INDEFINIDO';
             if (colBase && row[colBase]) {
               baseName = String(row[colBase]).trim().toUpperCase();
               baseName = baseName.replace('CD ', '').replace('HUB ', ''); 
             }

             baseCounts[baseName] = (baseCounts[baseName] || 0) + 1;
           }
        });

        const chartData = Object.entries(baseCounts)
          .map(([base, count]) => ({ base, count }))
          .sort((a, b) => b.count - a.count);

        setTotalExpedited(totalCount);
        setAnalyticsData(chartData);
        setAnalyticsStatus('success');

        if (analyticsInputRef.current) analyticsInputRef.current.value = '';

      } catch (err: any) {
        console.error(err);
        setAnalyticsStatus('error');
        alert(err.message || "Erro ao processar planilha.");
      }
    };
    reader.readAsBinaryString(file);
  };


  // --- EXPORT FUNCTIONS (VISUAL) ---
  const handlePrint = () => window.print();

  const handleExportToPNG = async () => {
    if (!reportContainerRef.current) return;
    try {
      const canvas = await html2canvas(reportContainerRef.current, { 
        scale: 2.5, 
        backgroundColor: '#ffffff', 
        useCORS: true,
        logging: false 
      });
      const image = canvas.toDataURL("image/png", 1.0);
      const link = document.createElement('a');
      link.href = image;
      link.download = `Relatorio_Visual_${opDate}.png`;
      link.click();
    } catch (err) { alert("Não foi possível gerar a imagem."); }
  };

  const dataUrlToArrayBuffer = async (dataUrl: string) => {
    const res = await fetch(dataUrl);
    return await res.arrayBuffer();
  };

  const handleExportToExcel = async () => {
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet([]);
    const CARDS_PER_ROW = 4;
    const grid: any[][] = [];
    const newMerges: XLSX.Range[] = [];
    const setGridCell = (r: number, c: number, val: any) => {
      if (!grid[r]) grid[r] = [];
      grid[r][c] = val;
    };
    let currentRowBase = 0;

    for (let i = 0; i < reportData.length; i++) {
      const item = reportData[i];
      const colBase = (i % CARDS_PER_ROW) * 3;
      if (i > 0 && i % CARDS_PER_ROW === 0) currentRowBase += 9;
      const r = currentRowBase;
      const c = colBase;
      setGridCell(r, c, "FOTO DO VEÍCULO");
      newMerges.push({ s: { r: r, c: c }, e: { r: r+1, c: c+1 } }); 
      setGridCell(r+2, c, "NOME DA LINHA"); setGridCell(r+2, c+1, item.pdd);
      setGridCell(r+3, c, "ID VIAGEM"); setGridCell(r+3, c+1, item.id);
      setGridCell(r+4, c, "TIPO DE VEICULO"); setGridCell(r+4, c+1, item.vehicleType);
      setGridCell(r+5, c, "VOLUMETRIA REAL"); setGridCell(r+5, c+1, item.volume);
      setGridCell(r+6, c, "CAPACIDADE"); setGridCell(r+6, c+1, item.capacity);
      setGridCell(r+7, c, "SATURAÇÃO"); setGridCell(r+7, c+1, `${(item.saturation * 100).toFixed(0)}%`);
      setGridCell(r+8, c, "PLACA"); setGridCell(r+8, c+1, item.plate);
    }
    XLSX.utils.sheet_add_aoa(ws, grid, { origin: "A1" });
    ws['!merges'] = newMerges;
    XLSX.utils.book_append_sheet(wb, ws, "Relatório");
    XLSX.writeFile(wb, `Relatorio_Operacional_${opDate}.xlsx`);
  };

  const handleExportToWord = async () => {
    const rows: TableRow[] = [];
    let currentCells: TableCell[] = [];

    for (let i = 0; i < reportData.length; i++) {
      const item = reportData[i];
      let photoChildren: any[] = [new Paragraph({ children: [new TextRun({ text: "FOTO DO VEÍCULO", bold: true, size: 20, color: "CCCCCC" })], alignment: AlignmentType.CENTER })];

      if (vehiclePhotos[item.id]) {
        try {
          const imageBuffer = await dataUrlToArrayBuffer(vehiclePhotos[item.id]);
          photoChildren = [new Paragraph({ children: [new ImageRun({ data: imageBuffer, transformation: { width: 250, height: 150 } })], alignment: AlignmentType.CENTER })];
        } catch (e) {}
      }

      const cardTable = new Table({
        width: { size: 100, type: WidthType.PERCENTAGE },
        rows: [
          new TableRow({ height: { value: 2000, rule: 'atLeast' }, children: [new TableCell({ columnSpan: 2, children: photoChildren, verticalAlign: VerticalAlign.CENTER })] }),
          ...[
            ["NOME DA LINHA", item.pdd], ["ID VIAGEM", item.id], ["TIPO DE VEICULO", item.vehicleType],
            ["VOLUMETRIA REAL", item.volume.toString()], ["CAPACIDADE", item.capacity.toString()],
            ["SATURAÇÃO", `${(item.saturation * 100).toFixed(0)}%`], ["PLACA", item.plate]
          ].map(([label, value]) => new TableRow({ children: [
                new TableCell({ width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E5E7EB" }, children: [new Paragraph({ children: [new TextRun({ text: label, bold: true, size: 16 })] })], verticalAlign: VerticalAlign.CENTER }),
                new TableCell({ width: { size: 60, type: WidthType.PERCENTAGE }, children: [new Paragraph({ children: [new TextRun({ text: value, bold: label === "PLACA" || label === "SATURAÇÃO", color: (label === "SATURAÇÃO" && parseFloat(value) > 100) ? "DC2626" : "000000", size: 16 })], alignment: AlignmentType.CENTER })], verticalAlign: VerticalAlign.CENTER })
              ]
            }))
        ]
      });
      currentCells.push(new TableCell({ children: [new Paragraph(""), cardTable, new Paragraph("")], width: { size: 25, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, left: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, right: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" } } }));
      if (currentCells.length === 4 || i === reportData.length - 1) {
        while (currentCells.length < 4) currentCells.push(new TableCell({ children: [], width: { size: 25, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "auto" }, bottom: { style: BorderStyle.NONE, size: 0, color: "auto" }, left: { style: BorderStyle.NONE, size: 0, color: "auto" }, right: { style: BorderStyle.NONE, size: 0, color: "auto" } } }));
        rows.push(new TableRow({ children: currentCells }));
        currentCells = [];
      }
    }
    const doc = new Document({ sections: [{ properties: { page: { size: { orientation: PageOrientation.LANDSCAPE }, margin: { top: 500, bottom: 500, left: 500, right: 500 } } }, children: [new Table({ rows: rows, width: { size: 100, type: WidthType.PERCENTAGE }, borders: { top: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, bottom: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, left: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, right: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, insideHorizontal: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" }, insideVertical: { style: BorderStyle.NONE, size: 0, color: "FFFFFF" } } })] }] });
    const blob = await Packer.toBlob(doc);
    const link = document.createElement('a');
    link.href = window.URL.createObjectURL(blob);
    link.download = `Relatorio_Visual_${opDate}.docx`;
    link.click();
  };

