import React, { useState, useRef, useMemo } from 'react';
import * as XLSX from 'xlsx';
import { Upload, FileSpreadsheet, TrendingUp, AlertCircle, CheckCircle2, Loader2, Table, Package, MapPin, BarChart3 } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LabelList, Cell } from 'recharts';

// Configuração das Bases Homologadas
const BASES_SE = ['NSS-SE', 'NSG-SE', 'F-IBN SE', 'F-LAG SE', 'PRO-SE', 'F-EST SE', 'CDM-SE', 'BUG-SE'];
const BASES_AL = ['ARP-AL', 'PMI-AL', 'STI-AL', 'F-MCZ AL', 'CAL-AL', 'CRP-AL', 'MDC-AL', 'JCN-AL', 'JGA-AL'];
const ALL_ALLOWED_BASES = [...BASES_SE, ...BASES_AL];

interface ForecastResult {
  base: string;
  count: number;
  state: 'SE' | 'AL';
}

const ExpeditionForecast: React.FC = () => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [rawData, setRawData] = useState<any[]>([]);
  const [fileName, setFileName] = useState<string>('');
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  // Estado para os resultados processados
  const [processedResults, setProcessedResults] = useState<ForecastResult[]>([]);

  const cleanValue = (val: any): string => {
    if (val === null || val === undefined) return '';
    return String(val).trim().toUpperCase();
  };

  const findColumn = (row: any, candidates: string[]): string => {
    if (!row) return '';
    const keys = Object.keys(row);
    for (const name of candidates) {
      const found = keys.find(k => k.trim().toLowerCase().includes(name.toLowerCase()));
      if (found) return found;
    }
    return '';
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('loading');

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(ws, { defval: "" });

        if (jsonData.length === 0) {
          throw new Error("A planilha está vazia.");
        }

        // Identificar colunas
        const colOrder = findColumn(jsonData[0], ['número de pedido jms', 'numero de pedido jms', 'pedido', 'jms', 'order']);
        const colBase = findColumn(jsonData[0], ['parada anterior ou próxima', 'parada anterior ou proxima', 'base', 'destino', 'parada']);

        if (!colOrder || !colBase) {
          throw new Error("Colunas 'Pedido' ou 'Parada/Base' não encontradas na planilha.");
        }

        const counts: Record<string, number> = {};

        jsonData.forEach(row => {
          const orderId = cleanValue(row[colOrder]);
          const baseRaw = cleanValue(row[colBase]);

          // 1. Remover Pedidos Filhos (Contém hífen)
          if (orderId.includes('-')) return;

          // 2. Validar se a base está na lista das 17 homologadas
          // Fazemos uma limpeza básica na string da base da planilha para comparação
          const matchedBase = ALL_ALLOWED_BASES.find(b => 
            baseRaw.includes(b.replace(/-/g, ' ')) || 
            baseRaw.includes(b) ||
            b.includes(baseRaw)
          );

          if (matchedBase) {
            counts[matchedBase] = (counts[matchedBase] || 0) + 1;
          }
        });

        const results: ForecastResult[] = Object.entries(counts).map(([base, count]) => ({
          base,
          count,
          state: BASES_SE.includes(base) ? 'SE' : 'AL'
        })).sort((a, b) => b.count - a.count);

        setProcessedResults(results);
        setRawData(jsonData);
        setStatus('success');
      } catch (err: any) {
        console.error(err);
        setStatus('error');
        setErrorMessage(err.message || "Erro ao ler arquivo Excel.");
      }
    };
    reader.onerror = () => {
      setStatus('error');
      setErrorMessage("Erro ao carregar o arquivo.");
    };
    reader.readAsBinaryString(file);
  };

  const handleReset = () => {
    setRawData([]);
    setProcessedResults([]);
    setFileName('');
    setStatus('idle');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // Filtrar resultados por estado para os gráficos
  const dataSE = useMemo(() => processedResults.filter(r => r.state === 'SE'), [processedResults]);
  const dataAL = useMemo(() => processedResults.filter(r => r.state === 'AL'), [processedResults]);

  const totalOrders = processedResults.reduce((acc, curr) => acc + curr.count, 0);

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-10">
      {/* Hero Header */}
      <div className="bg-slate-900 rounded-2xl p-8 text-white shadow-xl bg-[url('https://images.unsplash.com/photo-1473448912268-2022ce9509d8?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center bg-blend-overlay bg-opacity-90">
        <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
          <TrendingUp className="w-8 h-8 text-indigo-400" />
          Previsão de Expedição Regional
        </h2>
        <p className="text-slate-300 max-w-xl font-medium">
          Análise automática de demanda para as 17 bases SE/AL. Removemos pedidos filhos para precisão volumétrica.
        </p>
      </div>

      {/* Upload Area */}
      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm">
        <div className="max-w-xl mx-auto text-center space-y-6">
          {status === 'idle' && (
            <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center mx-auto">
              <Upload className="w-8 h-8 text-indigo-600" />
            </div>
          )}

          <div>
            <h3 className="text-lg font-bold text-slate-800">Carregar Planilha de Previsão</h3>
            <p className="text-sm text-slate-500 mt-1">Carregue o arquivo Excel para processamento das bases.</p>
          </div>

          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileUpload} 
            className="hidden" 
            accept=".xlsx,.xls" 
          />

          <div className="flex flex-col items-center gap-4">
            {!fileName ? (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-md flex items-center gap-2"
              >
                <FileSpreadsheet className="w-5 h-5" /> Selecionar Planilha
              </button>
            ) : (
              <div className="flex items-center gap-3 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 w-full">
                <FileSpreadsheet className="w-8 h-8 text-green-600" />
                <div className="flex-1 text-left overflow-hidden">
                  <p className="text-sm font-bold text-slate-800 truncate">{fileName}</p>
                  <p className="text-xs text-slate-500">Planilha Carregada</p>
                </div>
                <button 
                  onClick={handleReset}
                  className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                >
                  <RefreshCw className="w-5 h-5" />
                </button>
              </div>
            )}
          </div>

          {status === 'loading' && (
            <div className="flex items-center justify-center gap-2 text-indigo-600 font-bold animate-pulse">
              <Loader2 className="w-5 h-5 animate-spin" /> Analisando pedidos...
            </div>
          )}

          {status === 'error' && (
            <div className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-center gap-3 text-red-800 animate-fade-in">
              <AlertCircle className="w-6 h-6 text-red-600 shrink-0" />
              <div className="text-left">
                <p className="font-bold">Erro ao Processar</p>
                <p className="text-xs">{errorMessage}</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Resultados e Gráficos */}
      {status === 'success' && (
        <div className="space-y-8 animate-fade-in">
          {/* Totalizador */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
              <div className="p-3 bg-indigo-100 rounded-lg text-indigo-600">
                <Package className="w-6 h-6" />
              </div>
              <div>
                <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Pedidos (Pai)</p>
                <p className="text-2xl font-black text-slate-900">{totalOrders.toLocaleString('pt-BR')}</p>
              </div>
            </div>
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
              <div className="p-3 bg-blue-100 rounded-lg text-blue-600">
                <MapPin className="w-6 h-6" />
              </div>
              <div>
                <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Pedidos Sergipe</p>
                <p className="text-2xl font-black text-slate-900">{dataSE.reduce((a,c)=>a+c.count, 0).toLocaleString('pt-BR')}</p>
              </div>
            </div>
            <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
              <div className="p-3 bg-teal-100 rounded-lg text-teal-600">
                <MapPin className="w-6 h-6" />
              </div>
              <div>
                <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Pedidos Alagoas</p>
                <p className="text-2xl font-black text-slate-900">{dataAL.reduce((a,c)=>a+c.count, 0).toLocaleString('pt-BR')}</p>
              </div>
            </div>
          </div>

          {/* Quadros de Gráficos Lado a Lado */}
