import React, { useState, useRef, useMemo } from 'react';
import * as XLSX from 'xlsx';
import { Upload, FileSpreadsheet, TrendingUp, AlertCircle, CheckCircle2, Loader2, Table, Package, MapPin, BarChart3, RefreshCw, SearchX } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LabelList } from 'recharts';

// Lista exata fornecida pelo usuário
const BASES_SE = ['NSS-SE', 'NSG-SE', 'F-IBN SE', 'F-LAG SE', 'PRO-SE', 'F-EST SE', 'CDM-SE', 'BUG-SE'];
const BASES_AL = ['ARP-AL', 'PMI-AL', 'STI-AL', 'F-MCZ AL', 'CAL-AL', 'CRP-AL', 'MDC-AL', 'JCN-AL', 'JGA-AL'];
const ALL_ALLOWED_BASES = [...BASES_SE, ...BASES_AL];

interface ForecastResult {
  base: string;
  count: number;
  state: 'SE' | 'AL';
}

const ExpeditionForecast: React.FC = () => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [fileName, setFileName] = useState<string>('');
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [processedResults, setProcessedResults] = useState<ForecastResult[]>([]);
  const [debugInfo, setDebugInfo] = useState<{foundCols: string[], firstRows: any[]}>({foundCols: [], firstRows: []});

  // Função de limpeza agressiva para comparação
  const normalizeForMatch = (str: string) => {
    return str
      .toUpperCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "") // Remove acentos
      .replace(/[^A-Z0-0]/g, "");    // Remove tudo que não é letra ou número
  };

  const cleanValue = (val: any): string => {
    if (val === null || val === undefined) return '';
    return String(val).trim().toUpperCase();
  };

  // Busca coluna de forma mais inteligente
  const findColumn = (headers: string[], candidates: string[]): string => {
    // 1. Tenta match exato ou parcial nos nomes conhecidos
    for (const cand of candidates) {
      const found = headers.find(h => 
        normalizeForMatch(h).includes(normalizeForMatch(cand)) ||
        normalizeForMatch(cand).includes(normalizeForMatch(h))
      );
      if (found) return found;
    }
    return '';
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus('loading');
    setProcessedResults([]);

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const jsonData = XLSX.utils.sheet_to_json<any>(ws, { defval: "" });

        if (jsonData.length === 0) throw new Error("A planilha está vazia.");

        const headers = Object.keys(jsonData[0]);

        // Candidatos amplos para colunas
        const colOrder = findColumn(headers, ['Pedido', 'JMS', 'Order', 'Referencia', 'ID']);
        const colBase = findColumn(headers, ['Parada', 'Base', 'Destino', 'Next Stop', 'Anterior ou proxima']);

        setDebugInfo({ foundCols: [colOrder, colBase], firstRows: jsonData.slice(0, 3) });

        if (!colOrder || !colBase) {
          throw new Error(`Não identificamos as colunas necessárias. Procuramos por 'Pedido' e 'Parada'. Colunas lidas: ${headers.join(', ')}`);
        }

        const counts: Record<string, number> = {};
        let countValid = 0;

        jsonData.forEach(row => {
          const orderId = cleanValue(row[colOrder]);
          const baseRaw = cleanValue(row[colBase]);

          // 1. Remover Pedidos Filhos (Contém hífen)
          if (orderId.includes('-')) return;

          // 2. Normalizar base da planilha para comparação
          const normalizedInput = normalizeForMatch(baseRaw);

          // Busca na nossa lista de 17 bases
          const matchedBase = ALL_ALLOWED_BASES.find(b => {
            const normalizedAllowed = normalizeForMatch(b);
            // Match se um está contido no outro (Ex: "F-IBN SE" match com "FIBNSE")
            return normalizedInput.includes(normalizedAllowed) || normalizedAllowed.includes(normalizedInput);
          });

          if (matchedBase) {
            counts[matchedBase] = (counts[matchedBase] || 0) + 1;
            countValid++;
          }
        });

        if (countValid === 0) {
          throw new Error("Planilha lida, mas nenhum pedido corresponde às 17 bases homologadas (SE/AL). Verifique se a coluna de destinos está correta.");
        }

        const results: ForecastResult[] = Object.entries(counts).map(([base, count]) => ({
          base,
          count,
          state: (BASES_SE.includes(base) ? 'SE' : 'AL') as 'SE' | 'AL'
        })).sort((a, b) => b.count - a.count);

        setProcessedResults(results);
        setStatus('success');
      } catch (err: any) {
        console.error(err);
        setStatus('error');
        setErrorMessage(err.message || "Erro ao processar arquivo.");
      }
    };
    reader.onerror = () => {
      setStatus('error');
      setErrorMessage("Erro técnico ao carregar o arquivo.");
    };
    reader.readAsBinaryString(file);
  };

  const handleReset = () => {
    setProcessedResults([]);
    setFileName('');
    setStatus('idle');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const dataSE = useMemo(() => processedResults.filter(r => r.state === 'SE'), [processedResults]);
