                    <XAxis type="number" hide />
                    <YAxis dataKey="base" type="category" tick={{ fontSize: 10, fontWeight: 'bold', fill: '#134e4a' }} width={80} />
                    <Tooltip cursor={{fill: '#f8fafc'}} />
